/* ===== Global State ===== */

#define MAX_STASHES 4096
#define INITIAL_STASH_CAPACITY 32

static PerlStash *g_stashes[MAX_STASHES];
static int g_stash_count = 0;

/* Save stack for local() */
#define SAVE_STACK_INITIAL 256
static PerlSaveEntry *g_save_stack = NULL;
static int g_save_count = 0;
static int g_save_capacity = 0;

/* ===== Blessed-object registry (for global-destruction DESTROY) =====
 *
 * Perl fires DESTROY for every still-blessed object at program exit,
 * regardless of refcount. perla currently leaks refs through the call
 * chain (callee return-incref + caller call-site-incref are not balanced
 * by a matching decref on the consumer side), so DESTROY never fires via
 * the normal rc=0 path. Until that architectural fix lands, this registry
 * + perla_destroy_sweep gives us Perl-compatible "DESTROY at process
 * exit" semantics.
 *
 * Entries are appended on perla_bless; never removed mid-program. At
 * sweep time we re-check sv->meta and sv->meta->blessed_package — both
 * are NULL'd by strada_free_value before recycling the slot, so already-
 * DESTROYed (or recycled-to-a-different-type) entries are skipped.
 *
 * Re-bless of the same C-pointer to a fresh object inserts a new entry;
 * the stale old entry no-ops at sweep time because its blessed_package
 * was already cleared by the original DESTROY. */
static StradaValue **g_blessed_registry = NULL;
static size_t g_blessed_registry_size = 0;
static size_t g_blessed_registry_capacity = 0;
static int g_in_global_destruction = 0;

/* Sub::Util side-table — declared here (used in perla_cleanup) but defined
 * in the Sub::Util section below. */
typedef struct PerlaSubnameEntry {
    StradaValue *sv;
    char *name;
} PerlaSubnameEntry;
static PerlaSubnameEntry *perla_subname_table = NULL;
static size_t perla_subname_count = 0;
static size_t perla_subname_capacity = 0;

/* $. per-handle table — defined alongside perla_last_readline_fh below. */
typedef struct PerlaDotEntry { StradaValue *fh; int count; } PerlaDotEntry;
static PerlaDotEntry *perla_dot_table = NULL;
static int perla_dot_count = 0;
static int perla_dot_capacity = 0;

/* Special variables stash (held in "main" package) */
static PerlStash *g_main_stash = NULL;

static int g_initialized = 0;

