/* Perl-compatible boolean: references are always truthy unless `bool`
 * overload says otherwise. */
int perla_to_bool(StradaValue *sv) {
    if (!sv) return 0;
    if (STRADA_IS_TAGGED_INT(sv)) return STRADA_TAGGED_INT_VAL(sv) != 0;
    if (sv->type == STRADA_REF) {
        if (strada_overload_bool_hook) {
            int b = strada_overload_bool_hook(sv);
            if (b >= 0) return b;
        }
        return 1;  /* refs without bool overload are always truthy */
    }
    if (sv->type == STRADA_CLOSURE || sv->type == STRADA_CPOINTER) return 1;
    return strada_to_bool(sv);
}

