    /* Test::Simple is a tiny shim around Test::Builder that exports
     * only \`ok\`. Without registering its import, \`use Test::Simple
     * tests => N\` falls through to perla_require_module, which tries
     * to load Test/Simple.pm from CPAN — that pulls in Test::Builder's
     * deep load chain and either hangs or pulls in code we can't
     * handle. Bind \`ok\` and \`import\` directly. */
    perla_code_set_protected("Test::Simple", "ok",        strada_cpointer_new((void*)perla_tm_ok));
    perla_code_set_protected("Test::Simple", "import",    strada_cpointer_new((void*)perla_tm_import));
    /* Note: do NOT pre-bind Test::More functions in main:: at startup —
     * that pollutes the global namespace (e.g. user-defined \`sub pass\`
     * would call perla_tm_pass instead). Test::More::import handles the
     * main:: bindings when \`use Test::More\` actually fires. */
    if (!g_INC_hash) g_INC_hash = strada_new_hash();
    if (g_INC_hash && g_INC_hash->value.hv) {
        strada_hash_set(g_INC_hash->value.hv, "Test/More.pm",
                        strada_new_str("(perla-native-stub)"));
        strada_hash_set(g_INC_hash->value.hv, "Test/Builder.pm",
                        strada_new_str("(perla-native-stub)"));
        strada_hash_set(g_INC_hash->value.hv, "Test/Simple.pm",
                        strada_new_str("(perla-native-stub)"));
    }

