    perla_code_set_protected("main", "dirname",  strada_cpointer_new((void*)perla_file_basename_dirname));
    perla_code_set_protected("main", "fileparse", strada_cpointer_new((void*)perla_file_basename_fileparse));

    /* File::Find — recursive directory traversal. Callback invoked
     * once per entry; \$File::Find::name holds the full path,
     * \$File::Find::dir holds the parent dir, \$_ holds the basename.
     * Without this, `find(\\&wanted, $dir)` was a no-op (callback
     * never called) — broke Cwd-related modules and any code that
     * walks installed-modules dirs.
     */
    extern StradaValue *perla_file_find_find(StradaValue *args);
    extern StradaValue *perla_file_find_finddepth(StradaValue *args);
    perla_code_set_protected("File::Find", "find", strada_cpointer_new((void*)perla_file_find_find));
    perla_code_set_protected("File::Find", "finddepth", strada_cpointer_new((void*)perla_file_find_finddepth));
    /* Don't pre-register find/finddepth into "main" — that shadows
     * user-defined `sub find { ... }` since the slot is protected,
     * and silently substitutes File::Find::find at call sites that
     * have nothing to do with File::Find. Real Perl only puts these
     * into main via `use File::Find qw(find finddepth)`. The
     * Exporter glue below sets up EXPORT_OK and the .pm-stub
     * registration so explicit `use File::Find qw(find)` still
     * imports them on demand. */
    /* @EXPORT_OK + ISA so `use File::Find qw(find finddepth)` works */
    {
        StradaValue *eok = strada_new_array();
        strada_array_push_take(eok->value.av, strada_new_str("find"));
        strada_array_push_take(eok->value.av, strada_new_str("finddepth"));
        perla_array_set("File::Find", "EXPORT_OK", eok);
        strada_decref(eok);
        StradaValue *isa = strada_new_array();
        strada_array_push_take(isa->value.av, strada_new_str("Exporter"));
        perla_isa_assign("File::Find::ISA", isa);
        strada_decref(isa);
        if (!g_INC_hash) g_INC_hash = strada_new_hash();
        if (g_INC_hash && g_INC_hash->value.hv) {
            strada_hash_set(g_INC_hash->value.hv, "File/Find.pm",
                            strada_new_str("(perla-native-stub)"));
        }
    }

