    /* Storable::dclone: deep clone via strada_clone (XS Storable.so skipped
     * because Perla doesn't load XS modules — register a C replacement).
     * Also seed @Storable::ISA = (Exporter) and @Storable::EXPORT_OK so that
     * `use Storable qw(dclone)` via perla_exporter_import copies dclone into
     * the caller's stash (Storable.pm itself is XS-stubbed and doesn't run
     * its own `our @EXPORT_OK = ...` lines). */
    perla_code_set("Storable", "dclone", strada_cpointer_new((void*)perla_storable_dclone));
    /* freeze/thaw/nfreeze/store/retrieve — perla doesn't ship a binary
     * Storable serializer; substitute a Data::Dumper-text-based
     * round-trip. Lossy for code refs / blessed objects with custom
     * STORABLE_freeze hooks but covers plain data structures. */
    extern StradaValue *perla_storable_freeze(StradaValue *args);
    extern StradaValue *perla_storable_thaw(StradaValue *args);
    perla_code_set("Storable", "freeze",  strada_cpointer_new((void*)perla_storable_freeze));
    perla_code_set("Storable", "nfreeze", strada_cpointer_new((void*)perla_storable_freeze));
    perla_code_set("Storable", "thaw",    strada_cpointer_new((void*)perla_storable_thaw));
    {
        StradaValue *isa = strada_new_array();
        strada_array_push_take(isa->value.av, strada_new_str("Exporter"));
        perla_isa_assign("Storable::ISA", isa);
        strada_decref(isa);

        StradaValue *export_ok = strada_new_array();
        strada_array_push_take(export_ok->value.av, strada_new_str("dclone"));
        strada_array_push_take(export_ok->value.av, strada_new_str("freeze"));
        strada_array_push_take(export_ok->value.av, strada_new_str("thaw"));
        strada_array_push_take(export_ok->value.av, strada_new_str("nfreeze"));
        strada_array_push_take(export_ok->value.av, strada_new_str("store"));
        strada_array_push_take(export_ok->value.av, strada_new_str("nstore"));
        strada_array_push_take(export_ok->value.av, strada_new_str("retrieve"));
        strada_array_push_take(export_ok->value.av, strada_new_str("lock_store"));
        strada_array_push_take(export_ok->value.av, strada_new_str("lock_nstore"));
        strada_array_push_take(export_ok->value.av, strada_new_str("lock_retrieve"));
        strada_array_push_take(export_ok->value.av, strada_new_str("store_fd"));
        strada_array_push_take(export_ok->value.av, strada_new_str("nstore_fd"));
        strada_array_push_take(export_ok->value.av, strada_new_str("fd_retrieve"));
        perla_array_set("Storable", "EXPORT_OK", export_ok);
        strada_decref(export_ok);
    }

    /* Clone::clone — XS-only deep copy. Same engine as Storable::dclone
     * (strada_clone, now cycle-aware + coderef-preserving). Specio::XS does
     * `use Clone qw(clone); sub _clone { clone(shift) }`; without a native
     * Clone::clone, the imported `clone` was undefined and the unqualified
     * call resolved to Specio::OO::clone (a same-named method), which then
     * died "Can't call method _attrs on unblessed reference" when handed a
     * plain ref. Seed @ISA=(Exporter) + @EXPORT_OK=(clone) so
     * `use Clone qw(clone)` imports it. */
    perla_code_set("Clone", "clone", strada_cpointer_new((void*)perla_storable_dclone));
    {
        StradaValue *cisa = strada_new_array();
        strada_array_push_take(cisa->value.av, strada_new_str("Exporter"));
        perla_isa_assign("Clone::ISA", cisa);
        strada_decref(cisa);
        StradaValue *ceok = strada_new_array();
        strada_array_push_take(ceok->value.av, strada_new_str("clone"));
        perla_array_set("Clone", "EXPORT_OK", ceok);
        strada_decref(ceok);
    }

