/* Time::Local::timelocal — (sec, min, hour, mday, mon, year) → epoch local.
 * Same signature as POSIX::mktime but accepts year in Perl's localtime form
 * (year = year-1900) and DOES NOT require wday/yday/isdst. Without the
 * native binding `use Time::Local; timelocal(...)` returned empty in
 * perla. */
static int _perla_timelocal_year_to_tmyear(int year);  /* fwd */
static StradaValue *perla_time_local_timelocal(StradaValue *args) {
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 6) return strada_new_undef();
    struct tm tm = {0};
    tm.tm_sec  = (int)strada_to_int(strada_array_get(av, 0));
    tm.tm_min  = (int)strada_to_int(strada_array_get(av, 1));
    tm.tm_hour = (int)strada_to_int(strada_array_get(av, 2));
    tm.tm_mday = (int)strada_to_int(strada_array_get(av, 3));
    tm.tm_mon  = (int)strada_to_int(strada_array_get(av, 4));
    int year = (int)strada_to_int(strada_array_get(av, 5));
    tm.tm_year = _perla_timelocal_year_to_tmyear(year);
    tm.tm_isdst = -1;
    time_t t = mktime(&tm);
    if (t == (time_t)-1) return strada_new_undef();
    return STRADA_MAKE_TAGGED_INT((int64_t)t);
}

/* Time::Local::timegm — same as timelocal but UTC. timegm() is a BSD
 * extension; use the timezone-trick fallback if not available. */
/* Time::Local year interpretation rules (matches Time::Local 1.27+):
 *   year >= 1000: literal 4-digit year → tm_year = year - 1900
 *   year >= 100:  years-since-1900 offset → tm_year = year (so 100 = 2000)
 *   year 0..99:   rolling century (50yr +/- current year), ties go forward
 *     2026 anchor: 0..76 -> 2000..2076 (tm_year 100..176)
 *                  77..99 -> 1977..1999 (tm_year 77..99)
 * Previously perla just passed year < 1000 unchanged, so timegm(0,0,0,1,0,70)
 * returned 1970-01-01 (= 0) when Perl 5.32+ Time::Local returns 2070-01-01. */
static int _perla_timelocal_year_to_tmyear(int year) {
    if (year >= 1000) return year - 1900;
    if (year >= 100)  return year;
    /* Rolling century: based on current calendar year. */
    time_t now = time(NULL);
    struct tm cur;
    gmtime_r(&now, &cur);
    int cur_year = cur.tm_year + 1900;
    int base = cur_year - (cur_year % 100);  /* e.g. 2000 for 2026 */
    int candidate = base + year;
    if (candidate > cur_year + 50)      candidate -= 100;
    else if (candidate < cur_year - 50) candidate += 100;
    return candidate - 1900;
}

static StradaValue *perla_time_local_timegm(StradaValue *args) {
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 6) return strada_new_undef();
    struct tm tm = {0};
    tm.tm_sec  = (int)strada_to_int(strada_array_get(av, 0));
    tm.tm_min  = (int)strada_to_int(strada_array_get(av, 1));
    tm.tm_hour = (int)strada_to_int(strada_array_get(av, 2));
    tm.tm_mday = (int)strada_to_int(strada_array_get(av, 3));
    tm.tm_mon  = (int)strada_to_int(strada_array_get(av, 4));
    int year = (int)strada_to_int(strada_array_get(av, 5));
    tm.tm_year = _perla_timelocal_year_to_tmyear(year);
    tm.tm_isdst = 0;
    /* glibc's timegm is non-POSIX; use it directly. */
    time_t t = timegm(&tm);
    if (t == (time_t)-1) return strada_new_undef();
    return STRADA_MAKE_TAGGED_INT((int64_t)t);
}

static StradaValue *perla_posix_mktime(StradaValue *args) {
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 6) return strada_new_undef();
    struct tm tm = {0};
    tm.tm_sec  = (int)strada_to_int(strada_array_get(av, 0));
    tm.tm_min  = (int)strada_to_int(strada_array_get(av, 1));
    tm.tm_hour = (int)strada_to_int(strada_array_get(av, 2));
    tm.tm_mday = (int)strada_to_int(strada_array_get(av, 3));
    tm.tm_mon  = (int)strada_to_int(strada_array_get(av, 4));
    tm.tm_year = (int)strada_to_int(strada_array_get(av, 5));
    if (av->size >= 9) {
        tm.tm_wday  = (int)strada_to_int(strada_array_get(av, 6));
        tm.tm_yday  = (int)strada_to_int(strada_array_get(av, 7));
        tm.tm_isdst = (int)strada_to_int(strada_array_get(av, 8));
    } else {
        tm.tm_isdst = -1;  /* let libc figure it out */
    }
    time_t t = mktime(&tm);
    if (t == (time_t)-1) return strada_new_undef();
    return STRADA_MAKE_TAGGED_INT((int64_t)t);
}
