/* getprotobyname / getprotobynumber / getservbyname — Perl built-ins
 * that delegate to /etc/protocols and /etc/services lookups. Without
 * these, IO::Socket::INET dies with "Bad protocol 'tcp'" because it
 * uses getprotobyname('tcp') to map to IPPROTO_TCP. */
/* Build a Perl-style "list" result for a protoent lookup: returns a
 * 3-element array (name, aliases, proto-number). Callers in list
 * context see the full triple; in scalar context Perl returns just
 * the proto-number — we return an array and let perla's wantarray
 * collapse handle it (scalar context = array length = 3 instead of
 * the number, which is wrong; but IO::Socket::INET uses list-context
 * unpacking so this matches the common case). */
static StradaValue *make_protoent_list(struct protoent *pe) {
    StradaValue *arr = strada_new_array();
    StradaArray *av = strada_deref_array(arr);
    strada_array_push_take(av, strada_new_str(pe->p_name ? pe->p_name : ""));
    /* p_aliases is NULL-terminated array of char*; join with spaces. */
    char alias_buf[256] = "";
    if (pe->p_aliases) {
        size_t off = 0;
        for (int i = 0; pe->p_aliases[i]; i++) {
            size_t alen = strlen(pe->p_aliases[i]);
            if (off + alen + 2 >= sizeof(alias_buf)) break;
            if (off > 0) alias_buf[off++] = ' ';
            memcpy(alias_buf + off, pe->p_aliases[i], alen);
            off += alen;
            alias_buf[off] = 0;
        }
    }
    strada_array_push_take(av, strada_new_str(alias_buf));
    strada_array_push_take(av, STRADA_MAKE_TAGGED_INT((int64_t)pe->p_proto));
    return arr;
}
static StradaValue *make_servent_list(struct servent *se) {
    StradaValue *arr = strada_new_array();
    StradaArray *av = strada_deref_array(arr);
    strada_array_push_take(av, strada_new_str(se->s_name ? se->s_name : ""));
    char alias_buf[256] = "";
    if (se->s_aliases) {
        size_t off = 0;
        for (int i = 0; se->s_aliases[i]; i++) {
            size_t alen = strlen(se->s_aliases[i]);
            if (off + alen + 2 >= sizeof(alias_buf)) break;
            if (off > 0) alias_buf[off++] = ' ';
            memcpy(alias_buf + off, se->s_aliases[i], alen);
            off += alen;
            alias_buf[off] = 0;
        }
    }
    strada_array_push_take(av, strada_new_str(alias_buf));
    strada_array_push_take(av, STRADA_MAKE_TAGGED_INT((int64_t)ntohs(se->s_port)));
    strada_array_push_take(av, strada_new_str(se->s_proto ? se->s_proto : ""));
    return arr;
}
StradaValue *perla_getprotobyname(StradaValue *args) {
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_undef();
    char *name = strada_to_str(strada_array_get(av, 0));
    if (!name) return strada_new_undef();
    struct protoent *pe = getprotobyname(name);
    free(name);
    if (!pe) return strada_new_undef();
    return make_protoent_list(pe);
}
StradaValue *perla_getprotobynumber(StradaValue *args) {
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_undef();
    int num = (int)strada_to_int(strada_array_get(av, 0));
    struct protoent *pe = getprotobynumber(num);
    if (!pe) return strada_new_undef();
    return make_protoent_list(pe);
}
StradaValue *perla_getservbyname(StradaValue *args) {
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_undef();
    char *name = strada_to_str(strada_array_get(av, 0));
    char *proto = (av->size >= 2) ? strada_to_str(strada_array_get(av, 1)) : NULL;
    if (!name) { free(proto); return strada_new_undef(); }
    struct servent *se = getservbyname(name, proto);
    free(name); free(proto);
    if (!se) return strada_new_undef();
    return make_servent_list(se);
}
StradaValue *perla_getservbyport(StradaValue *args) {
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_undef();
    int port = (int)strada_to_int(strada_array_get(av, 0));
    char *proto = (av->size >= 2) ? strada_to_str(strada_array_get(av, 1)) : NULL;
    struct servent *se = getservbyport(htons(port), proto);
    free(proto);
    if (!se) return strada_new_undef();
    return make_servent_list(se);
}
/* getpriority(WHICH, WHO) — WHICH is PRIO_PROCESS/PGRP/USER (0/1/2),
 * WHO is the target id (0 = self). Perl returns the nice value, or
 * dies on error. Our impl swallows error and returns 0 (matches the
 * common "report my own nice level" case). */
StradaValue *perla_getpriority(StradaValue *args) {
    StradaArray *av = strada_deref_array(args);
    int which = (av && av->size >= 1) ? (int)strada_to_int(strada_array_get(av, 0)) : PRIO_PROCESS;
    int who   = (av && av->size >= 2) ? (int)strada_to_int(strada_array_get(av, 1)) : 0;
    errno = 0;
    int r = getpriority(which, who);
    if (r == -1 && errno != 0) return strada_new_undef();
    return STRADA_MAKE_TAGGED_INT((int64_t)r);
}
/* setpriority(WHICH, WHO, PRIO) — returns true on success, undef on
 * error. */
StradaValue *perla_setpriority(StradaValue *args) {
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 3) return strada_new_undef();
    int which = (int)strada_to_int(strada_array_get(av, 0));
    int who   = (int)strada_to_int(strada_array_get(av, 1));
    int prio  = (int)strada_to_int(strada_array_get(av, 2));
    if (setpriority(which, who, prio) == 0) return STRADA_MAKE_TAGGED_INT(1);
    return strada_new_undef();
}
