/* Reverse: Unicode codepoint → CP125x byte. Bytes < 0x80 are
 * identity (ASCII), so we only scan the 0x80-0xFF table. Returns 0
 * when no mapping exists (caller falls back to `?`). */
static unsigned char perla_unicode_to_cp125x(uint32_t cp, const uint16_t *table) {
    if (cp < 0x80) return (unsigned char)cp;
    for (int i = 0; i < 128; i++) {
        if (table[i] == cp) return (unsigned char)(0x80 + i);
    }
    return 0;
}

/* Decode UTF-8 to codepoint; returns bytes consumed (1..4) or 0
 * on malformed sequence (consume 1 byte to recover). */
static int perla_utf8_next(const char *p, size_t avail, uint32_t *out) {
    if (avail == 0) { *out = 0; return 0; }
    unsigned char b0 = (unsigned char)p[0];
    if (b0 < 0x80) { *out = b0; return 1; }
    if ((b0 & 0xE0) == 0xC0 && avail >= 2) {
        unsigned char b1 = (unsigned char)p[1];
        if ((b1 & 0xC0) != 0x80) { *out = 0xFFFD; return 1; }
        *out = ((b0 & 0x1F) << 6) | (b1 & 0x3F);
        return 2;
    }
    if ((b0 & 0xF0) == 0xE0 && avail >= 3) {
        unsigned char b1 = (unsigned char)p[1], b2 = (unsigned char)p[2];
        if ((b1 & 0xC0) != 0x80 || (b2 & 0xC0) != 0x80) { *out = 0xFFFD; return 1; }
        *out = ((b0 & 0x0F) << 12) | ((b1 & 0x3F) << 6) | (b2 & 0x3F);
        return 3;
    }
    if ((b0 & 0xF8) == 0xF0 && avail >= 4) {
        unsigned char b1 = (unsigned char)p[1], b2 = (unsigned char)p[2], b3 = (unsigned char)p[3];
        if ((b1 & 0xC0) != 0x80 || (b2 & 0xC0) != 0x80 || (b3 & 0xC0) != 0x80) { *out = 0xFFFD; return 1; }
        *out = ((b0 & 0x07) << 18) | ((b1 & 0x3F) << 12) | ((b2 & 0x3F) << 6) | (b3 & 0x3F);
        return 4;
    }
    *out = 0xFFFD;
    return 1;
}

/* Encode a single codepoint as UTF-8 into a 4-byte buffer; returns
 * bytes written. */
static int perla_utf8_emit(uint32_t cp, char *buf) {
    if (cp < 0x80) { buf[0] = (char)cp; return 1; }
    if (cp < 0x800) {
        buf[0] = (char)(0xC0 | (cp >> 6));
        buf[1] = (char)(0x80 | (cp & 0x3F));
        return 2;
    }
    if (cp < 0x10000) {
        buf[0] = (char)(0xE0 | (cp >> 12));
        buf[1] = (char)(0x80 | ((cp >> 6) & 0x3F));
        buf[2] = (char)(0x80 | (cp & 0x3F));
        return 3;
    }
    buf[0] = (char)(0xF0 | (cp >> 18));
    buf[1] = (char)(0x80 | ((cp >> 12) & 0x3F));
    buf[2] = (char)(0x80 | ((cp >> 6) & 0x3F));
    buf[3] = (char)(0x80 | (cp & 0x3F));
    return 4;
}

/* Encode (char → bytes) for non-UTF8 encodings. Codepoints that
 * don't fit are replaced with `?` (matching Encode's default fallback). */
static StradaValue *perla_encode_to_bytes(StradaValue *sv, PerlaEncId enc) {
    if (!sv || STRADA_IS_TAGGED_INT(sv) || sv->type != STRADA_STR || !sv->value.pv) {
        if (sv) strada_incref(sv);
        return sv ? sv : strada_new_str("");
    }
    size_t in_len = STRADA_STR_BYTELEN(sv);
    if (in_len == 0) in_len = strlen(sv->value.pv);
    int is_utf8 = STRADA_STR_IS_UTF8(sv) ? 1 : 0;
    /* Worst case: one byte per codepoint. */
    char *out = (char *)malloc(in_len + 1);
    size_t out_len = 0;
    size_t i = 0;
    const char *p = sv->value.pv;
    while (i < in_len) {
        uint32_t cp;
        int adv;
        if (is_utf8) {
            adv = perla_utf8_next(p + i, in_len - i, &cp);
            if (adv == 0) break;
        } else {
            cp = (unsigned char)p[i];
            adv = 1;
        }
        unsigned char b;
        if (enc == PERLA_ENC_LATIN1) {
            b = (cp < 0x100) ? (unsigned char)cp : '?';
        } else if (enc == PERLA_ENC_CP1252) {
            if (cp < 0x80 || (cp >= 0xA0 && cp < 0x100)) b = (unsigned char)cp;
            else {
                unsigned char m = perla_unicode_to_cp1252(cp);
                b = m ? m : '?';
            }
        } else if (enc == PERLA_ENC_CP1251) {
            b = perla_unicode_to_cp125x(cp, perla_cp1251_to_unicode);
            if (!b) b = '?';
        } else if (enc == PERLA_ENC_CP1250) {
            b = perla_unicode_to_cp125x(cp, perla_cp1250_to_unicode);
            if (!b) b = '?';
        } else if (enc == PERLA_ENC_CP1253) {
            b = perla_unicode_to_cp125x(cp, perla_cp1253_to_unicode);
            if (!b) b = '?';
        } else if (enc == PERLA_ENC_ASCII) {
            b = (cp < 0x80) ? (unsigned char)cp : '?';
        } else {
            b = '?';
        }
        out[out_len++] = (char)b;
        i += (size_t)adv;
    }
    StradaValue *result = strada_new_str_len(out, out_len);
    strada_set_utf8_flag(result, 0);
    free(out);
    return result;
}

/* Decode (bytes → char string + SVf_UTF8). Each byte produces a
 * codepoint per the encoding's table; codepoint is then UTF-8-encoded. */
static StradaValue *perla_encode_from_bytes(StradaValue *sv, PerlaEncId enc) {
    if (!sv || STRADA_IS_TAGGED_INT(sv) || sv->type != STRADA_STR || !sv->value.pv) {
        if (sv) strada_incref(sv);
        return sv ? sv : strada_new_str("");
    }
    size_t in_len = STRADA_STR_BYTELEN(sv);
    if (in_len == 0) in_len = strlen(sv->value.pv);
    /* Worst case: 3 UTF-8 bytes per input byte (CP1252 high range
     * produces 3-byte sequences like U+20AC). */
    char *out = (char *)malloc(in_len * 4 + 1);
    size_t out_len = 0;
    for (size_t i = 0; i < in_len; i++) {
        unsigned char b = (unsigned char)sv->value.pv[i];
        uint32_t cp;
        if (enc == PERLA_ENC_LATIN1) {
            cp = b;
        } else if (enc == PERLA_ENC_CP1252) {
            cp = (b >= 0x80 && b < 0xA0) ? perla_cp1252_to_unicode[b - 0x80] : b;
        } else if (enc == PERLA_ENC_CP1251) {
            cp = (b >= 0x80) ? perla_cp1251_to_unicode[b - 0x80] : b;
        } else if (enc == PERLA_ENC_CP1250) {
            cp = (b >= 0x80) ? perla_cp1250_to_unicode[b - 0x80] : b;
        } else if (enc == PERLA_ENC_CP1253) {
            cp = (b >= 0x80) ? perla_cp1253_to_unicode[b - 0x80] : b;
        } else if (enc == PERLA_ENC_ASCII) {
            cp = (b < 0x80) ? b : 0xFFFD;
        } else {
            cp = b;  /* fallback: identity */
        }
        out_len += perla_utf8_emit(cp, out + out_len);
    }
    StradaValue *result = strada_new_str_len_utf8(out, out_len);
    free(out);
    return result;
}

static StradaValue *perla_encode_encode(StradaValue *args) {
    if (!args) return strada_new_str("");
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 2) return strada_new_str("");
    StradaValue *enc_sv = av->elements[av->head + 0];
    StradaValue *sv = av->elements[av->head + 1];
    if (!sv) return strada_new_str("");
    char *enc_name = enc_sv ? strada_to_str(enc_sv) : NULL;
    PerlaEncId enc = perla_enc_id(enc_name);
    free(enc_name);

    /* UTF-8 / unknown: keep the original flag-flip behaviour. */
    if (enc == PERLA_ENC_UTF8 || enc == PERLA_ENC_UNKNOWN) {
        if (!STRADA_IS_TAGGED_INT(sv) && sv->type == STRADA_STR && sv->value.pv) {
            if (sv->refcount == 1 && STRADA_STR_IS_UTF8(sv)) {
                strada_set_utf8_flag(sv, 0);
                strada_incref(sv);
                return sv;
            }
            if (!STRADA_STR_IS_UTF8(sv)) {
                strada_incref(sv);
                return sv;
            }
            size_t len = STRADA_STR_BYTELEN(sv);
            if (len == 0) len = strlen(sv->value.pv);
            StradaValue *out = strada_new_str_len(sv->value.pv, len);
            strada_set_utf8_flag(out, 0);
            return out;
        }
        strada_incref(sv);
        return sv;
    }
    return perla_encode_to_bytes(sv, enc);
}

static StradaValue *perla_encode_decode(StradaValue *args) {
    if (!args) return strada_new_str("");
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 2) return strada_new_str("");
    StradaValue *enc_sv = av->elements[av->head + 0];
    StradaValue *sv = av->elements[av->head + 1];
    if (!sv) return strada_new_str("");
    char *enc_name = enc_sv ? strada_to_str(enc_sv) : NULL;
    PerlaEncId enc = perla_enc_id(enc_name);
    free(enc_name);

    if (enc == PERLA_ENC_UTF8 || enc == PERLA_ENC_UNKNOWN) {
        if (!STRADA_IS_TAGGED_INT(sv) && sv->type == STRADA_STR && sv->value.pv) {
            if (sv->refcount == 1 && !STRADA_STR_IS_UTF8(sv)) {
                strada_set_utf8_flag(sv, 1);
                strada_incref(sv);
                return sv;
            }
            if (STRADA_STR_IS_UTF8(sv)) {
                strada_incref(sv);
                return sv;
            }
            size_t len = STRADA_STR_BYTELEN(sv);
            if (len == 0) len = strlen(sv->value.pv);
            return strada_new_str_len_utf8(sv->value.pv, len);
        }
        strada_incref(sv);
        return sv;
    }
    return perla_encode_from_bytes(sv, enc);
}
static StradaValue *perla_encode_is_utf8(StradaValue *args) {
    return perla_utf8_is_utf8(args);
}

/* ============================================================
 * Unicode normalization (NFC / NFD / NFKC / NFKD)
 * ============================================================
 *
 * The mapping table below covers the Latin-1 Supplement
 * (U+00C0–U+00FF), Latin Extended-A (U+0100–U+017F), and the
 * common Greek precomposed letters. That's the bulk of what
 * everyday CPAN code normalises. For coverage beyond this set
 * the normaliser is a pass-through — better to return the input
 * unchanged than to silently drop accents we don't recognise.
 *
 * Hangul Syllables (U+AC00–U+D7A3) decompose algorithmically via
 * the Unicode standard formula, so no table entry is needed.
 *
 * NFKC/NFKD currently alias NFC/NFD — compatibility decomposition
 * (e.g. ﬁ → fi) needs a separate, larger table that we don't yet
 * carry. Codepoints with only compatibility decompositions are
 * passed through unchanged. */

/* Unicode normalization now lives in the Strada runtime
 * (strada_runtime.c + strada_norm_tables.h). Perla calls
 * strada_unicode_normalize directly via the wrappers below. */
extern StradaValue *strada_unicode_normalize(StradaValue *sv, int compose, int compat);

