/* The Unicode normalization helpers used to live here. They were
 * promoted to strada_runtime.c so any Strada user (not just perla)
 * can call utf8::nfc / utf8::nfd / utf8::nfkc / utf8::nfkd /
 * utf8::normalize. The perla wrappers below delegate to the
 * Strada-side strada_unicode_normalize. */


/* Sugar wrappers: NFC($s) / NFD($s). Called as Unicode::Normalize::NFC
 * directly so the user doesn't have to spell out the form name. */
StradaValue *perla_unicode_normalize_nfc(StradaValue *args) {
    if (!args) return strada_new_str("");
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_str("");
    return strada_unicode_normalize(av->elements[av->head + 0], 1, 0);
}

StradaValue *perla_unicode_normalize_nfd(StradaValue *args) {
    if (!args) return strada_new_str("");
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_str("");
    return strada_unicode_normalize(av->elements[av->head + 0], 0, 0);
}

StradaValue *perla_unicode_normalize_nfkc(StradaValue *args) {
    if (!args) return strada_new_str("");
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_str("");
    return strada_unicode_normalize(av->elements[av->head + 0], 1, 1);
}

StradaValue *perla_unicode_normalize_nfkd(StradaValue *args) {
    if (!args) return strada_new_str("");
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_str("");
    return strada_unicode_normalize(av->elements[av->head + 0], 0, 1);
}

/* core::unicode_normalize($s, $form) — $form is "NFC" / "NFD" /
 * "NFKC" / "NFKD" (case-insensitive). NFKC/NFKD currently alias
 * NFC/NFD (compatibility decomposition table not yet carried);
 * an unknown form falls back to a pass-through. */
StradaValue *perla_unicode_normalize(StradaValue *args) {
    if (!args) return strada_new_str("");
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 2) return strada_new_str("");
    /* Perl signature: normalize(FORM, STR). */
    char *form_buf = strada_to_str(av->elements[av->head + 0]);
    StradaValue *sv = av->elements[av->head + 1];
    const char *form = form_buf ? form_buf : "NFC";
    int compose = 1, compat = 0;
    if (perla_enc_eq_ci(form, "NFD")) { compose = 0; compat = 0; }
    else if (perla_enc_eq_ci(form, "NFKC")) { compose = 1; compat = 1; }
    else if (perla_enc_eq_ci(form, "NFKD")) { compose = 0; compat = 1; }
    /* else NFC */
    StradaValue *r = strada_unicode_normalize(sv, compose, compat);
    if (form_buf) free(form_buf);
    return r;
}
/* getpwuid / getpwnam — Perl list-context shape (9 elements):
 *   (name, passwd, uid, gid, quota, comment, gcos, dir, shell)
 * Scalar context returns just the name. perla's existing
 * strada_getpwuid returns a hash, which mismatches Perl semantics.
 */
#include <pwd.h>
StradaValue *perla_getpwuid_list(StradaValue *uid_sv) {
    uid_t u = (uid_t)strada_to_int(uid_sv);
    struct passwd *pw = getpwuid(u);
    if (!pw) return strada_new_undef();
    StradaValue *out = strada_new_array();
    StradaArray *av = strada_deref_array(out);
    strada_array_push_take(av, strada_new_str(pw->pw_name ? pw->pw_name : ""));
    strada_array_push_take(av, strada_new_str(pw->pw_passwd ? pw->pw_passwd : ""));
    strada_array_push_take(av, STRADA_MAKE_TAGGED_INT((int64_t)pw->pw_uid));
    strada_array_push_take(av, STRADA_MAKE_TAGGED_INT((int64_t)pw->pw_gid));
    strada_array_push_take(av, strada_new_str(""));
    strada_array_push_take(av, strada_new_str(""));
    strada_array_push_take(av, strada_new_str(pw->pw_gecos ? pw->pw_gecos : ""));
    strada_array_push_take(av, strada_new_str(pw->pw_dir ? pw->pw_dir : ""));
    strada_array_push_take(av, strada_new_str(pw->pw_shell ? pw->pw_shell : ""));
    return out;
}
StradaValue *perla_getpwuid_name(StradaValue *uid_sv) {
    uid_t u = (uid_t)strada_to_int(uid_sv);
    struct passwd *pw = getpwuid(u);
    if (!pw) return strada_new_undef();
    return strada_new_str(pw->pw_name ? pw->pw_name : "");
}
StradaValue *perla_getpwnam_list(StradaValue *name_sv) {
    char *n = strada_to_str(name_sv);
    struct passwd *pw = getpwnam(n);
    free(n);
    if (!pw) return strada_new_undef();
    StradaValue *out = strada_new_array();
    StradaArray *av = strada_deref_array(out);
    strada_array_push_take(av, strada_new_str(pw->pw_name ? pw->pw_name : ""));
    strada_array_push_take(av, strada_new_str(pw->pw_passwd ? pw->pw_passwd : ""));
    strada_array_push_take(av, STRADA_MAKE_TAGGED_INT((int64_t)pw->pw_uid));
    strada_array_push_take(av, STRADA_MAKE_TAGGED_INT((int64_t)pw->pw_gid));
    strada_array_push_take(av, strada_new_str(""));
    strada_array_push_take(av, strada_new_str(""));
    strada_array_push_take(av, strada_new_str(pw->pw_gecos ? pw->pw_gecos : ""));
    strada_array_push_take(av, strada_new_str(pw->pw_dir ? pw->pw_dir : ""));
    strada_array_push_take(av, strada_new_str(pw->pw_shell ? pw->pw_shell : ""));
    return out;
}
StradaValue *perla_getpwnam_name(StradaValue *name_sv) {
    char *n = strada_to_str(name_sv);
    struct passwd *pw = getpwnam(n);
    free(n);
    if (!pw) return strada_new_undef();
    return strada_new_str(pw->pw_name ? pw->pw_name : "");
}

/* Encode::encode_utf8(STRING) — convenience wrapper, identical to
 * encode('UTF-8', STRING). Reshapes args by prepending the encoding
 * name and delegates to perla_encode_encode so the SVf_UTF8 flag
 * handling stays in one place. */
static StradaValue *perla_encode_encode_utf8(StradaValue *args) {
    if (!args) return strada_new_str("");
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_str("");
    StradaValue *sv = av->elements[av->head + 0];
    StradaValue *new_args = strada_new_array();
    StradaArray *nav = strada_deref_array(new_args);
    strada_array_push_take(nav, strada_new_str("UTF-8"));
    if (sv) { strada_incref(sv); strada_array_push_take(nav, sv); }
    StradaValue *res = perla_encode_encode(new_args);
    strada_decref(new_args);
    return res;
}
/* Encode::decode_utf8(BYTES) — convenience wrapper, identical to
 * decode('UTF-8', BYTES). */
static StradaValue *perla_encode_decode_utf8(StradaValue *args) {
    if (!args) return strada_new_str("");
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_str("");
    StradaValue *sv = av->elements[av->head + 0];
    StradaValue *new_args = strada_new_array();
    StradaArray *nav = strada_deref_array(new_args);
    strada_array_push_take(nav, strada_new_str("UTF-8"));
    if (sv) { strada_incref(sv); strada_array_push_take(nav, sv); }
    StradaValue *res = perla_encode_decode(new_args);
    strada_decref(new_args);
    return res;
}
static StradaValue *perla_encode_find_encoding(StradaValue *args) {
    /* Return a truthy stub — most callers just check if the encoding
     * "exists" before encode/decode. */
    (void)args;
    return strada_new_str("UTF-8");
}

/* utf8::is_utf8 / Encode::is_utf8 — Perl semantics: returns TRUE iff
 * the SVf_UTF8 flag is set on the SV. This is a *flag* check, not a
 * byte-content check — perl distinguishes char-mode and byte-mode
 * strings via the flag, and code that does `if (is_utf8($x)) decode_utf8(...)`
 * relies on it to detect already-decoded strings. Without flag-based
 * dispatch, encode_utf8/decode_utf8 round-trip checks return wrong
 * results. Falls back to content scanning for non-STR / tagged-int. */
static StradaValue *perla_utf8_is_utf8(StradaValue *args) {
    if (!args) return STRADA_MAKE_TAGGED_INT(0);
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return STRADA_MAKE_TAGGED_INT(0);
    StradaValue *sv = av->elements[av->head + 0];
    if (!sv) return STRADA_MAKE_TAGGED_INT(0);
    if (!STRADA_IS_TAGGED_INT(sv) && sv->type == STRADA_STR) {
        return STRADA_STR_IS_UTF8(sv) ? STRADA_MAKE_TAGGED_INT(1)
                                       : STRADA_MAKE_TAGGED_INT(0);
    }
    /* Non-STR fallback: detect any high-bit byte that's part of a
     * valid UTF-8 sequence (mirrors the previous behavior). */
    char *bytes = strada_to_str(sv);
    if (!bytes) return STRADA_MAKE_TAGGED_INT(0);
    size_t n = strlen(bytes);
    int has_high = 0;
    for (size_t i = 0; i < n; i++) {
        if ((unsigned char)bytes[i] >= 0x80) { has_high = 1; break; }
    }
    int valid = perla_utf8_bytes_valid((const unsigned char*)bytes, n);
    free(bytes);
    return STRADA_MAKE_TAGGED_INT(has_high && valid ? 1 : 0);
}

/* utf8::valid — return true iff the string is well-formed UTF-8. */
static StradaValue *perla_utf8_valid(StradaValue *args) {
    return perla_utf8_decode(args);
}

/* utf8::upgrade — no-op. */
static StradaValue *perla_utf8_upgrade(StradaValue *args) {
    if (!args) return STRADA_MAKE_TAGGED_INT(0);
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return STRADA_MAKE_TAGGED_INT(0);
    StradaValue *sv = av->elements[av->head + 0];
    if (!sv) return STRADA_MAKE_TAGGED_INT(0);
    char *bytes = strada_to_str(sv);
    if (!bytes) return STRADA_MAKE_TAGGED_INT(0);
    int len = (int)strlen(bytes);
    free(bytes);
    return STRADA_MAKE_TAGGED_INT(len);
}

/* utf8::downgrade — no-op (always succeeds). */
static StradaValue *perla_utf8_downgrade(StradaValue *args) {
    (void)args;
    return STRADA_MAKE_TAGGED_INT(1);
}

/* JSON::PP::is_valid_utf8 — native override. Reads $JSON::PP::text and
 * $JSON::PP::at (perla mirrors file-scope my-vars to the package stash
 * at end-of-init via the Exporter-sync hook). Walks the next 1-4 bytes
 * of $text starting at offset $at - 1, validates as UTF-8, sets
 * $JSON::PP::utf8_len to the byte length, and returns the validated
 * bytes. Returns undef on malformed input. */
static StradaValue *perla_json_pp_is_valid_utf8(StradaValue *args) {
    (void)args;
    StradaValue *text_sv = perla_scalar_get("JSON::PP", "text");
    StradaValue *at_sv = perla_scalar_get("JSON::PP", "at");
    if (!text_sv || !at_sv) return strada_new_undef();
    char *text = strada_to_str(text_sv);
    if (!text) return strada_new_undef();
    int at_val = (int)strada_to_int(at_sv);
    size_t tlen = strlen(text);
    int start = at_val - 1;
    if (start < 0 || (size_t)start >= tlen) { free(text); return strada_new_undef(); }
    unsigned char b = (unsigned char)text[start];
    int n;
    if (b < 0x80) { n = 1; }
    else if ((b & 0xE0) == 0xC0) { n = 2; }
    else if ((b & 0xF0) == 0xE0) { n = 3; }
    else if ((b & 0xF8) == 0xF0) { n = 4; }
    else { free(text); return strada_new_undef(); }
    if ((size_t)(start + n) > tlen) { free(text); return strada_new_undef(); }
    for (int i = 1; i < n; i++) {
        unsigned char c = (unsigned char)text[start + i];
        if ((c & 0xC0) != 0x80) { free(text); return strada_new_undef(); }
    }
    /* Reject overlongs and surrogates. */
    if (n == 2 && b < 0xC2) { free(text); return strada_new_undef(); }
    if (n == 3 && b == 0xE0 && (unsigned char)text[start + 1] < 0xA0) { free(text); return strada_new_undef(); }
    if (n == 3 && b == 0xED && (unsigned char)text[start + 1] >= 0xA0) { free(text); return strada_new_undef(); }
    if (n == 4 && b == 0xF0 && (unsigned char)text[start + 1] < 0x90) { free(text); return strada_new_undef(); }
    if (n == 4 && b == 0xF4 && (unsigned char)text[start + 1] >= 0x90) { free(text); return strada_new_undef(); }
    /* Set $utf8_len in the JSON::PP stash. */
    perla_scalar_set("JSON::PP", "utf8_len", STRADA_MAKE_TAGGED_INT(n));
    /* Return the validated bytes as a new string. */
    char *buf = (char*)malloc((size_t)n + 1);
    memcpy(buf, text + start, (size_t)n);
    buf[n] = 0;
    StradaValue *r = strada_new_str(buf);
    free(buf);
    free(text);
    return r;
}

/* ===== Minimal JSON Parser =====
 * Parses RFC 8259 JSON. Operates on bytes — multi-byte UTF-8 chars are
 * passed through as bytes verbatim into string values. Surrogate pairs
 * in `\uXXXX` escapes are joined and re-encoded as UTF-8 bytes. */
typedef struct { const char *p; const char *end; const char *err; } JSONP;

static void json_skip_ws(JSONP *j) {
    while (j->p < j->end) {
        unsigned char c = (unsigned char)*j->p;
        if (c == ' ' || c == '\t' || c == '\n' || c == '\r') j->p++;
        else break;
    }
}

static StradaValue *json_parse_value(JSONP *j);
StradaValue *perla_json_pp_true_fn(StradaValue *args);
StradaValue *perla_json_pp_false_fn(StradaValue *args);

static StradaValue *json_parse_string(JSONP *j) {
    if (j->p >= j->end || *j->p != '"') { j->err = "expected '\"'"; return NULL; }
    j->p++;
    /* Compute conservative upper bound for output. */
    size_t cap = 64;
    char *buf = (char*)malloc(cap);
    size_t len = 0;
    while (j->p < j->end) {
        unsigned char c = (unsigned char)*j->p;
        if (c == '"') { j->p++; goto done; }
        if (c == '\\') {
            j->p++;
            if (j->p >= j->end) { free(buf); j->err = "trailing backslash"; return NULL; }
            char esc = *j->p++;
            char out[8];
            int outn = 0;
            switch (esc) {
                case '"': out[0] = '"'; outn = 1; break;
                case '\\': out[0] = '\\'; outn = 1; break;
                case '/': out[0] = '/'; outn = 1; break;
                case 'b': out[0] = '\b'; outn = 1; break;
                case 'f': out[0] = '\f'; outn = 1; break;
                case 'n': out[0] = '\n'; outn = 1; break;
                case 'r': out[0] = '\r'; outn = 1; break;
                case 't': out[0] = '\t'; outn = 1; break;
                case 'u': {
                    if (j->p + 4 > j->end) { free(buf); j->err = "bad \\u escape"; return NULL; }
                    unsigned int cp = 0;
                    for (int k = 0; k < 4; k++) {
                        char h = j->p[k];
                        cp <<= 4;
                        if (h >= '0' && h <= '9') cp |= h - '0';
                        else if (h >= 'a' && h <= 'f') cp |= h - 'a' + 10;
                        else if (h >= 'A' && h <= 'F') cp |= h - 'A' + 10;
                        else { free(buf); j->err = "bad hex in \\u"; return NULL; }
                    }
                    j->p += 4;
                    /* Surrogate pair? */
                    if (cp >= 0xD800 && cp <= 0xDBFF && j->p + 6 <= j->end &&
                        j->p[0] == '\\' && j->p[1] == 'u') {
                        unsigned int cp2 = 0;
                        for (int k = 0; k < 4; k++) {
                            char h = j->p[2 + k];
                            cp2 <<= 4;
                            if (h >= '0' && h <= '9') cp2 |= h - '0';
                            else if (h >= 'a' && h <= 'f') cp2 |= h - 'a' + 10;
                            else if (h >= 'A' && h <= 'F') cp2 |= h - 'A' + 10;
                            else { free(buf); j->err = "bad hex in \\u (low surrogate)"; return NULL; }
                        }
                        if (cp2 >= 0xDC00 && cp2 <= 0xDFFF) {
                            cp = 0x10000 + ((cp - 0xD800) << 10) + (cp2 - 0xDC00);
                            j->p += 6;
                        }
                    }
                    /* Encode codepoint as UTF-8. */
                    if (cp < 0x80) {
                        out[0] = (char)cp; outn = 1;
                    } else if (cp < 0x800) {
                        out[0] = (char)(0xC0 | (cp >> 6));
                        out[1] = (char)(0x80 | (cp & 0x3F));
                        outn = 2;
                    } else if (cp < 0x10000) {
                        out[0] = (char)(0xE0 | (cp >> 12));
                        out[1] = (char)(0x80 | ((cp >> 6) & 0x3F));
                        out[2] = (char)(0x80 | (cp & 0x3F));
                        outn = 3;
                    } else {
                        out[0] = (char)(0xF0 | (cp >> 18));
                        out[1] = (char)(0x80 | ((cp >> 12) & 0x3F));
                        out[2] = (char)(0x80 | ((cp >> 6) & 0x3F));
                        out[3] = (char)(0x80 | (cp & 0x3F));
                        outn = 4;
                    }
                    break;
                }
                default: free(buf); j->err = "bad escape"; return NULL;
            }
            if (len + outn + 1 > cap) {
                cap = (len + outn + 1) * 2;
                buf = (char*)realloc(buf, cap);
            }
            for (int k = 0; k < outn; k++) buf[len++] = out[k];
        } else if (c < 0x20) {
            free(buf); j->err = "control char in string"; return NULL;
        } else {
            /* Pass through bytes (including UTF-8 sequences) verbatim. */
            if (len + 5 > cap) { cap *= 2; buf = (char*)realloc(buf, cap); }
            buf[len++] = (char)c;
            j->p++;
        }
    }
    free(buf); j->err = "unterminated string"; return NULL;
done:
    buf[len] = 0;
    StradaValue *r = strada_new_str_len(buf, len);
    free(buf);
    return r;
}

static StradaValue *json_parse_number(JSONP *j) {
    const char *start = j->p;
    if (j->p < j->end && *j->p == '-') j->p++;
    int is_float = 0;
    while (j->p < j->end && *j->p >= '0' && *j->p <= '9') j->p++;
    if (j->p < j->end && *j->p == '.') { is_float = 1; j->p++; while (j->p < j->end && *j->p >= '0' && *j->p <= '9') j->p++; }
    if (j->p < j->end && (*j->p == 'e' || *j->p == 'E')) {
        is_float = 1; j->p++;
        if (j->p < j->end && (*j->p == '+' || *j->p == '-')) j->p++;
        while (j->p < j->end && *j->p >= '0' && *j->p <= '9') j->p++;
    }
    size_t n = (size_t)(j->p - start);
    char buf[64];
    if (n >= sizeof(buf)) { j->err = "number too long"; return NULL; }
    memcpy(buf, start, n); buf[n] = 0;
    if (is_float) {
        return strada_new_num(strtod(buf, NULL));
    } else {
        long long v = strtoll(buf, NULL, 10);
        if (v >= -((long long)1 << 62) && v < ((long long)1 << 62)) {
            return STRADA_MAKE_TAGGED_INT((int64_t)v);
        }
        return strada_new_int((int64_t)v);
    }
}

static StradaValue *json_parse_array(JSONP *j) {
    j->p++; /* consume '[' */
    StradaValue *arr = strada_new_array();
    StradaArray *av = strada_deref_array(arr);
    json_skip_ws(j);
    if (j->p < j->end && *j->p == ']') { j->p++; return strada_new_ref_take(arr, '@'); }
    while (j->p < j->end) {
        json_skip_ws(j);
        StradaValue *elem = json_parse_value(j);
        if (!elem) { strada_decref(arr); return NULL; }
        strada_array_push_take(av, elem);
        json_skip_ws(j);
        if (j->p < j->end && *j->p == ',') { j->p++; continue; }
        if (j->p < j->end && *j->p == ']') { j->p++; return strada_new_ref_take(arr, '@'); }
        strada_decref(arr); j->err = "expected ',' or ']'"; return NULL;
    }
    strada_decref(arr); j->err = "unterminated array"; return NULL;
}

static StradaValue *json_parse_object(JSONP *j) {
    j->p++; /* consume '{' */
    StradaValue *h = strada_new_hash();
    json_skip_ws(j);
    if (j->p < j->end && *j->p == '}') { j->p++; return strada_new_ref_take(h, '%'); }
    while (j->p < j->end) {
        json_skip_ws(j);
        if (*j->p != '"') { strada_decref(h); j->err = "expected key string"; return NULL; }
        StradaValue *key_sv = json_parse_string(j);
        if (!key_sv) { strada_decref(h); return NULL; }
        char *key = strada_to_str(key_sv);
        strada_decref(key_sv);
        json_skip_ws(j);
        if (j->p >= j->end || *j->p != ':') { free(key); strada_decref(h); j->err = "expected ':'"; return NULL; }
        j->p++;
        json_skip_ws(j);
        StradaValue *val = json_parse_value(j);
        if (!val) { free(key); strada_decref(h); return NULL; }
        strada_hv_store_take(h, key, val);
        free(key);
        json_skip_ws(j);
        if (j->p < j->end && *j->p == ',') { j->p++; continue; }
        if (j->p < j->end && *j->p == '}') { j->p++; return strada_new_ref_take(h, '%'); }
        strada_decref(h); j->err = "expected ',' or '}'"; return NULL;
    }
    strada_decref(h); j->err = "unterminated object"; return NULL;
}

static StradaValue *json_parse_value(JSONP *j) {
    json_skip_ws(j);
    if (j->p >= j->end) { j->err = "unexpected end"; return NULL; }
    char c = *j->p;
    if (c == '"') return json_parse_string(j);
    if (c == '{') return json_parse_object(j);
    if (c == '[') return json_parse_array(j);
    if (c == 't' && j->p + 4 <= j->end && memcmp(j->p, "true", 4) == 0) {
        j->p += 4;
        /* Bless as JSON::PP::Boolean so is_bool() round-trips through
         * decode/encode and the caller can tell true/false apart from
         * plain 1/0. Matches Perl's JSON::PP. */
        return perla_json_pp_true_fn(NULL);
    }
    if (c == 'f' && j->p + 5 <= j->end && memcmp(j->p, "false", 5) == 0) {
        j->p += 5;
        return perla_json_pp_false_fn(NULL);
    }
    if (c == 'n' && j->p + 4 <= j->end && memcmp(j->p, "null", 4) == 0) { j->p += 4; return strada_new_undef(); }
    if (c == '-' || (c >= '0' && c <= '9')) return json_parse_number(j);
    j->err = "unexpected character"; return NULL;
}

/* JSON::PP::decode($self, $text) — native parser. Caller invokes via
 * `$json->decode($text)` which dispatches through perla_method_dispatch
 * to our CPOINTER. Args: [obj, text]. Ignores obj (we parse with
 * default settings only). Returns the decoded structure or dies on
 * malformed input. */
static StradaValue *perla_json_pp_decode(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 2) return strada_new_undef();
    StradaValue *text_sv = av->elements[av->head + 1];
    if (!text_sv) return strada_new_undef();
    char *text = strada_to_str(text_sv);
    if (!text) return strada_new_undef();
    JSONP j = { text, text + strlen(text), NULL };
    StradaValue *r = json_parse_value(&j);
    if (!r) {
        char errbuf[256];
        snprintf(errbuf, sizeof(errbuf), "JSON decode error: %s", j.err ? j.err : "unknown");
        free(text);
        extern StradaValue *perla_eval_error;
        if (perla_eval_error) strada_decref(perla_eval_error);
        perla_eval_error = strada_new_str(errbuf);
        strada_incref(perla_eval_error);
        strada_die_sv(strada_new_str(errbuf));
        return strada_new_undef();
    }
    free(text);
    return r;
}

/* ===== Math::Trig native — pi/deg2rad/rad2deg/tan/sinh/cosh/tanh
 * etc. Perl's Math::Trig is a pure-perl module that doesn't fully
 * compile in perla's env, so bare `pi` came back as the literal
 * string "pi" and `deg2rad(180)` was 0. Native impl below. */
#include <math.h>
#ifndef PERLA_M_PI
#define PERLA_M_PI 3.14159265358979323846
#endif

static StradaValue *perla_trig_pi(StradaValue *args) { (void)args; return strada_new_num(PERLA_M_PI); }
static StradaValue *perla_trig_pi2(StradaValue *args) { (void)args; return strada_new_num(PERLA_M_PI * 2); }
static StradaValue *perla_trig_pip2(StradaValue *args) { (void)args; return strada_new_num(PERLA_M_PI / 2); }
static StradaValue *perla_trig_pip4(StradaValue *args) { (void)args; return strada_new_num(PERLA_M_PI / 4); }
static double perla_trig_first_arg(StradaValue *args) {
    if (!args) return 0.0;
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return 0.0;
    return strada_to_num(av->elements[av->head + 0]);
}
static StradaValue *perla_trig_deg2rad(StradaValue *args) { return strada_new_num(perla_trig_first_arg(args) * PERLA_M_PI / 180.0); }
static StradaValue *perla_trig_rad2deg(StradaValue *args) { return strada_new_num(perla_trig_first_arg(args) * 180.0 / PERLA_M_PI); }
static StradaValue *perla_trig_deg2grad(StradaValue *args) { return strada_new_num(perla_trig_first_arg(args) * 10.0 / 9.0); }
static StradaValue *perla_trig_grad2deg(StradaValue *args) { return strada_new_num(perla_trig_first_arg(args) * 0.9); }
static StradaValue *perla_trig_rad2grad(StradaValue *args) { return strada_new_num(perla_trig_first_arg(args) * 200.0 / PERLA_M_PI); }
static StradaValue *perla_trig_grad2rad(StradaValue *args) { return strada_new_num(perla_trig_first_arg(args) * PERLA_M_PI / 200.0); }
static StradaValue *perla_trig_tan(StradaValue *args) { return strada_new_num(tan(perla_trig_first_arg(args))); }
static StradaValue *perla_trig_sinh(StradaValue *args) { return strada_new_num(sinh(perla_trig_first_arg(args))); }
static StradaValue *perla_trig_cosh(StradaValue *args) { return strada_new_num(cosh(perla_trig_first_arg(args))); }
static StradaValue *perla_trig_tanh(StradaValue *args) { return strada_new_num(tanh(perla_trig_first_arg(args))); }
static StradaValue *perla_trig_asinh(StradaValue *args) { return strada_new_num(asinh(perla_trig_first_arg(args))); }
static StradaValue *perla_trig_acosh(StradaValue *args) { return strada_new_num(acosh(perla_trig_first_arg(args))); }
static StradaValue *perla_trig_atanh(StradaValue *args) { return strada_new_num(atanh(perla_trig_first_arg(args))); }

/* ===== File::Copy native — CPAN File::Copy.pm's pure-perl loop
 * uses sysread/syswrite patterns that don't work in perla, so copy()
 * returned undef and the file was never written. Native impl below
 * matches Perl's API: copy(SRC, DST) returns 1 on success, 0 on fail
 * with $! set. move(SRC, DST) tries rename, falls back to copy+unlink. */
static StradaValue *perla_file_copy_copy(StradaValue *args) {
    if (!args) return STRADA_MAKE_TAGGED_INT(0);
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 2) return STRADA_MAKE_TAGGED_INT(0);
    char *src = strada_to_str(av->elements[av->head + 0]);
    char *dst = strada_to_str(av->elements[av->head + 1]);
    if (!src || !dst) { if (src) free(src); if (dst) free(dst); return STRADA_MAKE_TAGGED_INT(0); }
    FILE *in = fopen(src, "rb");
    if (!in) { free(src); free(dst); return STRADA_MAKE_TAGGED_INT(0); }
    FILE *out = fopen(dst, "wb");
    if (!out) { fclose(in); free(src); free(dst); return STRADA_MAKE_TAGGED_INT(0); }
    char buf[8192];
    size_t n;
    int ok = 1;
    while ((n = fread(buf, 1, sizeof(buf), in)) > 0) {
        if (fwrite(buf, 1, n, out) != n) { ok = 0; break; }
    }
    if (ferror(in)) ok = 0;
    fclose(in);
    fclose(out);
    free(src);
    free(dst);
    return STRADA_MAKE_TAGGED_INT(ok ? 1 : 0);
}

static StradaValue *perla_file_copy_move(StradaValue *args) {
    if (!args) return STRADA_MAKE_TAGGED_INT(0);
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 2) return STRADA_MAKE_TAGGED_INT(0);
    char *src = strada_to_str(av->elements[av->head + 0]);
    char *dst = strada_to_str(av->elements[av->head + 1]);
    if (!src || !dst) { if (src) free(src); if (dst) free(dst); return STRADA_MAKE_TAGGED_INT(0); }
    /* Try fast-path rename — works within same filesystem. */
    if (rename(src, dst) == 0) {
        free(src); free(dst);
        return STRADA_MAKE_TAGGED_INT(1);
    }
    /* Cross-device — copy then unlink. */
    FILE *in = fopen(src, "rb");
    if (!in) { free(src); free(dst); return STRADA_MAKE_TAGGED_INT(0); }
    FILE *out = fopen(dst, "wb");
    if (!out) { fclose(in); free(src); free(dst); return STRADA_MAKE_TAGGED_INT(0); }
    char buf[8192];
    size_t n;
    int ok = 1;
    while ((n = fread(buf, 1, sizeof(buf), in)) > 0) {
        if (fwrite(buf, 1, n, out) != n) { ok = 0; break; }
    }
    if (ferror(in)) ok = 0;
    fclose(in);
    fclose(out);
    if (ok) unlink(src);
    free(src); free(dst);
    return STRADA_MAKE_TAGGED_INT(ok ? 1 : 0);
}

/* ===== Native JSON encoder ===== */
typedef struct {
    char *buf;
    size_t cap;
    size_t len;
    int canonical;   /* sort hash keys lexicographically */
    int pretty;      /* multi-line indented output */
    int indent_lvl;  /* current indent depth */
    /* Cycle-detection stack: pointers currently being encoded.
     * Capped at 256 — deeper structures degrade to a stack
     * overflow as before, but the common cyclic patterns (self-
     * referencing hash, A→B→A) are detected. Per JSON::PP the
     * canonical error is "circular reference"; we strada_die with
     * that message. */
    void *visited[256];
    int visited_n;
    int cycle_detected;
} JENC;

static void jenc_grow(JENC *j, size_t need) {
    if (j->len + need + 1 > j->cap) {
        size_t nc = j->cap ? j->cap * 2 : 256;
        while (nc < j->len + need + 1) nc *= 2;
        j->buf = (char*)realloc(j->buf, nc);
        j->cap = nc;
    }
}
static void jenc_put(JENC *j, const char *s, size_t n) { jenc_grow(j, n); memcpy(j->buf + j->len, s, n); j->len += n; }
static void jenc_putc(JENC *j, char c) { jenc_grow(j, 1); j->buf[j->len++] = c; }
static void jenc_str_escape(JENC *j, const char *s, size_t n) {
    jenc_putc(j, '"');
    for (size_t i = 0; i < n; i++) {
        unsigned char c = (unsigned char)s[i];
        if (c == '"')        jenc_put(j, "\\\"", 2);
        else if (c == '\\')  jenc_put(j, "\\\\", 2);
        else if (c == '\n')  jenc_put(j, "\\n", 2);
        else if (c == '\r')  jenc_put(j, "\\r", 2);
        else if (c == '\t')  jenc_put(j, "\\t", 2);
        else if (c == '\b')  jenc_put(j, "\\b", 2);
        else if (c == '\f')  jenc_put(j, "\\f", 2);
        else if (c < 0x20)   { char esc[8]; int n2 = snprintf(esc, sizeof(esc), "\\u%04x", c); jenc_put(j, esc, n2); }
        else                 jenc_putc(j, (char)c);
    }
    jenc_putc(j, '"');
}

static void jenc_value(JENC *j, StradaValue *v);

static void jenc_indent(JENC *j) {
    if (!j->pretty) return;
    jenc_putc(j, '\n');
    for (int k = 0; k < j->indent_lvl; k++) jenc_put(j, "   ", 3);
}

static void jenc_array(JENC *j, StradaArray *av) {
    jenc_putc(j, '[');
    if (av && av->size > 0) {
        j->indent_lvl++;
        for (size_t i = 0; i < av->size; i++) {
            if (i) jenc_putc(j, ',');
            jenc_indent(j);
            jenc_value(j, av->elements[av->head + i]);
        }
        j->indent_lvl--;
        jenc_indent(j);
    }
    jenc_putc(j, ']');
}

static int jenc_key_cmp(const void *a, const void *b) {
    const StradaHashEntry *ea = *(const StradaHashEntry *const *)a;
    const StradaHashEntry *eb = *(const StradaHashEntry *const *)b;
    size_t na = ea->key->len, nb = eb->key->len;
    size_t n = na < nb ? na : nb;
    int r = memcmp(ea->key->data, eb->key->data, n);
    if (r != 0) return r;
    return (na < nb) ? -1 : (na > nb) ? 1 : 0;
}

static void jenc_hash(JENC *j, StradaHash *hv) {
    jenc_putc(j, '{');
    if (hv && hv->next_slot > 0) {
        /* Collect non-null entries; optionally sort. */
        StradaHashEntry **entries = NULL;
        size_t count = 0;
        if (j->canonical) {
            entries = (StradaHashEntry**)malloc(hv->next_slot * sizeof(*entries));
            if (entries) {
                for (size_t i = 0; i < hv->next_slot; i++) {
                    if (hv->entries[i].key) entries[count++] = &hv->entries[i];
                }
                qsort(entries, count, sizeof(*entries), jenc_key_cmp);
            }
        }
        int first = 1;
        size_t iter_max = j->canonical ? count : hv->next_slot;
        j->indent_lvl++;
        for (size_t i = 0; i < iter_max; i++) {
            StradaHashEntry *e = j->canonical ? entries[i] : &hv->entries[i];
            if (!e->key) continue;
            if (!first) jenc_putc(j, ',');
            first = 0;
            jenc_indent(j);
            jenc_str_escape(j, e->key->data, e->key->len);
            /* Pretty-print uses " : " (space-colon-space) to match
             * Perl's JSON::PP default; compact mode just ":". */
            if (j->pretty) jenc_put(j, " : ", 3);
            else jenc_putc(j, ':');
            jenc_value(j, e->value);
        }
        j->indent_lvl--;
        if (!first) jenc_indent(j);
        if (entries) free(entries);
    }
    jenc_putc(j, '}');
}

static void jenc_value(JENC *j, StradaValue *v) {
    if (!v) { jenc_put(j, "null", 4); return; }
    if (STRADA_IS_TAGGED_INT(v)) {
        int64_t n = STRADA_TAGGED_INT_VAL(v);
        char buf[32]; int len = snprintf(buf, sizeof(buf), "%lld", (long long)n);
        jenc_put(j, buf, len);
        return;
    }
    /* Cycle detection: for container types (ARRAY/HASH/REF), check
     * whether this SV is already on the encode stack. If so, abort
     * with strada_die — matches JSON::PP's "circular reference"
     * error rather than recursing forever. */
    if (v->type == STRADA_REF || v->type == STRADA_ARRAY || v->type == STRADA_HASH) {
        for (int i = 0; i < j->visited_n; i++) {
            if (j->visited[i] == (void *)v) {
                if (!j->cycle_detected) {
                    j->cycle_detected = 1;
                    strada_die("circular reference");
                }
                jenc_put(j, "null", 4);
                return;
            }
        }
        if (j->visited_n < 256) {
            j->visited[j->visited_n++] = (void *)v;
        }
    }
    switch (v->type) {
        case STRADA_UNDEF: jenc_put(j, "null", 4); break;
        case STRADA_INT: {
            char buf[32]; int len = snprintf(buf, sizeof(buf), "%lld", (long long)v->value.iv);
            jenc_put(j, buf, len);
            break;
        }
        case STRADA_NUM: {
            double d = v->value.nv;
            if (isnan(d) || isinf(d)) { jenc_put(j, "null", 4); break; }
            char buf[32];
            int len = 0;
            /* Whole-valued floats that fit in int64 → print as int
             * (no scientific notation, no trailing zeros). Matches
             * Perl JSON::PP which prefers integer representation. */
            if (d >= -9.2233720368547748e18 && d <= 9.2233720368547748e18
                && d == (double)(int64_t)d) {
                len = snprintf(buf, sizeof(buf), "%lld", (long long)d);
                jenc_put(j, buf, len);
                break;
            }
            /* Use shortest-round-trip formatting like Perl: try
             * progressively higher precision until the string parses
             * back to the same double. "%.17g" is the safe ceiling
             * for IEEE 754 doubles, but most numbers (3.14, 0.5, etc.)
             * round-trip at much lower precision and look cleaner. */
            int prec;
            for (prec = 1; prec <= 17; prec++) {
                len = snprintf(buf, sizeof(buf), "%.*g", prec, d);
                double parsed = strtod(buf, NULL);
                if (parsed == d) break;
            }
            jenc_put(j, buf, len);
            break;
        }
        case STRADA_STR: {
            size_t n = strada_str_len(v);
            jenc_str_escape(j, v->value.pv, n);
            break;
        }
        case STRADA_REF: {
            StradaValue *t = v->value.rv;
            if (!t) { jenc_put(j, "null", 4); break; }
            /* JSON::PP::Boolean (or perla equivalent) → true/false */
            if (v->meta && v->meta->blessed_package &&
                (strcmp(v->meta->blessed_package, "JSON::PP::Boolean") == 0 ||
                 strcmp(v->meta->blessed_package, "JSON::Boolean") == 0)) {
                int64_t bv = strada_to_int(t);
                jenc_put(j, bv ? "true" : "false", bv ? 4 : 5);
                break;
            }
            /* Unblessed reference to a scalar → JSON boolean.
             * This is the standard JSON::PP convention: \1 encodes as
             * `true`, \0 as `false`. Refs to ARRAY/HASH/REF still recurse
             * (those are how you build nested structures). */
            if ((!v->meta || !v->meta->blessed_package) &&
                (t->type == STRADA_INT || t->type == STRADA_NUM ||
                 t->type == STRADA_STR || t->type == STRADA_UNDEF)) {
                int truthy = strada_to_bool(t);
                jenc_put(j, truthy ? "true" : "false", truthy ? 4 : 5);
                break;
            }
            /* Recurse on target */
            jenc_value(j, t);
            break;
        }
        case STRADA_ARRAY: jenc_array(j, v->value.av); break;
        case STRADA_HASH:  jenc_hash(j, v->value.hv); break;
        default: jenc_put(j, "null", 4); break;
    }
    /* Pop the visited stack entry pushed at function entry. */
    if (v->type == STRADA_REF || v->type == STRADA_ARRAY || v->type == STRADA_HASH) {
        if (j->visited_n > 0 && j->visited[j->visited_n - 1] == (void *)v) {
            j->visited_n--;
        }
    }
}

/* JSON::PP::true() / JSON::PP::false() — return blessed JSON::PP::Boolean
 * objects wrapping 1/0. The encoder already special-cases the
 * JSON::PP::Boolean class for emitting true/false JSON literals. */
StradaValue *perla_json_pp_true_fn(StradaValue *args) {
    (void)args;
    StradaValue *one = strada_new_int(1);
    StradaValue *ref = strada_new_ref(one, '$');
    strada_decref(one);
    /* Bless into JSON::PP::Boolean */
    StradaMetadata *meta = strada_ensure_meta(ref);
    if (meta) {
        if (meta->blessed_package && !meta->blessed_immortal) {
            /* free old package name */
        }
        meta->blessed_package = (char *)"JSON::PP::Boolean";
        meta->blessed_immortal = 1;
    }
    return ref;
}

StradaValue *perla_json_pp_false_fn(StradaValue *args) {
    (void)args;
    StradaValue *zero = strada_new_int(0);
    StradaValue *ref = strada_new_ref(zero, '$');
    strada_decref(zero);
    StradaMetadata *meta = strada_ensure_meta(ref);
    if (meta) {
        meta->blessed_package = (char *)"JSON::PP::Boolean";
        meta->blessed_immortal = 1;
    }
    return ref;
}

/* JSON::PP::null() — returns undef. JSON::PP defines it as a constant.
 * The encoder treats undef as JSON null, so this gives a uniform way to
 * write { "key" => JSON::PP::null } and have it encode as "key":null. */
StradaValue *perla_json_pp_null_fn(StradaValue *args) {
    (void)args;
    return strada_new_undef();
}

/* JSON::PP::Boolean's (0+ overload — derefs the blessed scalar ref to
 * its underlying 0/1, so `$json_bool ? "y" : "n"` evaluates the true/
 * false value instead of being unconditionally truthy (refs are always
 * truthy without overload). Used by perla_overload_bool's numeric
 * fallback path. */
StradaValue *perla_json_pp_boolean_numify(StradaValue *args) {
    if (!args) return strada_new_int(0);
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_int(0);
    StradaValue *sv = av->elements[av->head + 0];
    if (!sv || STRADA_IS_TAGGED_INT(sv)) return strada_new_int(0);
    if (sv->type == STRADA_REF && sv->value.rv) {
        return strada_new_int(strada_to_int(sv->value.rv));
    }
    return strada_new_int(strada_to_int(sv));
}
/* '""' overload — JSON::PP::Boolean is `bless \(my $b = 1|0)`, so its
 * string form is "$$self" → "1" / "0" (NOT the default object string).
 * Without this, decoded true/false stringify to "JSON::PP::Boolean=...". */
StradaValue *perla_json_pp_boolean_stringify(StradaValue *args) {
    if (!args) return strada_new_str("0");
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_str("0");
    StradaValue *sv = av->elements[av->head + 0];
    int64_t v = 0;
    if (sv && !STRADA_IS_TAGGED_INT(sv) && sv->type == STRADA_REF && sv->value.rv) {
        v = strada_to_int(sv->value.rv);
    } else if (sv) {
        v = strada_to_int(sv);
    }
    return strada_new_str(v ? "1" : "0");
}

/* JSON::PP::is_bool(SV) — returns 1 if SV is blessed JSON::PP::Boolean,
 * 0 otherwise. Used in decode round-trips to tell apart boolean values
 * from plain 0/1 integers. */
StradaValue *perla_json_pp_is_bool_fn(StradaValue *args) {
    if (!args) return strada_new_int(0);
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_int(0);
    StradaValue *sv = av->elements[av->head + 0];
    const char *bp = perla_blessed(sv);
    if (bp && strcmp(bp, "JSON::PP::Boolean") == 0) return strada_new_int(1);
    return strada_new_int(0);
}

/* JSON::PP::decode_json(TEXT) — top-level function form, takes [text]. */
static StradaValue *perla_json_pp_decode_json_fn(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_undef();
    StradaValue *text_sv = av->elements[av->head + 0];
    if (!text_sv) return strada_new_undef();
    char *text = strada_to_str(text_sv);
    if (!text) return strada_new_undef();
    JSONP j = { text, text + strlen(text), NULL };
    StradaValue *r = json_parse_value(&j);
    free(text);
    if (!r) return strada_new_undef();
    return r;
}

/* JSON::PP::encode_json(DATA) — top-level function form */
static StradaValue *perla_json_pp_encode_json(StradaValue *args) {
    if (!args) return strada_new_str("null");
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_str("null");
    JENC j = {0};
    jenc_value(&j, av->elements[av->head + 0]);
    jenc_grow(&j, 1); j.buf[j.len] = '\0';
    StradaValue *r = strada_new_str_len(j.buf, j.len);
    free(j.buf);
    return r;
}

/* ===== Digest::MD5 / Digest::SHA hex functions =====
 * Uses OpenSSL EVP_Digest (already linked). Functional forms only —
 * the OO `Digest::SHA->new(256)->add(...)->hexdigest` pattern needs
 * an incremental-context object which is deferred. */
#include <openssl/evp.h>

static StradaValue *perla_digest_hex_impl(StradaValue *args, const EVP_MD *md) {
    if (!args) return strada_new_str("");
    StradaArray *av = strada_deref_array(args);
    if (!av) return strada_new_str("");
    /* Concatenate all args as input (perl's md5_hex(LIST) hashes the
     * concatenation). */
    size_t total_len = 0;
    size_t n = av->size;
    char **bufs = NULL;
    size_t *lens = NULL;
    if (n > 0) {
        bufs = (char**)calloc(n, sizeof(char*));
        lens = (size_t*)calloc(n, sizeof(size_t));
        for (size_t i = 0; i < n; i++) {
            StradaValue *v = av->elements[av->head + i];
            if (!v) continue;
            if (!STRADA_IS_TAGGED_INT(v) && v->type == STRADA_STR && v->value.pv) {
                bufs[i] = v->value.pv;
                lens[i] = strada_str_len(v);
            } else {
                bufs[i] = strada_to_str(v);
                lens[i] = bufs[i] ? strlen(bufs[i]) : 0;
            }
            total_len += lens[i];
        }
    }
    unsigned char digest[EVP_MAX_MD_SIZE];
    unsigned int dlen = 0;
    EVP_MD_CTX *ctx = EVP_MD_CTX_new();
    EVP_DigestInit_ex(ctx, md, NULL);
    for (size_t i = 0; i < n; i++) {
        if (bufs && bufs[i] && lens[i] > 0) {
            EVP_DigestUpdate(ctx, bufs[i], lens[i]);
        }
    }
    EVP_DigestFinal_ex(ctx, digest, &dlen);
    EVP_MD_CTX_free(ctx);
    /* Free any strada_to_str-allocated buffers (those NOT pointing at
     * the borrowed value->pv). */
    if (n > 0) {
        for (size_t i = 0; i < n; i++) {
            StradaValue *v = av->elements[av->head + i];
            if (bufs[i] && (STRADA_IS_TAGGED_INT(v) || v->type != STRADA_STR || bufs[i] != v->value.pv)) {
                free(bufs[i]);
            }
        }
        free(bufs);
        free(lens);
    }
    char hex[EVP_MAX_MD_SIZE * 2 + 1];
    for (unsigned int i = 0; i < dlen; i++) {
        snprintf(hex + i * 2, 3, "%02x", digest[i]);
    }
    hex[dlen * 2] = '\0';
    return strada_new_str_len(hex, dlen * 2);
}

static StradaValue *perla_digest_md5_hex(StradaValue *args) { return perla_digest_hex_impl(args, EVP_md5()); }
static StradaValue *perla_digest_sha1_hex(StradaValue *args) { return perla_digest_hex_impl(args, EVP_sha1()); }
static StradaValue *perla_digest_sha224_hex(StradaValue *args) { return perla_digest_hex_impl(args, EVP_sha224()); }
static StradaValue *perla_digest_sha256_hex(StradaValue *args) { return perla_digest_hex_impl(args, EVP_sha256()); }
static StradaValue *perla_digest_sha384_hex(StradaValue *args) { return perla_digest_hex_impl(args, EVP_sha384()); }
static StradaValue *perla_digest_sha512_hex(StradaValue *args) { return perla_digest_hex_impl(args, EVP_sha512()); }

/* Raw binary digest impl — shared by md5/sha1/sha256/etc. Mirrors
 * perla_digest_hex_impl but returns the raw bytes rather than the
 * hex stringification. Required for Digest::MD5::md5(@) / Digest::SHA::
 * sha1(@) / sha256(@) functional forms, plus the *_base64 variants. */
static StradaValue *perla_digest_raw_impl(StradaValue *args, const EVP_MD *md, unsigned char *out, unsigned int *out_len) {
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    EVP_MD_CTX *ctx = EVP_MD_CTX_new();
    EVP_DigestInit_ex(ctx, md, NULL);
    if (av) {
        for (size_t i = 0; i < av->size; i++) {
            StradaValue *v = av->elements[av->head + i];
            if (!v) continue;
            const char *buf = NULL;
            size_t blen = 0;
            int allocated = 0;
            if (!STRADA_IS_TAGGED_INT(v) && v->type == STRADA_STR && v->value.pv) {
                buf = v->value.pv;
                blen = strada_str_len(v);
            } else {
                buf = strada_to_str(v);
                blen = buf ? strlen(buf) : 0;
                allocated = 1;
            }
            if (buf && blen > 0) EVP_DigestUpdate(ctx, buf, blen);
            if (allocated && buf) free((void*)buf);
        }
    }
    EVP_DigestFinal_ex(ctx, out, out_len);
    EVP_MD_CTX_free(ctx);
    return NULL;
}

static StradaValue *perla_digest_bin_impl(StradaValue *args, const EVP_MD *md) {
    unsigned char digest[EVP_MAX_MD_SIZE];
    unsigned int dlen = 0;
    perla_digest_raw_impl(args, md, digest, &dlen);
    return strada_new_str_len((const char *)digest, dlen);
}

static StradaValue *perla_digest_md5(StradaValue *args)    { return perla_digest_bin_impl(args, EVP_md5()); }
static StradaValue *perla_digest_sha1(StradaValue *args)   { return perla_digest_bin_impl(args, EVP_sha1()); }
static StradaValue *perla_digest_sha224(StradaValue *args) { return perla_digest_bin_impl(args, EVP_sha224()); }
static StradaValue *perla_digest_sha256(StradaValue *args) { return perla_digest_bin_impl(args, EVP_sha256()); }
static StradaValue *perla_digest_sha384(StradaValue *args) { return perla_digest_bin_impl(args, EVP_sha384()); }
static StradaValue *perla_digest_sha512(StradaValue *args) { return perla_digest_bin_impl(args, EVP_sha512()); }

/* Base64 digest variants. MIME::Base64-style "no trailing newline,
 * trailing '=' padding stripped" output to match Digest::MD5::md5_base64
 * and Digest::SHA::*_base64. */
static const char b64_alphabet[] = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
static StradaValue *perla_digest_b64_impl(StradaValue *args, const EVP_MD *md) {
    unsigned char digest[EVP_MAX_MD_SIZE];
    unsigned int dlen = 0;
    perla_digest_raw_impl(args, md, digest, &dlen);
    /* base64 encode dlen bytes; output is (dlen+2)/3 * 4 chars unpadded */
    size_t out_alloc = ((dlen + 2) / 3) * 4 + 1;
    char *out = malloc(out_alloc);
    size_t oi = 0;
    for (unsigned int i = 0; i < dlen; i += 3) {
        uint32_t triple = ((uint32_t)digest[i]) << 16;
        if (i + 1 < dlen) triple |= ((uint32_t)digest[i + 1]) << 8;
        if (i + 2 < dlen) triple |= (uint32_t)digest[i + 2];
        out[oi++] = b64_alphabet[(triple >> 18) & 0x3F];
        out[oi++] = b64_alphabet[(triple >> 12) & 0x3F];
        if (i + 1 < dlen) out[oi++] = b64_alphabet[(triple >> 6) & 0x3F];
        if (i + 2 < dlen) out[oi++] = b64_alphabet[triple & 0x3F];
    }
    out[oi] = '\0';
    StradaValue *r = strada_new_str_len(out, oi);
    free(out);
    return r;
}

static StradaValue *perla_digest_md5_base64(StradaValue *args)    { return perla_digest_b64_impl(args, EVP_md5()); }
static StradaValue *perla_digest_sha1_base64(StradaValue *args)   { return perla_digest_b64_impl(args, EVP_sha1()); }
static StradaValue *perla_digest_sha256_base64(StradaValue *args) { return perla_digest_b64_impl(args, EVP_sha256()); }

/* JSON::PP::encode($self, DATA) — method form, $self is the JSON::PP obj */
static StradaValue *perla_json_pp_encode_method(StradaValue *args) {
    if (!args) return strada_new_str("null");
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 2) return strada_new_str("null");
    JENC j = {0};
    /* Read fluent options from $self->{canonical} / ->{pretty} / ->{indent}.
     * $self is a blessed hashref (see JSON::PP::new). */
    StradaValue *self = av->elements[av->head + 0];
    if (self && !STRADA_IS_TAGGED_INT(self) && self->type == STRADA_REF) {
        StradaValue *inner = self->value.rv;
        if (inner && !STRADA_IS_TAGGED_INT(inner) && inner->type == STRADA_HASH && inner->value.hv) {
            StradaValue *c = strada_hash_get(inner->value.hv, "canonical");
            StradaValue *p = strada_hash_get(inner->value.hv, "pretty");
            StradaValue *i = strada_hash_get(inner->value.hv, "indent");
            if (c) j.canonical = (int)strada_to_int(c);
            if (p) j.pretty = (int)strada_to_int(p);
            if (i && !j.pretty) j.pretty = (int)strada_to_int(i);
        }
    }
    jenc_value(&j, av->elements[av->head + 1]);
    /* Pretty mode adds a trailing newline to match JSON::PP's output. */
    if (j.pretty) jenc_putc(&j, '\n');
    jenc_grow(&j, 1); j.buf[j.len] = '\0';
    StradaValue *r = strada_new_str_len(j.buf, j.len);
    free(j.buf);
    return r;
}

/* Storable::dclone — deep copy the single argument. Storable::dclone(REF)
 * returns a deep clone of REF. In the Perl XS version it uses freeze/thaw
 * internally; we use strada_clone which recursively copies arrays, hashes,
 * and refs. Scalars (int/num/str) are returned unchanged. */
static StradaValue *perla_storable_dclone(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_undef();
    StradaValue *target = av->elements[av->head + 0];
    return strada_clone(target);
}

/* Storable::freeze / Storable::thaw — perla doesn't implement the
 * binary Storable format. Serialize via Data::Dumper text and revive
 * via eval STRING. Sufficient for plain data structures (hash, array,
 * scalar refs). Loses code refs and STORABLE_freeze hooks. */
StradaValue *perla_storable_freeze(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_undef();
    /* Force Terse for the round-trip so thaw can eval directly. */
    int saved_terse = -1;
    StradaValue *t_sv = perla_scalar_get("Data::Dumper", "Terse");
    if (t_sv && !STRADA_IS_TAGGED_INT(t_sv) && t_sv->type != STRADA_UNDEF) {
        saved_terse = (int)strada_to_int(t_sv);
    }
    perla_scalar_set("Data::Dumper", "Terse", STRADA_MAKE_TAGGED_INT(1));
    StradaValue *one_arg = strada_new_array();
    strada_incref(av->elements[av->head + 0]);
    strada_array_push(strada_deref_array(one_arg), av->elements[av->head + 0]);
    StradaValue *dumped = perla_dumper(one_arg);
    strada_decref(one_arg);
    /* Restore Terse */
    if (saved_terse >= 0) {
        perla_scalar_set("Data::Dumper", "Terse", STRADA_MAKE_TAGGED_INT(saved_terse));
    }
    return dumped;
}
StradaValue *perla_storable_thaw(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_undef();
    StradaValue *src = av->elements[av->head + 0];
    if (!src) return strada_new_undef();
    /* eval the dumped text — wrap with `+(…)` so top-level `{`
     * parses as anon-hash, not a code BLOCK. The `+` prevents the
     * paren from being treated as part of a function call. */
    char *body = strada_to_str(src);
    if (!body) return strada_new_undef();
    size_t bl = strlen(body);
    size_t cl = bl + 5;
    char *wrapped = malloc(cl);
    snprintf(wrapped, cl, "+(%s)", body);
    free(body);
    StradaValue *src_sv = strada_new_str(wrapped);
    free(wrapped);
    StradaValue *r = perla_eval_string(src_sv, "main");
    strada_decref(src_sv);
    return r;
}

/* UNIVERSAL::can — checks whether $obj/$class can do $method. Returns
 * a truthy value (the code ref if found, 1 otherwise) or undef. */
static StradaValue *perla_universal_can(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 2) return strada_new_undef();
    StradaValue *obj = av->elements[av->head + 0];
    StradaValue *method_sv = av->elements[av->head + 1];
    if (!method_sv) return strada_new_undef();
    char *method = strada_to_str(method_sv);
    if (!method) return strada_new_undef();
    const char *pkg = perla_blessed(obj);
    if (!pkg) {
        if (obj && !STRADA_IS_TAGGED_INT(obj) && obj->type == STRADA_STR && obj->value.pv) {
            pkg = obj->value.pv;
        }
    }
    PerlGlob *g = pkg ? perla_method_resolve(pkg, method) : NULL;
    free(method);
    if (g && g->slots[PERLA_SLOT_CODE]) {
        StradaValue *code = g->slots[PERLA_SLOT_CODE];
        strada_incref(code);
        return code;
    }
    return strada_new_undef();
}

/* Exporter::import — implements the real @EXPORT / @EXPORT_OK /
 * %EXPORT_TAGS / :DEFAULT / :tag / !name semantics of CPAN's Exporter.pm.
 *
 * Called as `Package->import(@wanted)`. The first arg is the package
 * whose symbols to export from; @wanted is the list the `use Package
 * qw(...)` or `use Package @list` passed. Empty @wanted means import
 * everything in @EXPORT (the default set).
 *
 * The caller's package name comes from the Perla call-stack frame
 * (perla_call_stack[perla_call_depth-1]) — that mirrors Perl's caller()
 * semantics since Exporter::import is itself the frame being called.
 *
 * For each requested symbol:
 *   - Find it in the source package's stash (any slot: sub, scalar,
 *     array, hash).
 *   - Copy the appropriate glob slot into the caller's stash under the
 *     same name.
 * Sigil-prefixed names (&name, $name, @name, %name, *name) limit which
 * slot is copied; bare names default to copying the sub slot (and we
 * additionally copy scalar/array/hash if those exist too, matching
 * Exporter's glob-copy semantics).
 */
/* Exporter::export_ok_tags(@tags) / export_tags(@tags): expand the named
 * %EXPORT_TAGS entries of the CALLER's package into its @EXPORT_OK (resp.
 * @EXPORT). Many CPAN modules (Term::ANSIColor, POSIX, …) call these from a
 * BEGIN block; without them the BEGIN died with "Undefined subroutine", which
 * aborted the whole module's file-scope init (so e.g. Term::ANSIColor's
 * %ATTRIBUTES never got built and color() croaked "Invalid attribute name"). */
static StradaValue *perla_exporter_push_tags(StradaValue *args, const char *which) {
    const char *pkg = "main";
    if (perla_call_depth >= 1) {
        const char *p = perla_call_stack[perla_call_depth - 1].package;
        if (p && p[0] && strcmp(p, "Exporter") != 0) pkg = p;
    }
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av) return strada_new_undef();

    StradaValue *tags = perla_hash_get(pkg, "EXPORT_TAGS");
    StradaValue *target = perla_array_get(pkg, which);
    if (!target) {
        target = strada_new_array();
        perla_array_set(pkg, which, target);
    }
    StradaArray *tav = strada_deref_array(target);
    if (!tav) return strada_new_undef();

    for (size_t i = 0; i < av->size; i++) {
        char *tagname = strada_to_str(av->elements[av->head + i]);
        if (!tagname) continue;
        const char *tn = (tagname[0] == ':') ? tagname + 1 : tagname;  /* accept ':tag' or 'tag' */
        if (tags && !STRADA_IS_TAGGED_INT(tags) && tags->type == STRADA_HASH && tags->value.hv) {
            StradaValue *list = strada_hash_get(tags->value.hv, tn);
            /* %EXPORT_TAGS values are array refs; also tolerate a bare array. */
            StradaValue *la = NULL;
            if (list && !STRADA_IS_TAGGED_INT(list)) {
                if (list->type == STRADA_REF) la = list->value.rv;
                else if (list->type == STRADA_ARRAY) la = list;
            }
            if (la && !STRADA_IS_TAGGED_INT(la) && la->type == STRADA_ARRAY && la->value.av) {
                StradaArray *laa = la->value.av;
                for (size_t j = 0; j < laa->size; j++) {
                    StradaValue *sym = laa->elements[laa->head + j];
                    if (sym) strada_incref(sym);
                    strada_array_push_take(tav, sym ? sym : strada_new_undef());
                }
            }
        }
        free(tagname);
    }
    return strada_new_undef();
}

static StradaValue *perla_exporter_export_ok_tags(StradaValue *args) {
    return perla_exporter_push_tags(args, "EXPORT_OK");
}

static StradaValue *perla_exporter_export_tags(StradaValue *args) {
    return perla_exporter_push_tags(args, "EXPORT");
}

static StradaValue *perla_exporter_import(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_undef();

    /* arg 0 = the exporting package */
    char *from_pkg = strada_to_str(av->elements[av->head + 0]);
    if (!from_pkg || !from_pkg[0]) { free(from_pkg); return strada_new_undef(); }
    if (getenv("PERLA_EXPORTER_DEBUG")) {
        fprintf(stderr, "[exporter_import] from=%s argc=%zu call_depth=%d\n",
                from_pkg, av->size, perla_call_depth);
        for (size_t i = 0; i < av->size && i < 8; i++) {
            char *s = strada_to_str(av->elements[av->head + i]);
            fprintf(stderr, "  arg[%zu]=%s\n", i, s ? s : "NULL");
            free(s);
        }
    }

    /* caller package: look at the stack frame above this one.
     * perla_call_code(CPOINTER) doesn't push a frame for the C
     * function, so the top frame is the caller itself. Probe both
     * depth-1 and depth-2 and skip any frame whose package looks
     * like an internal/helper frame (e.g. main during module init
     * when we actually want the currently-active inlined module's
     * package from the /_ package _/ pseudo-statement).
     *
     * Override path: if perla_use_caller_pkg is set (codegen sets this
     * before emitting `use Module qw(...)` import dispatch — see the
     * `use Module` codegen in CodeGen.strada), use it directly. This
     * fixes the case where the call_stack top frame is the from_pkg
     * (e.g. .pm.so init context where mod_init's frame is the only
     * frame and depth-2 doesn't exist). Bizowie's `Abe::App.pm.so`
     * ran `use Storable qw(dclone)` and exporter_import fell back to
     * "main" instead of "Abe::App", so dclone was imported into main
     * and Abe::App::config died with `dclone undef` → silent undef
     * return → DBI bad-args → drogo-exit → app=UNDEF. */
    const char *to_pkg = "main";
    if (perla_use_caller_pkg && perla_use_caller_pkg[0] && strcmp(perla_use_caller_pkg, from_pkg) != 0) {
        to_pkg = perla_use_caller_pkg;
    } else {
        /* First try depth-1 (top frame) — if caller didn't push a frame,
         * this is the caller itself. */
        if (perla_call_depth >= 1) {
            const char *p = perla_call_stack[perla_call_depth - 1].package;
            if (p && p[0] && strcmp(p, from_pkg) != 0) to_pkg = p;
        }
        /* If that gave us "main" or the from_pkg itself, try one frame up. */
        if ((strcmp(to_pkg, "main") == 0 || strcmp(to_pkg, from_pkg) == 0)
            && perla_call_depth >= 2) {
            const char *p = perla_call_stack[perla_call_depth - 2].package;
            if (p && p[0] && strcmp(p, from_pkg) != 0) to_pkg = p;
        }
    }
    if (getenv("PERLA_EXPORTER_DEBUG")) {
        fprintf(stderr, "  chose to_pkg=%s (depth=%d)\n", to_pkg, perla_call_depth);
    }

    PerlStash *src_stash = perla_stash_get(from_pkg);
    if (!src_stash) { free(from_pkg); return strada_new_undef(); }

    /* Read @EXPORT and @EXPORT_OK */
    StradaArray *export_arr = NULL;
    StradaArray *export_ok_arr = NULL;
    StradaValue *export_sv = perla_array_get(from_pkg, "EXPORT");
    StradaValue *export_ok_sv = perla_array_get(from_pkg, "EXPORT_OK");
    if (export_sv) export_arr = strada_deref_array(export_sv);
    if (export_ok_sv) export_ok_arr = strada_deref_array(export_ok_sv);

    StradaValue *export_tags_sv = perla_hash_get(from_pkg, "EXPORT_TAGS");
    StradaHash *export_tags = export_tags_sv ? strada_deref_hash(export_tags_sv) : NULL;

    /* Build the list of names to import */
    size_t wanted_count = (av->size > 1) ? (av->size - 1) : 0;
    /* Max possible output: wanted_count tag expansions each up to @EXPORT_OK
     * plus @EXPORT if defaulting. Cap generously. */
    size_t cap = wanted_count + (export_arr ? export_arr->size : 0) + (export_ok_arr ? export_ok_arr->size : 0) + 16;
    char **names = (char**)calloc(cap, sizeof(char*));
    char **excludes = (char**)calloc(cap, sizeof(char*));
    size_t name_count = 0;
    size_t exclude_count = 0;

    if (wanted_count == 0) {
        /* Default: import @EXPORT */
        if (export_arr) {
            for (size_t i = 0; i < export_arr->size; i++) {
                char *nm = strada_to_str(export_arr->elements[export_arr->head + i]);
                if (nm && nm[0]) names[name_count++] = nm;
                else free(nm);
            }
        }
    } else {
        for (size_t i = 0; i < wanted_count; i++) {
            char *nm = strada_to_str(av->elements[av->head + 1 + i]);
            if (!nm || !nm[0]) { free(nm); continue; }

            if (nm[0] == '!') {
                /* !NAME — exclude */
                char *bare = strdup(nm + 1);
                excludes[exclude_count++] = bare;
                free(nm);
            } else if (nm[0] == ':') {
                /* :tag — expand via %EXPORT_TAGS, or :DEFAULT → @EXPORT, or :ALL → @EXPORT_OK */
                if (strcmp(nm, ":DEFAULT") == 0) {
                    if (export_arr) {
                        for (size_t j = 0; j < export_arr->size; j++) {
                            char *n2 = strada_to_str(export_arr->elements[export_arr->head + j]);
                            if (n2 && n2[0]) names[name_count++] = n2;
                            else free(n2);
                        }
                    }
                } else if (strcmp(nm, ":ALL") == 0) {
                    if (export_ok_arr) {
                        for (size_t j = 0; j < export_ok_arr->size; j++) {
                            char *n2 = strada_to_str(export_ok_arr->elements[export_ok_arr->head + j]);
                            if (n2 && n2[0]) names[name_count++] = n2;
                            else free(n2);
                        }
                    }
                    if (export_arr) {
                        for (size_t j = 0; j < export_arr->size; j++) {
                            char *n2 = strada_to_str(export_arr->elements[export_arr->head + j]);
                            if (n2 && n2[0]) names[name_count++] = n2;
                            else free(n2);
                        }
                    }
                } else if (export_tags) {
                    StradaValue *tag_val = strada_hash_get(export_tags, nm + 1);
                    if (tag_val) {
                        StradaArray *tav = strada_deref_array(tag_val);
                        if (tav) {
                            for (size_t j = 0; j < tav->size; j++) {
                                char *n2 = strada_to_str(tav->elements[tav->head + j]);
                                if (n2 && n2[0]) names[name_count++] = n2;
                                else free(n2);
                            }
                        }
                    }
                }
                free(nm);
            } else {
                names[name_count++] = nm;
            }
        }
    }

    /* Copy each requested symbol, respecting excludes. For bare names or
     * &name, copy the sub slot. Sigil prefixes limit to a single slot. */
    for (size_t i = 0; i < name_count; i++) {
        char *n = names[i];
        if (!n) continue;

        /* Skip if excluded */
        int skip = 0;
        for (size_t j = 0; j < exclude_count; j++) {
            if (excludes[j] && strcmp(n, excludes[j]) == 0) { skip = 1; break; }
        }
        if (skip) continue;

        char sigil = 0;
        const char *bare = n;
        if (n[0] == '&' || n[0] == '$' || n[0] == '@' || n[0] == '%' || n[0] == '*') {
            sigil = n[0];
            bare = n + 1;
        }
        if (!bare[0]) continue;

        PerlGlob *src_glob = perla_glob_get(src_stash, bare);
        if (!src_glob) continue;

        if (sigil == 0 || sigil == '*') {
            /* Copy all slots that exist */
            if (src_glob->slots[PERLA_SLOT_CODE]) perla_code_set(to_pkg, bare, src_glob->slots[PERLA_SLOT_CODE]);
            if (src_glob->slots[PERLA_SLOT_SCALAR]) perla_scalar_set(to_pkg, bare, src_glob->slots[PERLA_SLOT_SCALAR]);
            if (src_glob->slots[PERLA_SLOT_ARRAY]) perla_array_set(to_pkg, bare, src_glob->slots[PERLA_SLOT_ARRAY]);
            if (src_glob->slots[PERLA_SLOT_HASH]) perla_hash_set(to_pkg, bare, src_glob->slots[PERLA_SLOT_HASH]);
        } else if (sigil == '&') {
            if (src_glob->slots[PERLA_SLOT_CODE]) perla_code_set(to_pkg, bare, src_glob->slots[PERLA_SLOT_CODE]);
        } else if (sigil == '$') {
            if (src_glob->slots[PERLA_SLOT_SCALAR]) perla_scalar_set(to_pkg, bare, src_glob->slots[PERLA_SLOT_SCALAR]);
        } else if (sigil == '@') {
            if (src_glob->slots[PERLA_SLOT_ARRAY]) perla_array_set(to_pkg, bare, src_glob->slots[PERLA_SLOT_ARRAY]);
        } else if (sigil == '%') {
            if (src_glob->slots[PERLA_SLOT_HASH]) perla_hash_set(to_pkg, bare, src_glob->slots[PERLA_SLOT_HASH]);
        }
    }

    for (size_t i = 0; i < name_count; i++) if (names[i]) free(names[i]);
    for (size_t i = 0; i < exclude_count; i++) if (excludes[i]) free(excludes[i]);
    free(names);
    free(excludes);
    free(from_pkg);
    return STRADA_MAKE_TAGGED_INT(1);
}

/* Public entry to the Exporter copy logic, callable from generated C.
 * Used by the `use Module qw(...)` codegen to promote the requested
 * names from a module that has no `import` of its own (perla's native
 * builtin shims — Carp, Data::Dumper, etc. — register their subs in
 * their own stash but lack Exporter wiring). args = [MODULE, name...];
 * to_pkg is resolved from perla_use_caller_pkg / the call stack exactly
 * as for the registered Exporter::import. Copies whichever requested
 * names actually exist in the module's stash into the caller — so
 * `defined &main::croak` / `main->can('croak')` work after
 * `use Carp qw(croak)`. */
StradaValue *perla_exporter_import_pub(StradaValue *args) {
    return perla_exporter_import(args);
}

/* DBIC's mk_classdata / mk_classaccessor / mk_group_accessors all
 * install class-level or instance-level accessor methods. CPAN's
 * Class::Accessor::Grouped implements them with a chain of eval
 * STRING + closures + arrayrefs that perla's parser and codegen
 * trip over (the Class::Accessor::Grouped source has parse errors
 * around its accessor-builder templates, so the real subs never
 * get installed in the .pm.o). Provide native equivalents that DBIC
 * downstream code can rely on.
 *
 * Storage: class-data lives in the package's SLOT_SCALAR for the
 * named glob, instance-data in the object hash key. Inherited reads
 * walk @ISA for class-data so a default set on
 * DBIx::Class::ResultSourceProxy::Table propagates to Abe::DB::*. */

static StradaValue *perla_class_data_lookup(const char *pkg, const char *name) {
    PerlStash *stash = perla_stash_get(pkg);
    if (stash) {
        PerlGlob *g = perla_glob_get(stash, name);
        if (g && g->slots[PERLA_SLOT_SCALAR]) {
            StradaValue *v = g->slots[PERLA_SLOT_SCALAR];
            strada_incref(v);
            return v;
        }
        if (stash->isa && stash->isa->value.av) {
            StradaArray *isa = stash->isa->value.av;
            for (size_t i = 0; i < isa->size; i++) {
                StradaValue *psv = isa->elements[isa->head + i];
                if (!psv) continue;
                char *parent = strada_to_str(psv);
                if (parent && parent[0]) {
                    StradaValue *r = perla_class_data_lookup(parent, name);
                    free(parent);
                    if (r && !STRADA_IS_TAGGED_INT(r) && r->type != STRADA_UNDEF) {
                        return r;
                    }
                    if (r) strada_decref(r);
                } else if (parent) {
                    free(parent);
                }
            }
        }
    }
    return strada_new_undef();
}

static StradaValue *perla_mk_classdata(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 2) return strada_new_undef();
    char *class = strada_to_str(av->elements[av->head + 0]);
    char *name = strada_to_str(av->elements[av->head + 1]);
    if (!class || !class[0] || !name || !name[0]) {
        free(class); free(name);
        return strada_new_undef();
    }
    if (av->size >= 3) {
        StradaValue *val = av->elements[av->head + 2];
        if (val) strada_incref(val);
        perla_scalar_set(class, name, val);
    }
    char marker[512];
    snprintf(marker, sizeof(marker), "__class_data__%s", name);
    perla_code_set(class, name, strada_new_str(marker));
    free(class); free(name);
    return STRADA_MAKE_TAGGED_INT(1);
}

/* DBIC's $class->add_relationship_accessor($rel, $acc_type) installs
 * the relationship accessor method. CPAN uses Sub::Quote quote_sub
 * with a body that reads/writes $self->{_relationship_data}{$rel}
 * (single/filter) or builds a related resultset (multi). Perla can't
 * run quote_sub bodies, so we register a marker that the dispatcher
 * routes to: __rel_accessor_<acc_type>__<rel>. The dispatcher reads
 * _relationship_data (for prefetched relations) or falls back to
 * search_related. */
static StradaValue *perla_add_relationship_accessor(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 3) return strada_new_undef();
    char *class = strada_to_str(av->elements[av->head + 0]);
    char *rel = strada_to_str(av->elements[av->head + 1]);
    char *acc_type = strada_to_str(av->elements[av->head + 2]);
    if (!class || !class[0] || !rel || !rel[0] || !acc_type || !acc_type[0]) {
        free(class); free(rel); free(acc_type);
        return strada_new_undef();
    }
    char marker[512];
    snprintf(marker, sizeof(marker), "__rel_accessor_%s__%s", acc_type, rel);
    perla_code_set(class, rel, strada_new_str(marker));
    /* For 'multi' rels, also install ${rel}_rs and add_to_${rel} */
    if (strcmp(acc_type, "multi") == 0) {
        char accname[256], mkname[512];
        snprintf(accname, sizeof(accname), "%s_rs", rel);
        snprintf(mkname, sizeof(mkname), "__rel_accessor_multi_rs__%s", rel);
        perla_code_set(class, accname, strada_new_str(mkname));
        snprintf(accname, sizeof(accname), "add_to_%s", rel);
        snprintf(mkname, sizeof(mkname), "__rel_accessor_multi_add__%s", rel);
        perla_code_set(class, accname, strada_new_str(mkname));
    }
    free(class); free(rel); free(acc_type);
    return STRADA_MAKE_TAGGED_INT(1);
}

/* mk_classaccessor is the singular form of mk_classdata in DBIC. */
static StradaValue *perla_mk_classaccessor(StradaValue *args) {
    return perla_mk_classdata(args);
}

/* set_inherited($class_or_self, $name, $value) and get_inherited
 * — Class::Accessor::Grouped's storage primitives for the
 * 'inherited' accessor group. The CPAN source uses symbolic refs
 * (`${"$class\::__cag_$name"}`) which now work, but the .pm.o's
 * mod_init never gets a chance to run (the stash is already
 * non-empty from our native registrations of mk_*), so the Perl
 * subs are never installed. Native impls thread through DBIC's
 * `mk_classaccessor` → `set_inherited` chain via the package
 * stash's SLOT_SCALAR.
 *
 * On a hash ref, store/read the column directly under $name in
 * the object hash — that matches CPAN's behavior for the
 * "instance call" branch. */
static StradaValue *perla_set_inherited(StradaValue *args) {
    if (getenv("PERLA_SI_DEBUG")) fprintf(stderr, "[si] set_inherited called argc=%zu\n", args ? strada_deref_array(args)->size : 0);
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 3) return strada_new_undef();
    StradaValue *self = av->elements[av->head + 0];
    StradaValue *name_sv = av->elements[av->head + 1];
    StradaValue *val = av->elements[av->head + 2];
    if (!name_sv) return strada_new_undef();
    char *name = strada_to_str(name_sv);
    if (!name || !name[0]) { free(name); return strada_new_undef(); }
    /* Instance call (hash-based object) */
    if (self && !STRADA_IS_TAGGED_INT(self) && self->type == STRADA_REF
        && self->value.rv && !STRADA_IS_TAGGED_INT(self->value.rv)
        && self->value.rv->type == STRADA_HASH) {
        if (val) strada_incref(val);
        strada_hv_store(self->value.rv, name, val);
        free(name);
        return val ? val : strada_new_undef();
    }
    /* Class call: store on the named class's package stash. */
    const char *pkg = perla_blessed(self);
    if (!pkg && self && !STRADA_IS_TAGGED_INT(self)
        && self->type == STRADA_STR && self->value.pv) {
        pkg = self->value.pv;
    }
    if (pkg) {
        if (val) strada_incref(val);
        perla_scalar_set(pkg, name, val);
    }
    free(name);
    if (val) strada_incref(val);
    return val ? val : strada_new_undef();
}

static StradaValue *perla_get_inherited(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 2) return strada_new_undef();
    StradaValue *self = av->elements[av->head + 0];
    StradaValue *name_sv = av->elements[av->head + 1];
    if (!name_sv) return strada_new_undef();
    char *name = strada_to_str(name_sv);
    if (!name || !name[0]) { free(name); return strada_new_undef(); }
    /* Instance call: check the object hash first, then fall back to
     * class data. Mirrors CPAN's get_inherited semantics. */
    if (self && !STRADA_IS_TAGGED_INT(self) && self->type == STRADA_REF
        && self->value.rv && !STRADA_IS_TAGGED_INT(self->value.rv)
        && self->value.rv->type == STRADA_HASH) {
        StradaValue *v = strada_hv_fetch_owned(self->value.rv, name);
        if (v && (STRADA_IS_TAGGED_INT(v) || v->type != STRADA_UNDEF)) {
            free(name);
            return v;
        }
        if (v) strada_decref(v);
    }
    const char *pkg = perla_blessed(self);
    if (!pkg && self && !STRADA_IS_TAGGED_INT(self)
        && self->type == STRADA_STR && self->value.pv) {
        pkg = self->value.pv;
    }
    StradaValue *r = strada_new_undef();
    if (pkg) {
        StradaValue *got = perla_class_data_lookup(pkg, name);
        if (got) {
            strada_decref(r);
            r = got;
        }
    }
    free(name);
    return r;
}

/* mk_group_accessors($class, $group, @fields) — install @fields as
 * accessors. The group name picks the storage shape:
 *   'simple'         → instance-hash slot (Moose-style attr)
 *   'inherited'      → class-data scalar with @ISA walk on read
 *   'component_class' → class-data scalar (same shape as inherited)
 * Other groups fall back to instance-hash semantics, which works for
 * the typical DBIC column accessors. */
static StradaValue *perla_mk_group_accessors(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 2) return strada_new_undef();
    char *class = strada_to_str(av->elements[av->head + 0]);
    if (!class || !class[0]) { free(class); return strada_new_undef(); }
    char *group = av->size >= 2 ? strada_to_str(av->elements[av->head + 1]) : NULL;
    int is_inherited = group && (strcmp(group, "inherited") == 0
                                 || strcmp(group, "component_class") == 0
                                 || strcmp(group, "inherited_ro_instance") == 0);
    /* DBIC's "column" group routes through get_column/set_column rather
     * than direct slot access — values live in $self->{_column_data}{$col},
     * not $self->{$col}. The Moose-style direct-slot accessor was reading
     * the wrong slot, so every DBIC column accessor returned undef even
     * when _column_data was populated. Mark these with a separate prefix
     * the dispatcher can route through get_column / set_column. */
    int is_column = group && strcmp(group, "column") == 0;
    free(group);
    /* args[2..] are field names. Each may be a plain string or an
     * arrayref [$accessor_name, $col_name] (the column-accessor
     * shape DBIC uses for renaming); we honour the [0] slot as the
     * accessor name and [1] as the underlying column name. */
    for (size_t i = 2; i < av->size; i++) {
        StradaValue *fsv = av->elements[av->head + i];
        if (!fsv) continue;
        const char *acc_name = NULL;
        const char *col_name = NULL;
        char *acc_alloc = NULL;
        char *col_alloc = NULL;
        if (!STRADA_IS_TAGGED_INT(fsv) && fsv->type == STRADA_REF
            && fsv->value.rv && fsv->value.rv->type == STRADA_ARRAY) {
            StradaArray *aa = fsv->value.rv->value.av;
            if (aa && aa->size >= 1) {
                acc_alloc = strada_to_str(aa->elements[aa->head + 0]);
                acc_name = acc_alloc;
                if (aa->size >= 2) {
                    col_alloc = strada_to_str(aa->elements[aa->head + 1]);
                    col_name = col_alloc;
                }
            }
        }
        if (!acc_name) {
            acc_alloc = strada_to_str(fsv);
            acc_name = acc_alloc;
        }
        if (!col_name) col_name = acc_name;
        if (!acc_name || !acc_name[0]) { free(acc_alloc); free(col_alloc); continue; }
        char marker[512];
        if (is_inherited) {
            snprintf(marker, sizeof(marker), "__class_data__%s", acc_name);
        } else if (is_column) {
            /* Encode the column name in the marker so the dispatcher can
             * pull it out and call get_column/set_column on the right slot. */
            snprintf(marker, sizeof(marker), "__column_accessor__%s", col_name);
        } else {
            snprintf(marker, sizeof(marker), "__moose_attr__%s", acc_name);
        }
        perla_code_set(class, acc_name, strada_new_str(marker));
        free(acc_alloc);
        free(col_alloc);
    }
    free(class);
    return STRADA_MAKE_TAGGED_INT(1);
}

/* Class::C3::Componentised::ensure_class_loaded($class, $f_class) —
 * "make sure $f_class is require'd". The CPAN source uses a
 * `*{"$f_class\::$_"}{CODE}` glob-slot peek to short-circuit when a
 * sub already exists; perla's parser doesn't accept that idiom yet so
 * the original sub silently fails to compile, and DBIx::Class
 * load_components → ensure_class_loaded chain falls over. Replace
 * with a direct require: if the class isn't already in the stash, run
 * perla_require_module on it. */
static StradaValue *perla_noop_undef(StradaValue *args) {
    (void)args;
    return strada_new_undef();
}

/* Carp::longmess / shortmess / cluck / confess — return a simple
 * "$msg at <unknown> line 0" instead of doing CPAN Carp's full
 * frame walk. The real Carp.pm under perla iterates the call stack
 * and stringifies each frame's args via concat-on-undef; that path
 * hits a NULL StradaValue in strada_concat_sv and segfaults when
 * DBIx::Class::Exception throws inside a deep DBIC component init.
 * For programs that just want the message (which is almost
 * everything calling longmess), the simple form is good enough. */
static StradaValue *perla_carp_msg_only(StradaValue *args) {
    if (!args) return strada_new_str("");
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size == 0) return strada_new_str("");
    StradaValue *msg = av->elements[av->head + 0];
    if (!msg) return strada_new_str("");
    char *m = strada_to_str(msg);
    if (!m) return strada_new_str("");
    char buf[4096];
    snprintf(buf, sizeof(buf), "%s at <unknown> line 0\n", m);
    free(m);
    return strada_new_str(buf);
}

/* Carp::longmess — multi-line stack trace from perla_call_stack. This
 * is the heavy form: $msg + one "called at" frame per caller. Safe
 * against NULL frames (the issue that motivated msg-only). */

/* Smartmatch (`~~`) — common-case Perl smartmatch. Returns perl-style
 * true (tagged int 1) / false (empty string) for use in boolean and
 * print contexts. See header comment for the cases handled. */
static int perla_smartmatch_str_eq(StradaValue *a, StradaValue *b) {
    char *as = strada_to_str(a);
    char *bs = strada_to_str(b);
    int r = (as && bs && strcmp(as, bs) == 0) ? 1 : 0;
    free(as); free(bs);
    return r;
}

static int perla_smartmatch_num_eq(StradaValue *a, StradaValue *b) {
    double an = strada_to_num(a);
    double bn = strada_to_num(b);
    return an == bn ? 1 : 0;
}

StradaValue *perla_smartmatch(StradaValue *lhs, StradaValue *rhs) {
    int matched = 0;

    /* RHS undef → !defined(LHS). */
    if (!rhs || (!STRADA_IS_TAGGED_INT(rhs) && rhs->type == STRADA_UNDEF)) {
        matched = (!lhs || (!STRADA_IS_TAGGED_INT(lhs) && lhs->type == STRADA_UNDEF)) ? 1 : 0;
        goto done;
    }

    /* RHS code → coerce LHS into a single-arg call and use its truth. */
    if (!STRADA_IS_TAGGED_INT(rhs)
        && (rhs->type == STRADA_CLOSURE || rhs->type == STRADA_CPOINTER
            || (rhs->type == STRADA_REF && rhs->value.rv
                && !STRADA_IS_TAGGED_INT(rhs->value.rv)
                && (rhs->value.rv->type == STRADA_CLOSURE
                    || rhs->value.rv->type == STRADA_CPOINTER)))) {
        StradaValue *cv = rhs;
        if (rhs->type == STRADA_REF) cv = rhs->value.rv;
        StradaValue *argv = strada_new_array();
        /* strada_array_push increfs internally — pushing lhs gives av a
         * fresh ref, leaving caller's lhs ownership untouched. Adding an
         * explicit incref here leaks lhs by one refcount per call. */
        if (lhs) {
            strada_array_push(strada_deref_array(argv), lhs);
        }
        StradaValue *rv = perla_call_code(cv, argv);
        strada_decref(argv);
        if (rv) {
            matched = strada_to_bool(rv) ? 1 : 0;
            strada_decref(rv);
        }
        goto done;
    }

    /* Unwrap RHS ref to inspect underlying container. */
    StradaValue *rhs_inner = rhs;
    if (!STRADA_IS_TAGGED_INT(rhs) && rhs->type == STRADA_REF && rhs->value.rv) {
        rhs_inner = rhs->value.rv;
    }

    /* RHS regex →  LHS =~ /pat/. Perla stores qr// as a STRADA_STR blessed
     * "Regexp" (see CodeGen.strada N_REGEX is_qr branch) and the legacy
     * STRADA_REGEX form holds the pattern in value.pv. Handle both. */
    {
        const char *pat = NULL;
        if (!STRADA_IS_TAGGED_INT(rhs_inner) && rhs_inner->type == STRADA_REGEX) {
            pat = rhs_inner->value.pv;
        } else if (!STRADA_IS_TAGGED_INT(rhs_inner) && rhs_inner->type == STRADA_STR
                   && rhs_inner->meta && rhs_inner->meta->blessed_package
                   && strcmp(rhs_inner->meta->blessed_package, "Regexp") == 0) {
            pat = rhs_inner->value.pv;
        }
        if (pat) {
            char *ls = strada_to_str(lhs);
            if (ls) matched = strada_regex_match(ls, pat) ? 1 : 0;
            free(ls);
            goto done;
        }
    }

    /* RHS array → grep equality. Use numeric eq if LHS is numeric, else string. */
    if (!STRADA_IS_TAGGED_INT(rhs_inner) && rhs_inner->type == STRADA_ARRAY && rhs_inner->value.av) {
        StradaArray *av = rhs_inner->value.av;
        int lhs_num = STRADA_IS_TAGGED_INT(lhs)
                    || (lhs && (lhs->type == STRADA_INT || lhs->type == STRADA_NUM));
        for (size_t i = 0; i < av->size; i++) {
            StradaValue *el = av->elements[av->head + i];
            int eq;
            if (lhs_num) eq = perla_smartmatch_num_eq(lhs, el);
            else eq = perla_smartmatch_str_eq(lhs, el);
            if (eq) { matched = 1; break; }
        }
        goto done;
    }

    /* RHS hash → exists(LHS-as-key). */
    if (!STRADA_IS_TAGGED_INT(rhs_inner) && rhs_inner->type == STRADA_HASH && rhs_inner->value.hv) {
        char *ks = strada_to_str(lhs);
        if (ks) {
            matched = strada_hash_exists(rhs_inner->value.hv, ks) ? 1 : 0;
            free(ks);
        }
        goto done;
    }

    /* Fallback: stringy equality (or numeric if both sides look numeric). */
    int lnum = STRADA_IS_TAGGED_INT(lhs)
             || (lhs && !STRADA_IS_TAGGED_INT(lhs) && (lhs->type == STRADA_INT || lhs->type == STRADA_NUM));
    int rnum = STRADA_IS_TAGGED_INT(rhs)
             || (rhs && !STRADA_IS_TAGGED_INT(rhs) && (rhs->type == STRADA_INT || rhs->type == STRADA_NUM));
    matched = (lnum || rnum) ? perla_smartmatch_num_eq(lhs, rhs) : perla_smartmatch_str_eq(lhs, rhs);

done:
    return matched ? STRADA_MAKE_TAGGED_INT(1) : strada_new_str("");
}

StradaValue *perla_carp_longmess(StradaValue *args) {
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    char *m = NULL;
    if (av && av->size > 0) {
        StradaValue *msg = av->elements[av->head + 0];
        if (msg) m = strada_to_str(msg);
    }
    if (!m) m = strdup("");

    size_t cap = 1024, len = 0;
    char *out = (char *)malloc(cap);
    if (!out) { free(m); return strada_new_str(""); }
    out[0] = '\0';

    /* First line: "$msg at FILE line N." for the immediate caller. */
    const char *file0 = "<unknown>";
    int line0 = 0;
    if (perla_call_depth >= 1) {
        const char *f = perla_call_stack[perla_call_depth - 1].file;
        if (f && f[0]) file0 = f;
        line0 = perla_call_stack[perla_call_depth - 1].line;
    }
    int n = snprintf(out + len, cap - len, "%s at %s line %d.\n", m, file0, line0);
    if (n > 0) len += (size_t)n;

    /* Then "\tPKG::SUB() called at FILE line N." for each caller above. */
    for (int i = perla_call_depth - 2; i >= 0; i--) {
        const char *pkg  = perla_call_stack[i].package ? perla_call_stack[i].package : "main";
        const char *sub  = perla_call_stack[i].subname ? perla_call_stack[i].subname : "__ANON__";
        /* Fold perla's internal anon name to Perl's "__ANON__". */
        if (strncmp(sub, "__perla_anon_", 13) == 0) { sub = "__ANON__"; }
        /* The "called at" file/line is the location of the call,
         * which is recorded one frame *above* (the next-deeper frame's
         * file/line — but we don't fully model that here; use this
         * frame's file/line as an approximation). */
        const char *file = perla_call_stack[i].file ? perla_call_stack[i].file : "<unknown>";
        int line = perla_call_stack[i].line;
        if (cap - len < 512) {
            cap *= 2;
            char *nb = (char *)realloc(out, cap);
            if (!nb) break;
            out = nb;
        }
        /* Synthetic eval-block frame: print as "eval {...} called at ..."
         * with no PKG:: prefix (matches perl's Carp output). */
        if (sub && strcmp(sub, "(eval)") == 0) {
            n = snprintf(out + len, cap - len, "\teval {...} called at %s line %d.\n",
                         file, line);
        } else {
            n = snprintf(out + len, cap - len, "\t%s::%s() called at %s line %d.\n",
                         pkg, sub, file, line);
        }
        if (n > 0) len += (size_t)n;
    }
    free(m);
    StradaValue *r = strada_new_str(out);
    free(out);
    return r;
}

/* croak / confess — die() with a Carp-style message (caller location +
 * the caller chain, built by perla_carp_longmess). Registered as real
 * Carp subs so introspection (`defined &main::croak` after import,
 * `Carp->can('croak')`) and indirect/method calls (`\&croak->(...)`,
 * `$obj->croak`) work. Direct `croak(...)` calls still use the richer
 * inline codegen in CodeGen.strada — the inline path fires on the
 * bareword name regardless of whether this sub exists, so it is
 * unaffected. perla's Carp blames the immediate caller; a CPOINTER sub
 * pushes no call frame, so perla_call_stack's top IS the caller and
 * longmess reports the right location. Message ownership is transferred
 * to perla_eval_error ($@) before the throw (mirrors the inline path) so
 * it survives the longjmp and `$@` is set for eval. */
StradaValue *perla_carp_croak(StradaValue *args) {
    extern StradaValue *perla_eval_error;
    StradaValue *msg = perla_carp_longmess(args);
    if (perla_eval_error) strada_decref(perla_eval_error);
    perla_eval_error = msg;                /* $@ owns it */
    strada_die_sv(msg);                    /* throw (in eval) / print+exit */
    return strada_new_undef();             /* unreachable */
}

/* carp / cluck — warn() flavor (to STDERR), no die. Both emit the
 * caller-chain message; perl's carp is the immediate-caller short form
 * and cluck the full trace, but for the rare indirect path the trace is
 * acceptable and informative. */
StradaValue *perla_carp_carp(StradaValue *args) {
    StradaValue *msg = perla_carp_longmess(args);
    char *s = strada_to_str(msg);
    if (s) { fputs(s, stderr); free(s); }
    strada_decref(msg);
    return STRADA_MAKE_TAGGED_INT(1);
}

static StradaValue *perla_ensure_class_loaded(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 2) return strada_new_undef();
    StradaValue *fclass_sv = av->elements[av->head + 1];
    if (!fclass_sv) return strada_new_undef();
    char *fclass = strada_to_str(fclass_sv);
    if (!fclass || !fclass[0]) { free(fclass); return strada_new_undef(); }
    /* Already populated? */
    PerlStash *st = perla_stash_get(fclass);
    if (st && st->count > 0) { free(fclass); return strada_new_undef(); }
    /* Otherwise, require it. Failures here are non-fatal for our
     * purposes — the caller (load_components / similar) will surface
     * its own error if the class is genuinely missing. */
    StradaValue *mn = strada_new_str(fclass);
    StradaValue *r = perla_require_module(mn);
    if (r) strada_decref(r);
    strada_decref(mn);
    free(fclass);
    return strada_new_undef();
}

/* Class::C3::Componentised::inject_base($class, $target, @to_inject) —
 * unshift each component (in reverse order) onto @{$target::ISA}.
 * The CPAN source uses symbolic refs (`unshift @{"${target}::ISA"}, $to`)
 * that perla's codegen doesn't fully support for @ISA mutation, so the
 * inject silently no-ops. Without this, every load_components chain
 * (DBIx::Class::Core pulling in Row / ResultSourceProxy::Table /
 * Relationship / …) leaves the table classes' @ISA empty — Abe::DB::*
 * inherit nothing and `$class->table(...)`, `$class->add_columns(...)`,
 * `$class->result_source_instance` all miss. */
static StradaValue *perla_inject_base(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    /* args = ($invocant_class, $target, @to_inject) — at least 3 elements. */
    if (!av || av->size < 3) return strada_new_undef();
    StradaValue *target_sv = av->elements[av->head + 1];
    if (!target_sv) return strada_new_undef();
    char *target = strada_to_str(target_sv);
    if (!target || !target[0]) { free(target); return strada_new_undef(); }

    /* Walk to_inject in reverse so the first listed component ends up
     * earliest in @ISA after the unshifts (matches Class::C3::
     * Componentised::inject_base behavior). */
    for (size_t i = av->size; i > 2; i--) {
        StradaValue *cv = av->elements[av->head + (i - 1)];
        if (!cv) continue;
        char *comp = strada_to_str(cv);
        if (!comp || !comp[0]) { free(comp); continue; }
        if (strcmp(target, comp) == 0) { free(comp); continue; }

        /* Skip if already present in target's @ISA. */
        int already = 0;
        PerlStash *tst = perla_stash_get(target);
        if (tst && tst->isa) {
            StradaArray *isa_av = tst->isa->value.av;
            if (isa_av) {
                for (size_t j = 0; j < isa_av->size; j++) {
                    StradaValue *ev = isa_av->elements[isa_av->head + j];
                    if (!ev) continue;
                    char *es = strada_to_str(ev);
                    if (es && strcmp(es, comp) == 0) already = 1;
                    free(es);
                    if (already) break;
                }
            }
        }
        if (already) { free(comp); continue; }

        /* Unshift onto @{target::ISA}. perla_isa_push appends — emulate
         * unshift by saving existing entries, clearing, pushing comp,
         * then re-pushing the saved entries. Cheap given typical ISA
         * arrays are short (<10 entries). */
        PerlStash *st = perla_stash_get_or_create(target);
        StradaValue *new_isa = strada_new_array();
        StradaArray *new_av = strada_deref_array(new_isa);
        StradaValue *comp_sv = strada_new_str(comp);
        strada_array_push_take(new_av, comp_sv);
        if (st->isa) {
            StradaArray *old_av = st->isa->value.av;
            if (old_av) {
                for (size_t j = 0; j < old_av->size; j++) {
                    StradaValue *ov = old_av->elements[old_av->head + j];
                    if (ov) { strada_incref(ov); strada_array_push_take(new_av, ov); }
                }
            }
            strada_decref(st->isa);
        }
        st->isa = new_isa;
        /* Sync the ISA glob slot so @Pkg::ISA reads see the new array. */
        PerlGlob *g = perla_glob_get_or_create(st, "ISA");
        if (g->slots[PERLA_SLOT_ARRAY]) strada_decref(g->slots[PERLA_SLOT_ARRAY]);
        g->slots[PERLA_SLOT_ARRAY] = st->isa;
        strada_incref(st->isa);

        free(comp);
    }

    free(target);
    return strada_new_undef();
}

/* Exporter::export_to_level — strips the (level, undef) slots and
 * delegates to perla_exporter_import. Real Perl threads the level
 * through caller(N) to pick the target frame; perla_exporter_import's
 * existing depth-1/depth-2 heuristic catches the common
 * `MyPkg::import { MyPkg->export_to_level(1, $class, @_) }` pattern,
 * which is what Drogo::Dispatch and most CPAN modules using
 * export_to_level actually do. */

/* Exporter-style copy with explicit caller-pkg override. Codegen for
 * `use Module qw(...)` calls this with the inlining-package as to_pkg
 * to ensure imports go to the right package regardless of runtime
 * call-stack ordering. Always called with the from-package and
 * (optional) name list. With names_count==0, default-import @EXPORT.
 *
 * Why this helper exists: Abe::App.pm's `use YAML;` was supposed to
 * import Load/Dump into Abe::App::, but at .pm.so init time the
 * call_stack walk in perla_exporter_import didn't always identify the
 * correct caller package. Result: Abe::App::Load was undefined,
 * Abe::App::config returned undef, DBI got bad creds, drogo-exit fired,
 * app=UNDEF. By passing to_pkg explicitly here we bypass that ambiguity. */
StradaValue *perla_import_to_pkg(const char *to_pkg, const char *from_pkg,
                                   const char *const *names, int names_count) {
    if (!to_pkg || !from_pkg) return strada_new_undef();
    const char *saved = perla_use_caller_pkg;
    perla_use_caller_pkg = to_pkg;
    StradaValue *args = strada_new_array();
    StradaArray *aav = strada_deref_array(args);
    strada_array_push_take(aav, strada_new_str(from_pkg));
    for (int i = 0; i < names_count; i++) {
        strada_array_push_take(aav, strada_new_str(names[i]));
    }
    StradaValue *result = perla_exporter_import(args);
    strada_decref(args);
    perla_use_caller_pkg = saved;
    return result;
}

/* Exporter::export($pkg, $callpkg, @list) — the lower-level cousin of
 * Exporter::import. Some CPAN modules (Time::Piece does this in its
 * import sub) call $class->Exporter::export($caller, @list) directly
 * rather than going through Exporter::import. Without this binding,
 * the SUPER-chain walk fails with "Can't locate object method 'export'
 * via package 'X'".
 *
 * Args: [exporter_pkg, callpkg, @symbols].
 * Behavior: copy each symbol from exporter_pkg into callpkg, same as
 * import's body but with the caller package passed explicitly rather
 * than read from the call stack. */
static StradaValue *perla_exporter_export(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 2) return strada_new_undef();

    /* Repack as [pkg, @symbols] and set perla_use_caller_pkg to the
     * provided callpkg so the import body's "find target package" walk
     * picks the right one. */
    char *callpkg = strada_to_str(av->elements[av->head + 1]);
    const char *saved = perla_use_caller_pkg;
    perla_use_caller_pkg = callpkg;

    StradaValue *new_args = strada_new_array();
    StradaArray *nav = strada_deref_array(new_args);
    StradaValue *pkg_arg = av->elements[av->head + 0];
    if (pkg_arg) strada_incref(pkg_arg);
    strada_array_push_take(nav, pkg_arg);
    for (size_t i = 2; i < av->size; i++) {
        StradaValue *v = av->elements[av->head + i];
        if (v) strada_incref(v);
        strada_array_push_take(nav, v);
    }
    StradaValue *r = perla_exporter_import(new_args);
    strada_decref(new_args);
    perla_use_caller_pkg = saved;
    if (callpkg) free(callpkg);
    return r;
}

static StradaValue *perla_exporter_export_to_level(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_undef();

    StradaValue *new_args = strada_new_array();
    StradaArray *nav = strada_deref_array(new_args);
    /* args[0] = pkg → keep */
    StradaValue *pkg_arg = av->elements[av->head + 0];
    if (pkg_arg) strada_incref(pkg_arg);
    strada_array_push_take(nav, pkg_arg);
    /* args[1] = level (skip), args[2] = undef placeholder (skip) */
    /* args[3..] = symbol list → keep */
    for (size_t i = 3; i < av->size; i++) {
        StradaValue *v = av->elements[av->head + i];
        if (v) strada_incref(v);
        strada_array_push_take(nav, v);
    }
    StradaValue *r = perla_exporter_import(new_args);
    strada_decref(new_args);
    return r;
}

/* Assign a value to a dereferenced scalar reference: `$$ref = val`.
 * Decrefs the current target, increfs and installs `val`. No-op for
 * non-refs (tagged ints, strings used as symbolic refs, undef, etc.) —
 * the codegen will have already emitted this on real ref shapes. */
void perla_scalar_deref_assign(StradaValue *ref, StradaValue *val) {
    if (!ref || STRADA_IS_TAGGED_INT(ref)) return;
    if (ref->type == STRADA_REF) {
        /* Slot refs (\$var, \$arr[i]) point to a StradaValue** slot
         * that is the variable's actual storage. Replace the slot
         * pointer rather than mutating the (potentially-shared)
         * value behind ->value.rv. Without this, compound-assigns
         * through slot refs (\$arr[i] *= 2 via $$ref) treat the
         * slot address as a StradaValue and segfault. */
        if (strada_is_slot_ref(ref)) {
            StradaValue **slot = (StradaValue **)ref->value.ptr;
            if (!slot) return;
            StradaValue *old = *slot;
            if (val) strada_incref(val);
            *slot = val;
            if (old) strada_decref(old);
            /* If this slot is a registered \$Pkg::var stash slot, sync
             * the file-static local mirror so subs in pkg that read
             * v_x directly see the new value. */
            extern StradaValue **perla_find_local_by_stash_slot(StradaValue **);
            StradaValue **local = perla_find_local_by_stash_slot(slot);
            if (local && local != slot) {
                StradaValue *old_local = *local;
                if (val) strada_incref(val);
                *local = val;
                if (old_local) strada_decref(old_local);
            }
            return;
        }
        /* Heap refs (\$h->{k}, \(expr)): mutate the target value in
         * place so all aliases (hash entries, array slots holding the
         * same StradaValue) see the new value. The old code replaced
         * ref->value.rv — which leaves the hash entry pointing at the
         * old value. strada_overwrite_in_place keeps the pointer
         * stable and changes only the content. */
        if (ref->value.rv) {
            strada_overwrite_in_place(ref->value.rv, val);
            return;
        }
        /* Fallback: no target yet — store val and refcount. */
        if (val) strada_incref(val);
        ref->value.rv = val;
    }
}

/* ===== Getopt::Long (native, common subset) =====
 *
 * The real Getopt::Long.pm is large and doesn't run under perla, so
 * GetOptions was undefined. This native covers the overwhelmingly-common
 * feature set:
 *   - linkage mode:   GetOptions('name=s' => \$x, 'flag' => \$f, ...)
 *   - hashref mode:   GetOptions(\%opts, 'name=s', 'flag', ...)
 *   - GetOptionsFromArray(\@args, <either form>)
 *   - types: =s =i =f (and :s :i optional-arg), plain flag, ! (negatable),
 *     + (incremental); destinations @ (array) and % (hash)
 *   - aliases via |, e.g. 'verbose|v'
 *   - forms: --opt, --opt=val, --opt val, -o, -o val, -oVAL, --no-opt, --
 * Unknown options warn to STDERR and make the call return 0 (false), but
 * processing continues; non-option args are left in the parsed array
 * (permute, the Getopt::Long default). */
typedef struct {
    char prim[64];
    char alias[8][48];
    int  nalias;
    int  type;       /* 's','i','f' take a value; 'b' plain flag; 'n' negatable(!); '+' incr */
    int  optional;   /* ':' — value optional */
    int  dest;       /* 0 scalar, '@' array, '%' hash */
    StradaValue *ref;/* linkage ref, or NULL in hashref mode */
} GoSpec;

static int go_parse_spec(const char *str, GoSpec *out) {
    memset(out, 0, sizeof(*out));
    out->type = 'b';
    char buf[256];
    strncpy(buf, str ? str : "", sizeof(buf) - 1);
    buf[sizeof(buf) - 1] = 0;
    size_t L = strlen(buf);
    if (L > 0 && (buf[L-1] == '@' || buf[L-1] == '%')) { out->dest = buf[L-1]; buf[--L] = 0; }
    char *eq = strpbrk(buf, "=:");
    if (eq) {
        out->optional = (*eq == ':');
        char t = eq[1];
        out->type = (t == 'i' || t == 'f' || t == 'o' || t == 's') ? (t == 'o' ? 'f' : t) : 's';
        *eq = 0; L = strlen(buf);
    } else if (L > 0 && buf[L-1] == '!') { out->type = 'n'; buf[--L] = 0; }
    else if (L > 0 && buf[L-1] == '+') { out->type = '+'; buf[--L] = 0; }
    /* split names on | */
    char *save = NULL;
    char *tok = strtok_r(buf, "|", &save);
    int first = 1;
    while (tok) {
        if (first) { strncpy(out->prim, tok, sizeof(out->prim) - 1); first = 0; }
        else if (out->nalias < 8) { strncpy(out->alias[out->nalias], tok, 47); out->nalias++; }
        tok = strtok_r(NULL, "|", &save);
    }
    return out->prim[0] != 0;
}

static int go_spec_matches(const GoSpec *s, const char *opt) {
    if (strcmp(s->prim, opt) == 0) return 1;
    for (int i = 0; i < s->nalias; i++) if (strcmp(s->alias[i], opt) == 0) return 1;
    return 0;
}

static StradaValue *go_make_val(int type, const char *s) {
    if (type == 'i') return strada_new_int((int64_t)strtoll(s ? s : "0", NULL, 10));
    if (type == 'f') return strada_new_num(strtod(s ? s : "0", NULL));
    return strada_new_str(s ? s : "");
}

/* Resolve the underlying container (ARRAY/HASH) a linkage ref points at,
 * handling slot refs (\@arr / \%h point at the variable's StradaValue**
 * storage, not ->value.rv). */
static StradaValue *go_resolve_container(StradaValue *ref) {
    if (!ref || STRADA_IS_TAGGED_INT(ref)) return NULL;
    if (ref->type == STRADA_REF) {
        if (strada_is_slot_ref(ref)) {
            StradaValue **slot = (StradaValue **)ref->value.ptr;
            return slot ? *slot : NULL;
        }
        return ref->value.rv;
    }
    return ref;
}

/* Store one parsed value (owned, this fn consumes it) into a spec's dest. */
static void go_store(GoSpec *s, StradaValue *dest_hash, StradaValue *val) {
    if (s->dest == '%') {
        /* val is "key=value"; split and store sub-key */
        char *raw = strada_to_str(val);
        strada_decref(val);
        char *kvp = raw ? raw : (char*)"";
        char *eqp = strchr(kvp, '=');
        char *k = kvp; char *v = (char*)"1";
        if (eqp) { *eqp = 0; v = eqp + 1; }
        StradaValue *container;
        if (s->ref) container = go_resolve_container(s->ref);
        else {
            container = strada_hash_get(dest_hash->value.hv, s->prim);
            if (!container || STRADA_IS_TAGGED_INT(container) || container->type != STRADA_REF) {
                container = strada_new_ref_take(strada_new_hash(), '%');
                strada_hash_set_take(dest_hash->value.hv, s->prim, container);
            }
            container = container->value.rv;
        }
        if (container && !STRADA_IS_TAGGED_INT(container) && container->type == STRADA_HASH)
            strada_hash_set_take(container->value.hv, k, go_make_val(s->type, v));
        if (raw) free(raw);
        return;
    }
    if (s->dest == '@') {
        StradaValue *arr;
        if (s->ref) arr = go_resolve_container(s->ref);
        else {
            StradaValue *cur = strada_hash_get(dest_hash->value.hv, s->prim);
            if (!cur || STRADA_IS_TAGGED_INT(cur) || cur->type != STRADA_REF) {
                cur = strada_new_ref_take(strada_new_array(), '@');
                strada_hash_set_take(dest_hash->value.hv, s->prim, cur);
            }
            arr = cur->value.rv;
        }
        if (arr && !STRADA_IS_TAGGED_INT(arr) && arr->type == STRADA_ARRAY)
            strada_array_push_take(strada_deref_array(arr), val);
        else strada_decref(val);
        return;
    }
    /* scalar destination */
    if (s->ref) { perla_scalar_deref_assign(s->ref, val); strada_decref(val); }
    else strada_hash_set_take(dest_hash->value.hv, s->prim, val);
}

/* Read the current scalar value of a spec's dest (for ++ / increment). */
static int64_t go_current_int(GoSpec *s, StradaValue *dest_hash) {
    StradaValue *cur = NULL;
    if (s->ref && s->ref->type == STRADA_REF) cur = s->ref->value.rv;
    else if (!s->ref) cur = strada_hash_get(dest_hash->value.hv, s->prim);
    return cur ? strada_to_int(cur) : 0;
}

/* Core driver. specs come from args[spec_start..]; in hashref mode
 * dest_hash is args[spec_start] and specs start at spec_start+1. Returns
 * tagged-int 1 (success) / 0 (an unknown option was seen). */
static StradaValue *go_run(StradaArray *args, int spec_start, StradaArray *parse) {
    if (!args || !parse) return STRADA_MAKE_TAGGED_INT(1);
    StradaValue *dest_hash = NULL;
    int i = spec_start;
    StradaValue *a0 = (int)strada_array_length(args) > spec_start
                      ? strada_array_get(args, spec_start) : NULL;
    if (a0 && !STRADA_IS_TAGGED_INT(a0) && a0->type == STRADA_REF
        && a0->value.rv && a0->value.rv->type == STRADA_HASH) {
        dest_hash = a0->value.rv;
        i = spec_start + 1;
    }
    /* build spec table */
    int cap = 32, n = 0;
    GoSpec *specs = (GoSpec*)calloc(cap, sizeof(GoSpec));
    int alen = (int)strada_array_length(args);
    while (i < alen) {
        StradaValue *sp = strada_array_get(args, i);
        char *ss = sp ? strada_to_str(sp) : NULL;
        if (n >= cap) { cap *= 2; specs = (GoSpec*)realloc(specs, cap * sizeof(GoSpec)); }
        if (ss && go_parse_spec(ss, &specs[n])) {
            if (!dest_hash) {
                /* linkage mode: next arg is the destination ref */
                if (i + 1 < alen) { specs[n].ref = strada_array_get(args, i + 1); i++; }
                /* Perl derives @/% accumulation from the DESTINATION ref's
                 * type, not just a spec '@'/'%' suffix: `'I=s' => \@inc`
                 * accumulates. Promote dest from the linkage container. */
                if (specs[n].dest == 0 && specs[n].ref) {
                    StradaValue *c = go_resolve_container(specs[n].ref);
                    if (c && !STRADA_IS_TAGGED_INT(c)) {
                        if (c->type == STRADA_ARRAY) specs[n].dest = '@';
                        else if (c->type == STRADA_HASH) specs[n].dest = '%';
                    }
                }
            }
            n++;
        }
        if (ss) free(ss);
        i++;
    }
    /* walk the parse array */
    int ret = 1;
    int plen = (int)strada_array_length(parse);
    StradaValue *leftover = strada_new_array();
    StradaArray *lav = strada_deref_array(leftover);
    int pi = 0, options_done = 0;
    while (pi < plen) {
        StradaValue *tokv = strada_array_get(parse, pi);
        char *tok = tokv ? strada_to_str(tokv) : NULL;
        if (!tok) { pi++; continue; }
        if (options_done || tok[0] != '-' || tok[1] == 0) {
            if (tokv) { strada_incref(tokv); strada_array_push_take(lav, tokv); }
            free(tok); pi++; continue;
        }
        if (strcmp(tok, "--") == 0) { options_done = 1; free(tok); pi++; continue; }
        /* strip leading dashes (treat - and -- the same for name lookup) */
        const char *body = tok + 1;
        if (body[0] == '-') body++;
        /* split inline =value */
        char namebuf[256]; const char *inlineval = NULL;
        const char *eqp = strchr(body, '=');
        if (eqp) {
            size_t nl = (size_t)(eqp - body);
            if (nl >= sizeof(namebuf)) nl = sizeof(namebuf) - 1;
            memcpy(namebuf, body, nl); namebuf[nl] = 0;
            inlineval = eqp + 1;
        } else {
            strncpy(namebuf, body, sizeof(namebuf) - 1); namebuf[sizeof(namebuf) - 1] = 0;
        }
        /* negation: --no-foo / --nofoo */
        int negated = 0;
        char *lookup = namebuf;
        /* find a matching spec; try the literal name first, then negated form */
        GoSpec *match = NULL;
        for (int k = 0; k < n; k++) if (go_spec_matches(&specs[k], lookup)) { match = &specs[k]; break; }
        if (!match && (strncmp(namebuf, "no-", 3) == 0 || strncmp(namebuf, "no", 2) == 0)) {
            const char *stripped = (strncmp(namebuf, "no-", 3) == 0) ? namebuf + 3 : namebuf + 2;
            for (int k = 0; k < n; k++) {
                if (specs[k].type == 'n' && go_spec_matches(&specs[k], stripped)) { match = &specs[k]; negated = 1; break; }
            }
        }
        /* short attached value: -xVALUE where x is a single-letter value opt */
        if (!match && !inlineval && strlen(namebuf) > 1) {
            char single[2] = { namebuf[0], 0 };
            for (int k = 0; k < n; k++) {
                if (go_spec_matches(&specs[k], single)
                    && (specs[k].type == 's' || specs[k].type == 'i' || specs[k].type == 'f')) {
                    match = &specs[k]; inlineval = body + 1; break;
                }
            }
        }
        if (!match) {
            fprintf(stderr, "Unknown option: %s\n", namebuf);
            ret = 0; free(tok); pi++; continue;
        }
        if (match->type == 'b' || match->type == 'n') {
            go_store(match, dest_hash, strada_new_int(negated ? 0 : 1));
        } else if (match->type == '+') {
            go_store(match, dest_hash, strada_new_int(go_current_int(match, dest_hash) + 1));
        } else {
            /* value option */
            const char *valstr = inlineval;
            char *consumed_val = NULL;
            if (!valstr) {
                if (pi + 1 < plen) {
                    StradaValue *nx = strada_array_get(parse, pi + 1);
                    char *ns = nx ? strada_to_str(nx) : NULL;
                    int looks_opt = ns && ns[0] == '-' && ns[1] != 0
                                    && !(ns[1] >= '0' && ns[1] <= '9');
                    if (ns && (!match->optional || !looks_opt)) {
                        valstr = consumed_val = ns; pi++;
                    } else if (ns) { free(ns); }
                }
            }
            if (!valstr) valstr = match->optional ? (match->type == 's' ? "" : "0") : "";
            go_store(match, dest_hash, go_make_val(match->type, valstr));
            if (consumed_val) free(consumed_val);
        }
        free(tok); pi++;
    }
    /* replace the parsed array contents with the leftovers (permute) */
    while (strada_array_length(parse) > 0) {
        StradaValue *e = strada_array_pop(parse);
        if (e) strada_decref(e);
    }
    int llen = (int)strada_array_length(lav);
    for (int k = 0; k < llen; k++) {
        StradaValue *e = strada_array_get(lav, k);
        if (e) { strada_incref(e); strada_array_push_take(parse, e); }
    }
    strada_decref(leftover);
    free(specs);
    return STRADA_MAKE_TAGGED_INT(ret);
}

/* ===== Text::Wrap (native) =====
 * Faithful port of Text::Wrap::wrap/fill + Text::Tabs::expand/unexpand for
 * the common (largely ASCII) case. The real .pm doesn't run under perla.
 * Honors $Text::Wrap::{columns,tabstop,unexpand,huge,separator}. */
static size_t tw_glen(const char *s, size_t i, size_t n) {
    if (i >= n) return 0;
    unsigned char c = (unsigned char)s[i];
    size_t l = (c >= 0xF0) ? 4 : (c >= 0xE0) ? 3 : (c >= 0xC0) ? 2 : 1;
    if (i + l > n) l = n - i;
    return l ? l : 1;
}
static size_t tw_xlen(const char *s, size_t n) {
    size_t c = 0;
    for (size_t i = 0; i < n; i++) if (((unsigned char)s[i] & 0xC0) != 0x80) c++;
    return c;
}
static char *tw_expand(const char *s, size_t n, int ts) {
    if (ts < 1) ts = 8;
    size_t cap = n + 16, out = 0;
    char *r = (char*)malloc(cap);
    size_t col = 0;
    for (size_t i = 0; i < n; ) {
        char c = s[i];
        if (c == '\t') {
            int pad = ts - (int)(col % ts);
            if (pad <= 0) pad = ts;
            while (out + (size_t)pad + 1 > cap) { cap = cap * 2 + pad; r = (char*)realloc(r, cap); }
            for (int k = 0; k < pad; k++) r[out++] = ' ';
            col += (size_t)pad; i++;
        } else if (c == '\n') {
            if (out + 2 > cap) { cap *= 2; r = (char*)realloc(r, cap); }
            r[out++] = '\n'; col = 0; i++;
        } else {
            size_t gl = tw_glen(s, i, n);
            while (out + gl + 1 > cap) { cap = cap * 2 + gl; r = (char*)realloc(r, cap); }
            memcpy(r + out, s + i, gl); out += gl; i += gl; col++;
        }
    }
    r[out] = 0;
    return r;
}
/* unexpand a single line (no embedded \n); out must hold >= strlen(line)+1 */
static void tw_unexpand_line(const char *line, int ts, char *out) {
    if (ts < 1) ts = 8;
    size_t n = strlen(line), i = 0, o = 0;
    while (i < n) {
        size_t bstart = i, g = 0;
        while (g < (size_t)ts && i < n) { i += tw_glen(line, i, n); g++; }
        size_t bend = i;
        if (g == (size_t)ts) {
            size_t te = bend, sp = 0;
            while (te > bstart && line[te-1] == ' ') { te--; sp++; }
            if (sp >= 2) { memcpy(out + o, line + bstart, te - bstart); o += te - bstart; out[o++] = '\t'; }
            else { memcpy(out + o, line + bstart, bend - bstart); o += bend - bstart; }
        } else { memcpy(out + o, line + bstart, bend - bstart); o += bend - bstart; }
    }
    out[o] = 0;
}
static int tw_cfg_int(const char *name, int dflt) {
    StradaValue *v = perla_scalar_get("Text::Wrap", name);
    if (!v || (!STRADA_IS_TAGGED_INT(v) && v->type == STRADA_UNDEF)) return dflt;
    return (int)strada_to_int(v);
}
static char *tw_cfg_str(const char *name, const char *dflt) {
    StradaValue *v = perla_scalar_get("Text::Wrap", name);
    if (!v || (!STRADA_IS_TAGGED_INT(v) && v->type == STRADA_UNDEF)) return strdup(dflt);
    char *s = strada_to_str(v);
    return s ? s : strdup(dflt);
}
/* core wrap: returns malloc'd result */
static char *tw_do_wrap(const char *ip, const char *xp, const char *text_in) {
    int columns = tw_cfg_int("columns", 76);
    int tabstop = tw_cfg_int("tabstop", 8);
    int unexp   = tw_cfg_int("unexpand", 1);
    char *huge  = tw_cfg_str("huge", "wrap");
    char *sep   = tw_cfg_str("separator", "\n");
    char *t = tw_expand(text_in, strlen(text_in), tabstop);
    char *eip = tw_expand(ip, strlen(ip), tabstop);
    char *exp = tw_expand(xp, strlen(xp), tabstop);
    int ll  = columns - (int)tw_xlen(eip, strlen(eip)) - 1; if (ll < 0) ll = 0;
    int nll = columns - (int)tw_xlen(exp, strlen(exp)) - 1; if (nll < 1) nll = 1;
    free(eip); free(exp);
    size_t n = strlen(t);
    size_t cap = n * 2 + strlen(ip) + strlen(xp) + 64, ro = 0;
    char *r = (char*)malloc(cap);
    const char *lead = ip;
    const char *nl = "";
    int cur_ll = ll;
    char rembuf[16]; rembuf[0] = 0; const char *remainder = rembuf;
    size_t pos = 0;
#define TW_APP(S,L) do { size_t _l=(L); while (ro+_l+1>cap){cap=cap*2+_l;r=(char*)realloc(r,cap);} memcpy(r+ro,(S),_l); ro+=_l; } while(0)
    for (;;) {
        size_t j = pos; int allws = 1;
        while (j < n) { unsigned char cc = (unsigned char)t[j]; if (cc!=' '&&cc!='\t'&&cc!='\n'&&cc!='\r') { allws = 0; break; } j++; }
        if (allws) break;
        /* scan one line: largest group1 (<= cur_ll graphemes, no \n) ending at a break */
        size_t b = pos; long brk = -1; int brk_nl = 0; size_t ll_end = pos; size_t gtaken = 0;
        for (size_t g = 0; ; g++) {
            if (b >= n) { brk = (long)n; brk_nl = 0; break; }
            char c = t[b];
            if (c == '\n') { brk = (long)b; brk_nl = 1; break; }
            if (c == ' ' || c == '\t' || c == '\r') { brk = (long)b; brk_nl = 0; }
            if (g >= (size_t)cur_ll) { break; }
            b += tw_glen(t, b, n); gtaken++; ll_end = b;
        }
        size_t g1_end; int forced_wrap = 0;
        (void)gtaken;
        if (brk >= 0) {
            g1_end = (size_t)brk;
        } else if (strcmp(huge, "overflow") == 0) {
            /* let the huge word overflow whole: extend to the next break */
            size_t e = pos;
            while (e < n && t[e] != '\n' && t[e] != ' ' && t[e] != '\t' && t[e] != '\r')
                e += tw_glen(t, e, n);
            g1_end = e;
            if (e >= n) brk = (long)n;
            else if (t[e] == '\n') { brk = (long)e; brk_nl = 1; }
            else { brk = (long)e; brk_nl = 0; }
        } else {
            /* huge='wrap' (default): force-break at exactly cur_ll graphemes */
            g1_end = ll_end; forced_wrap = 1;
        }
        /* emit nl + unexpand(lead + group1) — perl unexpands lead+chunk as a
         * unit so a space-only lead collapses to tabs too. */
        TW_APP(nl, strlen(nl));
        size_t g1len = g1_end - pos;
        size_t leadlen = strlen(lead);
        size_t cl = leadlen + g1len;
        char *combo = (char*)malloc(cl + 1);
        memcpy(combo, lead, leadlen);
        memcpy(combo + leadlen, t + pos, g1len);
        combo[cl] = 0;
        if (unexp) {
            char *ue = (char*)malloc(cl + 16);
            tw_unexpand_line(combo, tabstop, ue);
            TW_APP(ue, strlen(ue));
            free(ue);
        } else {
            TW_APP(combo, cl);
        }
        free(combo);
        /* compute remainder + advance pos */
        if (forced_wrap) {
            remainder = sep; pos = g1_end;
        } else if ((size_t)brk == n) {
            rembuf[0] = 0; remainder = rembuf; pos = n;
        } else if (brk_nl) {
            size_t e = (size_t)brk;
            while (e < n && (t[e] == '\n' || t[e] == '\r')) e++;
            remainder = sep;            /* separator replaces the newline run */
            pos = e;
        } else {
            rembuf[0] = t[(size_t)brk]; rembuf[1] = 0; remainder = rembuf;
            pos = (size_t)brk + tw_glen(t, (size_t)brk, n);
        }
        lead = xp; cur_ll = nll; nl = sep;
    }
    TW_APP(remainder, strlen(remainder));
    if (pos != n) { TW_APP(lead, strlen(lead)); TW_APP(t + pos, n - pos); }
    r[ro] = 0;
#undef TW_APP
    free(t); free(huge); free(sep);
    return r;
}
/* join the text args the way Text::Wrap does (single space between, none if
 * an element already ends in whitespace; tail appended raw) */
static char *tw_join_text(StradaArray *av, int start) {
    int len = (int)strada_array_length(av);
    size_t cap = 64, o = 0; char *buf = (char*)malloc(cap);
    for (int i = start; i < len; i++) {
        StradaValue *e = strada_array_get(av, i);
        char *s = e ? strada_to_str(e) : strdup("");
        size_t sl = strlen(s);
        while (o + sl + 2 > cap) { cap = cap * 2 + sl; buf = (char*)realloc(buf, cap); }
        memcpy(buf + o, s, sl); o += sl;
        int is_last = (i == len - 1);
        int ends_ws = sl > 0 && (s[sl-1]==' '||s[sl-1]=='\t'||s[sl-1]=='\n'||s[sl-1]=='\r');
        if (!is_last && !ends_ws) buf[o++] = ' ';
        free(s);
    }
    buf[o] = 0;
    return buf;
}
StradaValue *perla_text_wrap(StradaValue *args) {
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    if (!av || strada_array_length(av) < 2) return strada_new_str("");
    char *ip = strada_to_str(strada_array_get(av, 0));
    char *xp = strada_to_str(strada_array_get(av, 1));
    char *text = tw_join_text(av, 2);
    char *out = tw_do_wrap(ip ? ip : "", xp ? xp : "", text);
    StradaValue *r = strada_new_str(out);
    free(ip); free(xp); free(text); free(out);
    return r;
}
/* fill: split into paragraphs on /\n\s+/, collapse \s+ -> ' ' per para,
 * wrap each, join with "\n\n" (ip eq xp) or "\n". */
StradaValue *perla_text_fill(StradaValue *args) {
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    if (!av || strada_array_length(av) < 2) return strada_new_str("");
    char *ip = strada_to_str(strada_array_get(av, 0));
    char *xp = strada_to_str(strada_array_get(av, 1));
    /* join raw text args with "\n" */
    int len = (int)strada_array_length(av);
    size_t cap = 64, o = 0; char *joined = (char*)malloc(cap);
    for (int i = 2; i < len; i++) {
        StradaValue *e = strada_array_get(av, i);
        char *s = e ? strada_to_str(e) : strdup("");
        size_t sl = strlen(s);
        while (o + sl + 2 > cap) { cap = cap * 2 + sl; joined = (char*)realloc(joined, cap); }
        if (i > 2) joined[o++] = '\n';
        memcpy(joined + o, s, sl); o += sl;
        free(s);
    }
    joined[o] = 0;
    char *psep = (ip && xp && strcmp(ip, xp) == 0) ? "\n\n" : "\n";
    size_t rcap = o * 2 + 64, ro = 0; char *res = (char*)malloc(rcap);
    /* split on /\n\s+/ : a newline followed by 1+ whitespace starts a new para */
    size_t i = 0, n = o; int first_para = 1;
    while (i <= n) {
        size_t pstart = i;
        /* find next /\n\s+/ */
        size_t pend = n; size_t nexti = n;
        for (size_t k = i; k + 1 < n; k++) {
            if (joined[k] == '\n') {
                unsigned char c2 = (unsigned char)joined[k+1];
                if (c2==' '||c2=='\t'||c2=='\n'||c2=='\r') {
                    pend = k; size_t e = k + 1;
                    while (e < n && ((unsigned char)joined[e]==' '||joined[e]=='\t'||joined[e]=='\n'||joined[e]=='\r')) e++;
                    nexti = e; break;
                }
            }
        }
        /* paragraph text [pstart,pend); collapse \s+ -> ' ' */
        size_t plen = pend - pstart;
        char *para = (char*)malloc(plen + 1); size_t po = 0; int inws = 0;
        for (size_t k = pstart; k < pend; k++) {
            unsigned char c = (unsigned char)joined[k];
            if (c==' '||c=='\t'||c=='\n'||c=='\r') { if (!inws) { para[po++]=' '; inws=1; } }
            else { para[po++] = (char)c; inws = 0; }
        }
        para[po] = 0;
        char *w = tw_do_wrap(ip ? ip : "", xp ? xp : "", para);
        if (!first_para) { size_t sl=strlen(psep); while(ro+sl+1>rcap){rcap*=2;res=realloc(res,rcap);} memcpy(res+ro,psep,sl); ro+=sl; }
        size_t wl = strlen(w);
        while (ro + wl + 1 > rcap) { rcap = rcap*2+wl; res = realloc(res, rcap); }
        memcpy(res + ro, w, wl); ro += wl;
        free(w); free(para);
        first_para = 0;
        if (nexti >= n) break;
        i = nexti;
    }
    res[ro] = 0;
    StradaValue *r = strada_new_str(res);
    free(ip); free(xp); free(joined); free(res);
    return r;
}

extern StradaValue *v_ARGV;
StradaValue *perla_getopt_getoptions(StradaValue *args) {
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    if (!av) return STRADA_MAKE_TAGGED_INT(1);
    if (!v_ARGV) v_ARGV = strada_new_array();
    StradaArray *argv = strada_deref_array(v_ARGV);
    return go_run(av, 0, argv);
}
StradaValue *perla_getopt_getoptions_from_array(StradaValue *args) {
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    if (!av || strada_array_length(av) < 1) return STRADA_MAKE_TAGGED_INT(1);
    StradaValue *aref = strada_array_get(av, 0);
    StradaArray *parse = NULL;
    if (aref && !STRADA_IS_TAGGED_INT(aref) && aref->type == STRADA_REF
        && aref->value.rv && aref->value.rv->type == STRADA_ARRAY)
        parse = strada_deref_array(aref->value.rv);
    if (!parse) return STRADA_MAKE_TAGGED_INT(1);
    return go_run(av, 1, parse);
}

/* Assign a list to a dereferenced array via `@{$ref} = LIST`.
 *
 * - If $ref is a string ending in "::ISA", route through the stash so the
 *   package's @ISA is rebuilt (used by dynamic `import` subs that rewrite
 *   the caller's ISA, e.g. Drogo::Dispatch).
 * - Otherwise, if $ref is a real array reference, replace its contents
 *   with the elements of `value` — matching the normal Perl semantics of
 *   `@{$arrayref} = (...)`.
 * - Other shapes (undef, tagged int, etc.) are no-ops. */
/* `%{$ref} = (k => v, ...)` — hash dereference assignment. Real hashref:
 * replace dst entries with the RHS list. Symbolic ref (`$ref` is a
 * string holding `Pkg::name`): set the package hash. Without this,
 * perla had no LHS deref handler for hashes — `%{$href} = (k => v)`
 * silently dropped the assignment. */
static StradaValue *_pairs_to_hash(StradaValue *value) {
    /* Build a fresh hash from value: if value is already a hash, copy it;
     * if value is an array of alternating (k, v) pairs, convert. Returns
     * a NEW StradaValue (caller takes ownership). */
    StradaValue *h = strada_new_hash();
    if (!value) return h;
    if (!STRADA_IS_TAGGED_INT(value) && value->type == STRADA_HASH) {
        StradaArray *vkeys = strada_hash_keys(value->value.hv);
        if (vkeys) {
            for (size_t i = 0; i < vkeys->size; i++) {
                char *k = strada_to_str(vkeys->elements[vkeys->head + i]);
                if (k) {
                    StradaValue *v = strada_hash_get(value->value.hv, k);
                    if (v) strada_incref(v);
                    strada_hash_set_take(h->value.hv, k, v);
                    free(k);
                }
            }
            strada_free_array(vkeys);
        }
        return h;
    }
    StradaArray *src = strada_deref_array(value);
    if (!src) return h;
    for (size_t i = 0; i + 1 < src->size; i += 2) {
        char *k = strada_to_str(src->elements[src->head + i]);
        StradaValue *v = src->elements[src->head + i + 1];
        if (k) {
            if (v) strada_incref(v);
            strada_hash_set_take(h->value.hv, k, v);
            free(k);
        }
    }
    return h;
}

void perla_deref_hash_assign(StradaValue *ref, StradaValue *value) {
    if (!ref) return;
    /* Symbolic-ref case */
    if (!STRADA_IS_TAGGED_INT(ref) && ref->type == STRADA_STR) {
        char *name = strada_to_str(ref);
        if (name) {
            /* Build the actual hash from the RHS list/hash. perla_hash_set
             * needs a hash value — storing the raw array would defeat
             * later $h{k} reads. */
            StradaValue *h = _pairs_to_hash(value);
            const char *sep = NULL;
            for (const char *p = name; *p; p++) {
                if (p[0] == ':' && p[1] == ':') { sep = p; }
            }
            if (sep) {
                size_t plen = sep - name;
                char pkg[256];
                if (plen >= sizeof(pkg)) plen = sizeof(pkg) - 1;
                memcpy(pkg, name, plen);
                pkg[plen] = '\0';
                perla_hash_set(pkg, sep + 2, h);
            } else {
                perla_hash_set("main", name, h);
            }
            strada_decref(h);
            free(name);
        }
        return;
    }
    /* Real hashref case */
    StradaHash *dst = strada_deref_hash(ref);
    if (!dst) return;
    /* Clear existing entries */
    StradaArray *keys = strada_hash_keys(dst);
    if (keys) {
        for (size_t i = 0; i < keys->size; i++) {
            char *k = strada_to_str(keys->elements[keys->head + i]);
            if (k) {
                strada_hash_delete_take(dst, k);
                free(k);
            }
        }
        strada_free_array(keys);
    }
    /* Walk the RHS list as alternating (key, value) pairs */
    if (!value) return;
    StradaArray *src = strada_deref_array(value);
    if (src) {
        for (size_t i = 0; i + 1 < src->size; i += 2) {
            char *k = strada_to_str(src->elements[src->head + i]);
            StradaValue *v = src->elements[src->head + i + 1];
            if (k) {
                if (v) strada_incref(v);
                strada_hash_set_take(dst, k, v);
                free(k);
            }
        }
    } else if (!STRADA_IS_TAGGED_INT(value) && value->type == STRADA_HASH) {
        /* Already a hash — copy entries */
        StradaArray *vkeys = strada_hash_keys(value->value.hv);
        if (vkeys) {
            for (size_t i = 0; i < vkeys->size; i++) {
                char *k = strada_to_str(vkeys->elements[vkeys->head + i]);
                if (k) {
                    StradaValue *v = strada_hash_get(value->value.hv, k);
                    if (v) strada_incref(v);
                    strada_hash_set_take(dst, k, v);
                    free(k);
                }
            }
            strada_free_array(vkeys);
        }
    }
}

void perla_deref_array_assign(StradaValue *ref, StradaValue *value) {
    if (!ref) return;
    /* Symbolic-ref case: string name */
    if (!STRADA_IS_TAGGED_INT(ref) && ref->type == STRADA_STR) {
        char *name = strada_to_str(ref);
        if (name) {
            size_t len = strlen(name);
            if (len >= 5 && strcmp(name + len - 5, "::ISA") == 0) {
                perla_isa_assign(name, value);
            } else {
                /* General `@{"Pkg::name"} = (...)` symbolic write. Split
                 * at the last `::` to find package + name and store
                 * through the stash. Without this, only ::ISA worked;
                 * other package arrays silently stayed at their
                 * original value. */
                const char *sep = NULL;
                for (const char *p = name; *p; p++) {
                    if (p[0] == ':' && p[1] == ':') { sep = p; }
                }
                if (sep) {
                    size_t plen = sep - name;
                    char pkg[256];
                    if (plen >= sizeof(pkg)) plen = sizeof(pkg) - 1;
                    memcpy(pkg, name, plen);
                    pkg[plen] = '\0';
                    perla_array_set(pkg, sep + 2, value);
                } else {
                    perla_array_set("main", name, value);
                }
            }
            free(name);
        }
        return;
    }
    /* Real array reference case: replace dst contents with value's */
    StradaArray *dst = strada_deref_array(ref);
    if (!dst) return;
    while (dst->size > 0) {
        StradaValue *e = dst->elements[dst->head + dst->size - 1];
        dst->size--;
        if (e) strada_decref(e);
    }
    StradaArray *src = value ? strada_deref_array(value) : NULL;
    if (src) {
        for (size_t i = 0; i < src->size; i++) {
            StradaValue *e = src->elements[src->head + i];
            if (e) strada_incref(e);
            strada_array_push(dst, e);
        }
    }
}

/* Replace a package's @ISA via symbolic-ref assignment.
 * pkg_isa is a string like "Foo::Bar::ISA"; the trailing "::ISA" is stripped
 * to get the package name. parents is a StradaValue* array whose elements
 * become the new @ISA contents. Used for the Perl idiom
 *   @{"${caller}::ISA"} = qw(Parent1 Parent2);
 * that dynamic `import` subs use (e.g. Drogo::Dispatch). */
void perla_isa_assign(const char *pkg_isa, StradaValue *parents) {
    if (!pkg_isa) return;
    if (getenv("PERLA_ISA_DEBUG")) {
        fprintf(stderr, "[isa_assign] pkg_isa=%s", pkg_isa);
        if (parents) {
            StradaArray *dav = strada_deref_array(parents);
            if (dav) {
                fprintf(stderr, " parents=[");
                for (size_t i = 0; i < dav->size; i++) {
                    StradaValue *p = dav->elements[dav->head + i];
                    char *ps = p ? strada_to_str(p) : NULL;
                    fprintf(stderr, "%s%s", i ? "," : "", ps ? ps : "(null)");
                    if (ps) free(ps);
                }
                fprintf(stderr, "]");
            } else if (!STRADA_IS_TAGGED_INT(parents) && parents->type == STRADA_STR) {
                char *ps = strada_to_str(parents);
                fprintf(stderr, " parent=%s", ps ? ps : "(empty)");
                if (ps) free(ps);
            }
        }
        fprintf(stderr, "\n");
    }
    size_t len = strlen(pkg_isa);
    const char *suffix = "::ISA";
    size_t slen = 5;
    if (len < slen || strcmp(pkg_isa + len - slen, suffix) != 0) return;
    /* Extract package name (everything before "::ISA") */
    char *pkg = strndup(pkg_isa, len - slen);
    PerlStash *stash = perla_stash_get_or_create(pkg);
    free(pkg);
    /* Reset existing ISA */
    if (stash->isa) {
        strada_decref(stash->isa);
        stash->isa = NULL;
    }
    stash->isa = strada_new_array();
    PerlGlob *g = perla_glob_get_or_create(stash, "ISA");
    if (g->slots[PERLA_SLOT_ARRAY]) {
        strada_decref(g->slots[PERLA_SLOT_ARRAY]);
    }
    g->slots[PERLA_SLOT_ARRAY] = stash->isa;
    strada_incref(stash->isa);
    /* Push each parent. `parents` may be an array (the usual case from
     * `@{"Pkg::ISA"} = qw(A B)`), or a single scalar string if the user
     * wrote `@{"Pkg::ISA"} = "Parent"` — Perl treats scalar assignment
     * to an array as a one-element list. YAML::Mo does exactly this:
     *   @{$P.ISA} = $M . 'Object'
     * If we skipped the single-scalar form, @Pkg::ISA ended up empty
     * and method dispatch fell off the ISA chain. */
    StradaArray *pav = parents ? strada_deref_array(parents) : NULL;
    if (!pav) {
        if (parents && !STRADA_IS_TAGGED_INT(parents) && parents->type == STRADA_STR) {
            char *ps = strada_to_str(parents);
            if (ps) {
                StradaValue *parent_sv = strada_new_str(ps);
                strada_array_push(stash->isa->value.av, parent_sv);
                strada_decref(parent_sv);
                free(ps);
            }
        }
        return;
    }
    for (size_t i = 0; i < pav->size; i++) {
        StradaValue *p = pav->elements[pav->head + i];
        if (!p) continue;
        char *ps = strada_to_str(p);
        if (ps) {
            StradaValue *parent_sv = strada_new_str(ps);
            strada_array_push(stash->isa->value.av, parent_sv);
            strada_decref(parent_sv);
            free(ps);
        }
    }
}

int perla_isa_check(const char *pkg, const char *target) {
    if (!pkg || !target) return 0;
    if (strcmp(pkg, target) == 0) return 1;
    /* Every Perl class IS-A UNIVERSAL (Perl semantics). The inline `isa()`
     * codegen calls this directly without the universal_isa wrapper, so
     * `$obj->isa("UNIVERSAL")` would otherwise return false. */
    if (strcmp(target, "UNIVERSAL") == 0) return 1;

    PerlStash *stash = perla_stash_get(pkg);
    if (!stash) return 0;

    /* Same sync as perla_method_resolve — when @{"Pkg::ISA"} was
     * mutated via symbolic ref (Class::C3::Componentised, raw
     * `@{"$pkg\::ISA"} = ...`, etc.) the glob slot has the new
     * value but stash->isa is stale. Reconcile before walking. */
    PerlGlob *isa_glob = perla_glob_get(stash, "ISA");
    if (isa_glob && isa_glob->slots[PERLA_SLOT_ARRAY]
        && isa_glob->slots[PERLA_SLOT_ARRAY] != stash->isa) {
        StradaValue *gv = isa_glob->slots[PERLA_SLOT_ARRAY];
        if (gv && !STRADA_IS_TAGGED_INT(gv) && gv->type == STRADA_ARRAY) {
            if (stash->isa) strada_decref(stash->isa);
            stash->isa = gv;
            strada_incref(stash->isa);
        }
    }

    if (!stash->isa) return 0;

    StradaArray *isa = stash->isa->value.av;
    if (!isa) return 0;

    for (size_t i = 0; i < isa->size; i++) {
        /* Use head offset (see perla_method_resolve comment). */
        StradaValue *parent_sv = isa->elements[isa->head + i];
        if (!parent_sv) continue;
        char *parent = strada_to_str(parent_sv);
        int found = perla_isa_check(parent, target);
        free(parent);
        if (found) return 1;
    }
    return 0;
}

/* ===== Introspection ===== */

StradaValue *perla_stash_keys(const char *pkg) {
    PerlStash *stash = perla_stash_get(pkg);
    StradaValue *arr = strada_new_array();
    if (!stash) return arr;

    for (int i = 0; i < stash->count; i++) {
        StradaValue *key = strada_new_str(stash->keys[i]);
        strada_array_push(arr->value.av, key);
        strada_decref(key);
    }
    return arr;
}

int perla_can(const char *pkg, const char *method) {
    return perla_method_resolve(pkg, method) != NULL;
}

/* Return the actual code value for $pkg->can($method), so callers can
 * invoke `$u->(args)` on the result. Real Perl `can` returns a CODE
 * ref; the inline ->can codegen previously returned a tagged int (1/0)
 * which broke any caller that tried to use the result as a code ref
 * (e.g. Module::Runtime::use_module accessed via Clone::Choose).
 *
 * If the class defines its own `can` (excluding the UNIVERSAL one),
 * dispatch through that instead — Clone::Choose, Moose's metaclass,
 * and various proxy/AUTOLOAD wrappers override `can` to do backend
 * selection or lazy method generation, and the inline shortcut hides
 * those overrides. We detect "is this UNIVERSAL::can?" by looking at
 * the resolved CPOINTER value. */
StradaValue *perla_can_code(const char *pkg, const char *method) {
    /* See if the class has its own `can` (not the inherited UNIVERSAL one).
     * If so, invoke it: $pkg->can($method) — and return whatever it
     * returns. */
    PerlGlob *can_g = pkg ? perla_method_resolve(pkg, "can") : NULL;
    if (can_g && can_g->slots[PERLA_SLOT_CODE]) {
        StradaValue *can_code = can_g->slots[PERLA_SLOT_CODE];
        int is_universal = 0;
        if (can_code && !STRADA_IS_TAGGED_INT(can_code) &&
            can_code->type == STRADA_CPOINTER &&
            can_code->value.ptr == (void *)perla_universal_can) {
            is_universal = 1;
        }
        if (!is_universal) {
            StradaValue *args = strada_new_array();
            StradaArray *av = strada_deref_array(args);
            strada_array_push_take(av, strada_new_str(pkg));
            strada_array_push_take(av, strada_new_str(method));
            StradaValue *r = perla_call_code(can_code, args);
            strada_decref(args);
            return r ? r : strada_new_undef();
        }
    }
    /* UNIVERSAL behavior — return a callable for the resolved sub.
     *
     * The stash may store the entry as either:
     *   - STRADA_CPOINTER — native C function (already callable);
     *   - STRADA_CLOSURE  — Perl closure (already callable);
     *   - STRADA_STR      — name of a generated C function (e.g.
     *     "perla_sub_Class_Accessor_Grouped_make_group_accessor"),
     *     which is what codegen emits for ordinary `sub` definitions.
     *     Stringifying that to use as a method name would dispatch
     *     into nothing — `can()` callers (e.g. Class::Accessor::
     *     Grouped's `$maker = $self->can($maker)`) expect a code
     *     ref. Resolve via dlsym and box as a CPOINTER so the
     *     subsequent `$self->$maker(...)` hits perla_call_code. */
    PerlGlob *g = perla_method_resolve(pkg, method);
    if (g && g->slots[PERLA_SLOT_CODE]) {
        StradaValue *code = g->slots[PERLA_SLOT_CODE];
        if (code && !STRADA_IS_TAGGED_INT(code) && code->type == STRADA_STR) {
            char *fname = strada_to_str(code);
            if (fname) {
                void *fp = dlsym(RTLD_DEFAULT, fname);
                free(fname);
                if (fp) return strada_cpointer_new(fp);
            }
            /* Fall through to returning the string itself if dlsym
             * fails — caller may still find it useful (e.g.
             * `defined($obj->can($m))` only checks truthiness). */
        }
        strada_incref(code);
        return code;
    }
    return strada_new_undef();
}

/* perla_blessed is now a static inline in perla_stash.h (hot on method dispatch). */

/* `${*$fh}` — the SCALAR slot of the glob that $fh represents. perla
 * models a filehandle as its own SV (no separate glob object), so the
 * slot is stored on the SV's metadata. File::Temp->new stashes the
 * temp filename here; `$self->filename` returns `${*$self}`.
 * perla_fh_slot_get returns the stored value (incref'd) or undef. */
StradaValue *perla_fh_slot_get(StradaValue *gv) {
    if (!gv || STRADA_IS_TAGGED_INT(gv) || !gv->meta
        || !gv->meta->glob_scalar_slot) {
        return strada_new_undef();
    }
    /* Return an independent COPY of the slot value, not the stored SV
     * itself. The surrounding N_DEREF_SCALAR codegen treats the result
     * as a freshly-owned temp (needs_temp_cleanup) and decrefs it after
     * use; handing out the slot's own SV let that decref — and the
     * decrefs accumulated across repeated `${*$fh}` / `$self->filename`
     * / `"$f"` reads — drive the stored value's refcount to zero, so it
     * was freed out from under the slot (the path went empty after a
     * few accesses). A fresh copy (refcount 1) absorbs all that
     * refcounting without touching the slot. `${*$fh}` is read-only in
     * practice (File::Temp's `filename`); writes go through
     * perla_fh_slot_set, so copy-on-read is correct here. */
    StradaValue *v = gv->meta->glob_scalar_slot;
    if (STRADA_IS_TAGGED_INT(v)) return v;  /* immortal — safe to share */
    return strada_clone(v);
}

/* `${*$fh} = X` — store X in the glob's SCALAR slot. Returns X
 * (incref'd) so the assignment expression yields the assigned value. */
StradaValue *perla_fh_slot_set(StradaValue *gv, StradaValue *v) {
    if (!gv || STRADA_IS_TAGGED_INT(gv)) {
        if (v) strada_incref(v);
        return v ? v : strada_new_undef();
    }
    StradaMetadata *m = strada_ensure_meta(gv);
    if (m) {
        if (m->glob_scalar_slot) strada_decref(m->glob_scalar_slot);
        if (v) strada_incref(v);
        m->glob_scalar_slot = v;
    }
    if (v) strada_incref(v);
    return v ? v : strada_new_undef();
}

StradaValue *perla_bless(StradaValue *ref, const char *pkg) {
    if (!pkg) return ref;
    /* Perl dies on `bless 5, 'Foo'` and similar non-ref blesses
     * ("Can't bless non-reference value"). The legitimate targets
     * are STRADA_REF (the common case: `bless \%h, $cls`) and the
     * directly-blessed container types perla also allows: HASH,
     * ARRAY, REGEX, CLOSURE, CSTRUCT, CPOINTER. Anything else
     * (UNDEF, INT, NUM, STR, tagged int) is an error. */
    if (!ref || STRADA_IS_TAGGED_INT(ref)) {
        strada_die("Can't bless non-reference value");
        return ref;
    }
    if (ref->type != STRADA_REF && ref->type != STRADA_HASH
        && ref->type != STRADA_ARRAY && ref->type != STRADA_REGEX
        && ref->type != STRADA_CLOSURE && ref->type != STRADA_CSTRUCT
        && ref->type != STRADA_CPOINTER && ref->type != STRADA_FILEHANDLE) {
        /* STRADA_FILEHANDLE: perl lets you bless an open filehandle
         * (a glob ref). File::Temp->new does exactly this and then
         * overloads '""'. perla models a filehandle as its own SV, so
         * blessing just stamps meta->blessed_package on it. */
        strada_die("Can't bless non-reference value");
        return ref;
    }
    /* Ensure the package stash exists and intern the package name via
     * stash->name. Reusing the stash's stable char* (instead of a fresh
     * strdup per bless) makes ref->meta->blessed_package pointer-equal
     * across all objects of the same class. Hot dispatch sites cache
     * the interned pointer and skip strcmp — a real cost reduction in
     * `$obj->method()` loops. blessed_package was already not-freed
     * (see the "Don't free — may be interned" comment below) so this
     * tightens the invariant rather than introducing it. */
    PerlStash *bless_stash = perla_stash_get_or_create(pkg);
    int was_blessed = 0;
    /* Set blessed_package on the value's metadata */
    if (!ref->meta) {
        ref->meta = (StradaMetadata*)calloc(1, sizeof(StradaMetadata));
    } else if (ref->meta->blessed_package) {
        was_blessed = 1;
        /* Don't free — may be interned */
    }
    if (bless_stash) {
        ref->meta->blessed_package = bless_stash->name;
        /* CRITICAL: stash->name is owned by PerlStash, not by the SV.
         * strada_free_value calls strada_intern_release(blessed_package)
         * which falls through to free() when the pointer isn't in
         * strada's intern table — that would free the stash's name and
         * corrupt every subsequent bless / stash lookup in the same
         * package (manifested as a double-free at the next free site).
         * blessed_immortal=1 tells strada_free_value to skip the
         * intern_release entirely. */
        ref->meta->blessed_immortal = 1;
    } else {
        ref->meta->blessed_package = strdup(pkg);
        ref->meta->blessed_immortal = 0;
    }
    /* Register for the process-exit DESTROY sweep. Re-bless (was_blessed==1)
     * keeps the existing registry entry; only first-time bless appends. */
    if (!was_blessed) perla_blessed_registry_add(ref);
    /* Do NOT incref. perla_bless is now transparent: it returns the
     * same SV with refcount unchanged. The void-context case (`bless
     * $h, "C";`) is handled by the codegen emitting `strada_incref(__br)`
     * inside the bless statement-expression so the outer void-wrap's
     * decref balances out. Without this change, DESTROY-at-scope-exit
     * could never fire because the extra incref pinned every blessed
     * lexical past the variable's lifetime. */
    return ref;
}

/* Append ref to the global blessed registry. Grows the array
 * geometrically. Safe to call with any ref; the sweep tolerates entries
 * whose meta/blessed_package have since been cleared. */
void perla_blessed_registry_add(StradaValue *ref) {
    if (!ref || STRADA_IS_TAGGED_INT(ref)) return;
    if (g_blessed_registry_size >= g_blessed_registry_capacity) {
        size_t newcap = g_blessed_registry_capacity ? g_blessed_registry_capacity * 2 : 256;
        StradaValue **n = (StradaValue **)realloc(g_blessed_registry,
                                                  newcap * sizeof(StradaValue *));
        if (!n) return;  /* OOM — silently skip; worst case = missed DESTROY */
        g_blessed_registry = n;
        g_blessed_registry_capacity = newcap;
    }
    g_blessed_registry[g_blessed_registry_size++] = ref;
}

/* Remove ref from the global blessed registry. Called when a blessed
 * value is being freed so the process-exit DESTROY sweep doesn't fire
 * DESTROY a second time on a pool-recycled SV pointer. Linear scan
 * is fine — the registry stays small in practice (each entry is one
 * blessed object that's STILL alive at the call site, and most are
 * released back into the pool by the time exit fires anyway).
 *
 * This is the safety net half of the DESTROY-at-scope-exit work: it
 * doesn't fire DESTROY earlier on its own (perla still pins via
 * perla_bless's strada_incref + missing block-exit decrefs for lexicals),
 * but it ensures that IF a future codegen change does emit those decrefs,
 * the registry sweep won't double-fire on stale pointers. */
void perla_blessed_registry_remove(StradaValue *ref) {
    if (!ref || STRADA_IS_TAGGED_INT(ref) || !g_blessed_registry) return;
    for (size_t i = 0; i < g_blessed_registry_size; i++) {
        if (g_blessed_registry[i] == ref) {
            /* Compact by moving the last entry into this slot (O(1)). */
            g_blessed_registry[i] = g_blessed_registry[--g_blessed_registry_size];
            return;
        }
    }
}

int perla_in_global_destruction_active(void) {
    return g_in_global_destruction;
}

/* Walk the registry and fire DESTROY for any still-blessed entry. Called
 * from perla_cleanup before the stashes are freed so DESTROY can still
 * resolve method bodies via perla_method_resolve. Marks
 * g_in_global_destruction = 1 while running so
 * Devel::GlobalDestruction::in_global_destruction reports truth. */
void perla_destroy_sweep(void) {
    if (!g_blessed_registry || g_blessed_registry_size == 0) return;
    g_in_global_destruction = 1;
    /* Iterate forward — DESTROY order isn't guaranteed by Perl in global
     * destruction either. Forward = bless order; reverse is also valid. */
    for (size_t i = 0; i < g_blessed_registry_size; i++) {
        StradaValue *sv = g_blessed_registry[i];
        if (!sv || STRADA_IS_TAGGED_INT(sv)) continue;
        /* sv->meta is NULL after strada_free_value recycles the slot, so
         * already-DESTROYed entries (and re-purposed pool slots) skip. */
        if (!sv->meta) continue;
        if (!sv->meta->blessed_package) continue;
        /* Fire DESTROY via strada's existing call path. The hook walks
         * @ISA chain to find an ancestor's DESTROY if needed. Result is
         * discarded. After this, clear blessed_package so the rc=0 path
         * won't fire DESTROY a second time on this sv. */
        strada_call_destroy(sv);
        /* Clear blessed_package so the rc=0 path in strada_free_value
         * doesn't fire DESTROY a second time on this sv. We deliberately
         * skip strada_intern_release here — that symbol is static to
         * strada_runtime.c, and we're in global destruction anyway, so
         * leaking the strdup'd / interned class-name string until OS
         * reclaim is benign. */
        if (sv->meta && sv->meta->blessed_package) {
            sv->meta->blessed_package = NULL;
            sv->meta->blessed_immortal = 0;
        }
    }
    g_in_global_destruction = 0;
}

/* Resolve a StradaValue to a class name (mirrors Perl's bless semantics).
 *
 * Perl's `bless $r, $class` treats $class as a class name:
 *   - If $class is a blessed ref, bless uses ref($class) — i.e. the
 *     *package* of the ref, not the ref's stringification. This lets
 *     `$self->new(...)` patterns land on the invocant's package.
 *   - If $class is a plain string, use the string.
 *   - If $class is an unblessed ref, stringify (matches Perl; the
 *     resulting weird "REF(0x…)" class name is Perl's behavior too).
 *
 * Returns a strdup'd C string — caller must free. */
char *perla_class_name(StradaValue *sv) {
    if (!sv || STRADA_IS_TAGGED_INT(sv)) return strdup("");
    if (sv->meta && sv->meta->blessed_package) {
        return strdup(sv->meta->blessed_package);
    }
    return strada_to_str(sv);
}

/* ===== Method Dispatch ===== */

/* Global $AUTOLOAD variable — set before calling AUTOLOAD sub */
static StradaValue *perla_autoload_var = NULL;

/* Tracks the last filehandle read by perla_readline_fh /
 * perla_read_all_lines_fh, so $. can resume from the right counter
 * when the active fh changes. Per Perl, $. is *per-handle*: switching
 * to a previously-read fh restores its prior line count. */
StradaValue *perla_last_readline_fh = NULL;

/* Save the current count for `from`, look up `to`'s saved count and
 * return it (0 if never read before). */
int perla_dollar_dot_switch(StradaValue *from, int from_count, StradaValue *to) {
    if (from) {
        int found = 0;
        for (int i = 0; i < perla_dot_count; i++) {
            if (perla_dot_table[i].fh == from) {
                perla_dot_table[i].count = from_count;
                found = 1;
                break;
            }
        }
        if (!found) {
            if (perla_dot_count >= perla_dot_capacity) {
                int cap = perla_dot_capacity ? perla_dot_capacity * 2 : 8;
                PerlaDotEntry *n = (PerlaDotEntry *)realloc(perla_dot_table,
                                                          cap * sizeof(PerlaDotEntry));
                if (n) { perla_dot_table = n; perla_dot_capacity = cap; }
            }
            if (perla_dot_count < perla_dot_capacity) {
                perla_dot_table[perla_dot_count].fh = from;
                perla_dot_table[perla_dot_count].count = from_count;
                perla_dot_count++;
            }
        }
    }
    if (!to) return 0;
    for (int i = 0; i < perla_dot_count; i++) {
        if (perla_dot_table[i].fh == to) return perla_dot_table[i].count;
    }
    return 0;
}

StradaValue *perla_get_autoload_var(void) {
    return perla_autoload_var ? perla_autoload_var : strada_new_undef();
}

void perla_set_autoload_var(const char *fullname) {
    if (perla_autoload_var) strada_decref(perla_autoload_var);
    perla_autoload_var = strada_new_str(fullname ? fullname : "");
}

/* Assign $AUTOLOAD = value from generated code. Takes ownership of `val`
 * (mirrors strada_decref+reassign pattern used by other scalar lvalues). */
void perla_set_autoload_var_sv(StradaValue *val) {
    if (perla_autoload_var) strada_decref(perla_autoload_var);
    perla_autoload_var = val;
}

/* Try AUTOLOAD dispatch: sets $Package::AUTOLOAD and calls AUTOLOAD($self, @args) */
StradaValue *perla_try_autoload(const char *pkg, const char *method,
                                 StradaValue *obj, StradaValue *args) {
    /* DBI method interception — check if this is a DBI method call */
    /* DBI::_install_method is a no-op — we intercept DBI at C level */
    if (strcmp(method, "_install_method") == 0 || strcmp(method, "install_method") == 0) {
        return STRADA_MAKE_TAGGED_INT(1);
    }
    StradaArray *dbi_av = args ? strada_deref_array(args) : NULL;
    if (dbi_av && dbi_av->size >= 1) {
        if (strcmp(method, "selectrow_array") == 0) {
            if (dbi_av->size >= 2) {
                char *sql = strada_to_str(dbi_av->elements[1]);
                StradaValue *r = perla_dbi_selectrow_array(obj, sql, args);
                free(sql);
                return r;
            }
        } else if (strcmp(method, "selectall_arrayref") == 0) {
            if (dbi_av->size >= 2) {
                char *sql = strada_to_str(dbi_av->elements[1]);
                StradaValue *r = perla_dbi_selectall_arrayref(obj, sql, args);
                free(sql);
                return r;
            }
        } else if (strcmp(method, "selectcol_arrayref") == 0) {
            if (dbi_av->size >= 2) {
                char *sql = strada_to_str(dbi_av->elements[1]);
                StradaValue *r = perla_dbi_selectcol_arrayref(obj, sql, args);
                free(sql);
                return r;
            }
        } else if (strcmp(method, "do") == 0 || strcmp(method, "sql_do") == 0) {
            if (dbi_av->size >= 2) {
                char *sql = strada_to_str(dbi_av->elements[1]);
                StradaValue *r = perla_dbi_do(obj, sql, args);
                free(sql);
                return r;
            }
        } else if (strcmp(method, "prepare") == 0 || strcmp(method, "prepare_cached") == 0) {
            /* `prepare_cached` is `prepare` with a server-side cache; for
             * perla's MySQL-only DBI shim a plain prepare is fine — the
             * cache is a perf optimization, not a semantic change. DBIC
             * calls prepare_cached for the connection-test selectrow. */
            if (dbi_av->size >= 2) {
                char *sql = strada_to_str(dbi_av->elements[1]);
                StradaValue *r = perla_dbi_prepare(obj, sql);
                free(sql);
                return r;
            }
        } else if (strcmp(method, "errstr") == 0 || strcmp(method, "err") == 0) {
            /* `$dbh->errstr` / `$dbh->err` — DBIC reads these to format
             * exception messages. We don't track per-connection error
             * state yet (errors print to stderr from perla_dbi_*), so
             * return undef like a clean handle. */
            return strada_new_undef();
        } else if (strcmp(method, "execute") == 0) {
            return perla_dbi_execute(obj, args);
        } else if (strcmp(method, "bind_param") == 0) {
            return perla_dbi_bind_param(obj, args);
        } else if (strcmp(method, "bind_columns") == 0) {
            return perla_dbi_bind_columns(obj, args);
        } else if (strcmp(method, "fetch") == 0) {
            return perla_dbi_fetch(obj);
        } else if (strcmp(method, "fetchall_arrayref") == 0) {
            return perla_dbi_fetchall_arrayref(obj, args);
        } else if (strcmp(method, "finish") == 0) {
            return perla_dbi_finish(obj);
        } else if (strcmp(method, "fetchrow_hashref") == 0) {
            return perla_dbi_fetchrow_hashref(obj);
        } else if (strcmp(method, "fetchrow_array") == 0) {
            return perla_dbi_fetchrow_array(obj);
        } else if (strcmp(method, "disconnect") == 0) {
            perla_dbi_disconnect(obj);
            return STRADA_MAKE_TAGGED_INT(1);
        } else if (strcmp(method, "ping") == 0 || strcmp(method, "connected") == 0) {
            /* `$dbh->ping` / `$dbh->connected` — DBIC and DBI.pm's connect
             * post-hook call these to verify the connection. Real DBI returns
             * true if alive. Approximate via `Active`. */
            StradaValue *r = perla_dbi_get_attr(obj, "Active");
            return r ? r : STRADA_MAKE_TAGGED_INT(1);
        } else if (strcmp(method, "FETCH") == 0 && dbi_av->size >= 2) {
            /* `$dbh->FETCH($attr)` / `$sth->FETCH($attr)` — DBI's tied-hash
             * style attribute access. DBIC reads `Active`/`AutoCommit` on
             * the dbh and `NUM_OF_FIELDS` on the sth; route to the right
             * handler based on the blessed package. */
            char *attr = strada_to_str(dbi_av->elements[1]);
            const char *pkg_b = perla_blessed(obj);
            StradaValue *r;
            if (pkg_b && strcmp(pkg_b, "DBI::st") == 0) {
                r = perla_dbi_sth_fetch(obj, attr);
            } else {
                r = perla_dbi_get_attr(obj, attr);
            }
            free(attr);
            return r;
        } else if (strcmp(method, "STORE") == 0 && dbi_av->size >= 3) {
            /* `$dbh->STORE($attr, $val)` — set DBI attribute. */
            char *attr = strada_to_str(dbi_av->elements[1]);
            perla_dbi_set_attr(obj, attr, dbi_av->elements[2]);
            free(attr);
            return STRADA_MAKE_TAGGED_INT(1);
        } else if (strcmp(method, "get_info") == 0 && dbi_av->size >= 2) {
            /* `$dbh->get_info($info_type)` — DBI's portable per-driver info
             * lookup. DBIC walks a handful of these to compute SQL dialect
             * options (SQL_DBMS_NAME, SQL_DBMS_VER, SQL_IDENTIFIER_QUOTE_CHAR,
             * etc.). Without this, DBIC's _server_info / _determine_supports
             * paths die on `Can't locate object method "get_info"` and the
             * resultset short-circuits to undef. */
            extern StradaValue *perla_dbi_get_info(StradaValue *handle, int info_type);
            int info = (int)strada_to_int(dbi_av->elements[1]);
            return perla_dbi_get_info(obj, info);
        } else if (strcmp(method, "begin_work") == 0) {
            /* DBIC calls $dbh->begin_work to start a transaction. Real DBI
             * sets AutoCommit=0 and emits BEGIN. For perla's MySQL shim we
             * just flip auto_commit and run BEGIN. */
            perla_dbi_set_attr(obj, "AutoCommit", STRADA_MAKE_TAGGED_INT(0));
            StradaValue *bw = strada_new_array();
            perla_dbi_do(obj, "BEGIN", bw);
            strada_decref(bw);
            return STRADA_MAKE_TAGGED_INT(1);
        } else if (strcmp(method, "commit") == 0) {
            StradaValue *bw = strada_new_array();
            perla_dbi_do(obj, "COMMIT", bw);
            strada_decref(bw);
            perla_dbi_set_attr(obj, "AutoCommit", STRADA_MAKE_TAGGED_INT(1));
            return STRADA_MAKE_TAGGED_INT(1);
        } else if (strcmp(method, "rollback") == 0) {
            StradaValue *bw = strada_new_array();
            perla_dbi_do(obj, "ROLLBACK", bw);
            strada_decref(bw);
            perla_dbi_set_attr(obj, "AutoCommit", STRADA_MAKE_TAGGED_INT(1));
            return STRADA_MAKE_TAGGED_INT(1);
        } else if (strcmp(method, "quote") == 0 && dbi_av->size >= 2) {
            /* $dbh->quote($val) — wrap string in single quotes with simple
             * escaping. DBIC uses this for fallback SQL builders. */
            char *v = strada_to_str(dbi_av->elements[1]);
            if (!v) return strada_new_str("''");
            size_t n = strlen(v);
            char *out = malloc(n * 2 + 3);
            char *p = out;
            *p++ = '\'';
            for (size_t i = 0; i < n; i++) {
                if (v[i] == '\'') { *p++ = '\''; *p++ = '\''; }
                else if (v[i] == '\\') { *p++ = '\\'; *p++ = '\\'; }
                else *p++ = v[i];
            }
            *p++ = '\'';
            *p = '\0';
            free(v);
            StradaValue *r = strada_new_str(out);
            free(out);
            return r;
        } else if (strcmp(method, "quote_identifier") == 0 && dbi_av->size >= 2) {
            char *v = strada_to_str(dbi_av->elements[1]);
            if (!v) return strada_new_str("``");
            size_t n = strlen(v);
            char *out = malloc(n + 3);
            out[0] = '`';
            memcpy(out + 1, v, n);
            out[n + 1] = '`';
            out[n + 2] = '\0';
            free(v);
            StradaValue *r = strada_new_str(out);
            free(out);
            return r;
        } else if (strcmp(method, "last_insert_id") == 0) {
            /* Use mysql_insert_id via the existing dbi handle. perla_dbi
             * doesn't expose this yet, so fetch it via SELECT LAST_INSERT_ID(). */
            StradaValue *bw = strada_new_array();
            StradaValue *r = perla_dbi_selectrow_array(obj, "SELECT LAST_INSERT_ID()", bw);
            strada_decref(bw);
            return r ? r : STRADA_MAKE_TAGGED_INT(0);
        }
    }

    /* Look up AUTOLOAD — walk @ISA so an AUTOLOAD defined in a parent
     * class (e.g. DBIx::Class::Core) is found from a subclass with no
     * AUTOLOAD of its own. Stops at the first AUTOLOAD found. */
    StradaValue *autoload_fn = perla_code_get(pkg, "AUTOLOAD");
    if (!autoload_fn) {
        /* Walk ISA via perla_method_resolve on the literal name "AUTOLOAD";
         * that uses the normal @ISA traversal rules. */
        PerlGlob *ag = perla_method_resolve(pkg, "AUTOLOAD");
        if (ag && ag->slots[PERLA_SLOT_CODE]) {
            autoload_fn = ag->slots[PERLA_SLOT_CODE];
        }
    }
    if (!autoload_fn) return NULL;

    /* Set $AUTOLOAD to "Package::method" */
    if (perla_autoload_var) strada_decref(perla_autoload_var);
    char fullname[512];
    snprintf(fullname, sizeof(fullname), "%s::%s", pkg, method);
    perla_autoload_var = strada_new_str(fullname);

    /* Call the AUTOLOAD function with the original args */
    char *fn_name = strada_to_str(autoload_fn);
    void *fn_ptr = dlsym(RTLD_DEFAULT, fn_name);
    free(fn_name);

    if (!fn_ptr) return NULL;

    StradaValue *result = ((StradaValue*(*)(StradaValue*))fn_ptr)(args);
    return result;
}

/* Adapter for strada_method_can_hook — wraps perla_can with the
 * (obj, method) signature strada expects. Returns 0 for unblessed
 * values or unresolvable methods. */
int perla_method_can_adapter(StradaValue *obj, const char *method) {
    if (!obj || STRADA_IS_TAGGED_INT(obj) || !method) return 0;
    /* Bless may stamp blessed_package on the REF wrapper OR the inner
     * value; check both. */
    const char *pkg = (obj->meta ? obj->meta->blessed_package : NULL);
    if (!pkg && obj->type == STRADA_REF && obj->value.rv
        && !STRADA_IS_TAGGED_INT(obj->value.rv) && obj->value.rv->meta) {
        pkg = obj->value.rv->meta->blessed_package;
    }
    if (!pkg) return 0;
    return perla_can(pkg, method);
}

StradaValue *perla_method_dispatch(StradaValue *obj, const char *method, StradaValue *args) {
    if (!obj || !method) return strada_new_undef();
    /* Perl: `undef->method` dies with `Can't call method "X" on an undefined
     * value`. Without this, perla silently returned undef, which masked
     * upstream bugs (a method that returned undef, then a chained call on
     * it kept walking with undef instead of dying at the source).
     * Diagnosed via Abe::Bootstrap::app: an Abe::App::init failure
     * propagated through several `$self->r->...` chains as silent undef
     * before Try::Tiny's catch fired with an empty message. */
    if (!STRADA_IS_TAGGED_INT(obj) && obj->type == STRADA_UNDEF) {
        /* Perl: `undef->method` dies with `Can't call method "X" on an
         * undefined value`. Match Perl by default so `eval { $u->method }`
         * can catch the failure via $@. Env opt-out
         * PERLA_UNDEF_METHOD_SILENT=1 restores the old silent-undef-
         * return path for CPAN modules whose flow depends on it
         * (Class::Load::PP / Package::Stash chains). */
        char buf[256];
        snprintf(buf, sizeof(buf),
                 "Can't call method \"%s\" on an undefined value", method);
        if (getenv("PERLA_UNDEF_METHOD_TRACE")) {
            fprintf(stderr, "[undef-method] %s\n", buf);
            strada_print_stack_trace(stderr);
            void *frames[32];
            int nf = backtrace(frames, 32);
            char **syms = backtrace_symbols(frames, nf);
            if (syms) {
                fprintf(stderr, "C backtrace:\n");
                for (int bi = 0; bi < nf; bi++) {
                    fprintf(stderr, "  %s\n", syms[bi]);
                }
                free(syms);
            }
        }
        if (getenv("PERLA_UNDEF_METHOD_SILENT")) {
            return strada_new_undef();
        }
        strada_throw(buf);
        return strada_new_undef();
    }
    if (getenv("PERLA_DISPATCH_DEBUG")) {
        const char *bp = perla_blessed(obj);
        char *os = strada_to_str(obj);
        fprintf(stderr, "[dispatch] %s->%s (blessed=%s)\n", os, method, bp ? bp : "(none)");
        free(os);
    }

    /* IO::Socket::SSL (native client) — route I/O methods to the OpenSSL
     * backend before normal resolution (the system .pm's inherited IO::Handle
     * methods don't resolve in perla). */
    if (perla_value_is_iossl(obj)) {
        StradaValue *r = perla_iossl_method(obj, method, args);
        if (r) return r;
    }

    /* MRO-relative dispatch: $obj->next::method(@args) and the
     * non-fatal $obj->maybe::next::method(@args). DBIx::Class and any
     * MRO::Compat user reaches for these in pretty much every method.
     * Without interception, normal method resolution looks for a
     * literal "next::method" sub and fails. */
    if (strcmp(method, "next::method") == 0) {
        return perla_next_method_dispatch(obj, args, 0);
    }
    if (strcmp(method, "maybe::next::method") == 0) {
        return perla_next_method_dispatch(obj, args, 1);
    }

    /* Fully-qualified method form: $obj->Pkg::method(@args). The leading
     * Pkg specifies WHERE to look up `method` (bypasses normal MRO from
     * the object's blessed package). Most common case is
     * \`$obj->UNIVERSAL::isa("X")\` and \`$obj->UNIVERSAL::can("X")\`,
     * which are sometimes used to test whether a class is a true
     * subclass independent of an isa override. Without this branch
     * perla looked up the literal method name "UNIVERSAL::isa" in the
     * object's class and threw "Can't locate". */
    {
        /* Split on the LAST "::" so multi-level packages resolve correctly:
         * $obj->Type::Tiny::_install_overloads(...) => pkg "Type::Tiny",
         * method "_install_overloads". Splitting on the first "::" (strstr)
         * would wrongly give pkg "Type", method "Tiny::_install_overloads". */
        const char *dcolon = NULL;
        {
            const char *scan = method;
            while ((scan = strstr(scan, "::")) != NULL) {
                dcolon = scan;
                scan += 2;
            }
        }
        if (dcolon && dcolon != method) {
            size_t pkg_len = (size_t)(dcolon - method);
            char pkg_buf[256];
            if (pkg_len < sizeof(pkg_buf)) {
                memcpy(pkg_buf, method, pkg_len);
                pkg_buf[pkg_len] = '\0';
                const char *bare_method = dcolon + 2;
                PerlGlob *g = perla_glob_get(perla_stash_get_or_create(pkg_buf), bare_method);
                if (g && g->slots[PERLA_SLOT_CODE]) {
                    StradaValue *code = g->slots[PERLA_SLOT_CODE];
                    return perla_call_code(code, args);
                }
            }
        }
    }

    /* DBI method names (fetch, execute, prepare, ...) overlap with method
     * names a user might define on their own classes. Gate the DBI
     * intercepts on a blessed-package check: DBI, DBI::*, DBD::*, DBIx::*.
     * Without this, `package Puppy; sub fetch { ... }` was unreachable
     * because the intercept fired regardless of receiver class. */
    int __perla_is_dbi_obj = 0;
    {
        const char *bp = perla_blessed(obj);
        if (bp && (strcmp(bp, "DBI") == 0
                || strncmp(bp, "DBI::", 5) == 0
                || strncmp(bp, "DBD::", 5) == 0
                || strncmp(bp, "DBIx::", 6) == 0)) {
            __perla_is_dbi_obj = 1;
        }
        /* Class-method calls like DBI->connect / DBD::mysql->driver pass
         * the class name as a STR — those need to keep working. */
        if (!__perla_is_dbi_obj && obj && !STRADA_IS_TAGGED_INT(obj) && obj->type == STRADA_STR && obj->value.pv) {
            const char *cn = obj->value.pv;
            if (strcmp(cn, "DBI") == 0
                || strncmp(cn, "DBI::", 5) == 0
                || strncmp(cn, "DBD::", 5) == 0
                || strncmp(cn, "DBIx::", 6) == 0) {
                __perla_is_dbi_obj = 1;
            }
        }
    }

    /* DBI method interception — route DBI calls to our MySQL bridge */
    if (__perla_is_dbi_obj && strcmp(method, "connect") == 0) {
        /* Intercept BOTH DBI->connect("DBI:mysql:...", $user, $pass, $attrs)
         * and $drh->connect("database=...", $user, $pass, $attrs) where
         * $drh is our DBD::mysql driver stub (see "driver" handler below).
         * DBI.pm.o compiles `DBI->connect(...)` to a direct call into
         * perla_sub_DBI_connect which internally calls $drh->connect. We
         * intercept AT the inner $drh->connect so both forms land on
         * perla_dbi_connect. */
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 4) {
            char *class = strada_to_str(av->elements[0]);
            const char *blessed = perla_blessed(av->elements[0]);
            int is_dbi = (strcmp(class, "DBI") == 0);
            int is_drh = (blessed && strcmp(blessed, "DBD::mysql::dr") == 0);
            free(class);
            if (is_dbi || is_drh) {
                char *dsn = strada_to_str(av->elements[1]);
                char *user = strada_to_str(av->elements[2]);
                char *pass = strada_to_str(av->elements[3]);
                /* DBI moves the username/password into the attr hash
                 * (Username/Password) and passes them there, not positionally,
                 * once it has normalised the connect args. When the positional
                 * user/pass come through empty, recover them from the attr
                 * hash (the 4th arg, a hashref). */
                if (av->size >= 5 && ((user && !user[0]) || (pass && !pass[0]))) {
                    StradaValue *attr = av->elements[av->head + 4];
                    if (attr && !STRADA_IS_TAGGED_INT(attr) && attr->type == STRADA_REF)
                        attr = attr->value.rv;
                    if (attr && !STRADA_IS_TAGGED_INT(attr) && attr->type == STRADA_HASH) {
                        StradaValue *u = strada_hash_get(attr->value.hv, "Username");
                        StradaValue *p = strada_hash_get(attr->value.hv, "Password");
                        if (u && (!user || !user[0])) { free(user); user = strada_to_str(u); }
                        if (p && (!pass || !pass[0])) { free(pass); pass = strada_to_str(p); }
                    }
                }
                /* The inner $drh->connect form receives the DSN with the
                 * "dbi:Driver:" prefix already stripped by DBI.pm. Rebuild it
                 * from the driver handle's recorded Name so perla_dbi_connect
                 * can pick the backend (otherwise a SQLite DSN like
                 * "dbname=foo" looks driver-less and defaults to mysql). */
                char *full_dsn = NULL;
                if (is_drh && dsn && strncasecmp(dsn, "dbi:", 4) != 0) {
                    StradaValue *drh = av->elements[0];
                    StradaValue *drhh = (drh && !STRADA_IS_TAGGED_INT(drh) && drh->type == STRADA_REF)
                                        ? drh->value.rv : NULL;
                    StradaValue *nm = (drhh && drhh->type == STRADA_HASH)
                                      ? strada_hash_get(drhh->value.hv, "Name") : NULL;
                    char *nms = nm ? strada_to_str(nm) : NULL;
                    if (nms && *nms) {
                        size_t len = strlen(nms) + strlen(dsn) + 8;
                        full_dsn = malloc(len);
                        snprintf(full_dsn, len, "dbi:%s:%s", nms, dsn);
                    }
                    if (nms) free(nms);
                }
                StradaValue *r = perla_dbi_connect(full_dsn ? full_dsn : dsn, user, pass);
                if (full_dsn) free(full_dsn);
                free(dsn); free(user); free(pass);
                return r;
            }
        }
    }
    /* All DBI-style method intercepts (driver, do, prepare, execute,
     * fetch*, ...) live in this `if (__perla_is_dbi_obj)` block so they
     * don't fire when a user class happens to define a method with the
     * same name (e.g. `package Puppy; sub fetch { ... }`).
     * search/all/first are guarded separately (ResultSet pattern). */
    if (__perla_is_dbi_obj) {
    /* DBI tracing methods — no-ops in perla. DBI.pm's connect post-hook and
     * various paths call $h->trace_msg(...) / DBI->trace(...); return true. */
    if (strcmp(method, "trace_msg") == 0 || strcmp(method, "trace") == 0)
        return STRADA_MAKE_TAGGED_INT(1);
    /* DBD::mysql->driver() — compiled DBI.pm calls this to fetch a driver
     * handle before dispatching connect. The real DBD::mysql loader is
     * XS-based and Perla skips XS modules. Return a minimal blessed
     * stub whose `connect` method falls through to the DBI interception
     * above (via the is_drh check). */
    if (strcmp(method, "driver") == 0) {
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 1) {
            char *class = strada_to_str(av->elements[0]);
            int is_dbd_mysql = (class && (strcmp(class, "DBD::mysql") == 0
                                          || strcmp(class, "DBD::SQLite") == 0
                                          || strcmp(class, "DBD::Pg") == 0));
            free(class);
            if (is_dbd_mysql) {
                StradaValue *h = strada_new_hash();
                /* Record the driver name (strip the "DBD::" prefix) so the
                 * later $drh->connect intercept can reconstruct the full DSN
                 * and route to the right backend (mysql vs SQLite). */
                {
                    char *cn2 = strada_to_str(av->elements[0]);
                    const char *nm = cn2 ? cn2 : "mysql";
                    if (strncmp(nm, "DBD::", 5) == 0) nm += 5;
                    strada_hash_set_take(h->value.hv, "Name", strada_new_str(nm));
                    if (cn2) free(cn2);
                }
                StradaValue *r = strada_ref_create(h);
                perla_bless(r, "DBD::mysql::dr");
                strada_decref(h);
                return r;
            }
        }
    }
    if (strcmp(method, "do") == 0 || strcmp(method, "sql_do") == 0) {
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 2) {
            char *sql = strada_to_str(av->elements[1]);
            StradaValue *r = perla_dbi_do(av->elements[0], sql, args);
            free(sql);
            return r;
        }
    }
    if (strcmp(method, "selectrow_array") == 0) {
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 2) {
            char *sql = strada_to_str(av->elements[1]);
            StradaValue *r = perla_dbi_selectrow_array(av->elements[0], sql, args);
            free(sql);
            return r;
        }
    }
    if (strcmp(method, "selectall_arrayref") == 0) {
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 2) {
            char *sql = strada_to_str(av->elements[1]);
            StradaValue *r = perla_dbi_selectall_arrayref(av->elements[0], sql, args);
            free(sql);
            return r;
        }
    }
    if (strcmp(method, "selectcol_arrayref") == 0) {
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 2) {
            char *sql = strada_to_str(av->elements[1]);
            StradaValue *r = perla_dbi_selectcol_arrayref(av->elements[0], sql, args);
            free(sql);
            return r;
        }
    }
    if (strcmp(method, "prepare") == 0) {
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 2) {
            char *sql = strada_to_str(av->elements[1]);
            StradaValue *r = perla_dbi_prepare(av->elements[0], sql);
            free(sql);
            return r;
        }
    }
    if (strcmp(method, "execute") == 0) {
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 1) {
            return perla_dbi_execute(av->elements[0], args);
        }
    }
    if (strcmp(method, "bind_param") == 0) {
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 1) {
            return perla_dbi_bind_param(av->elements[0], args);
        }
    }
    if (strcmp(method, "bind_columns") == 0) {
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 1) {
            return perla_dbi_bind_columns(av->elements[0], args);
        }
    }
    if (strcmp(method, "fetch") == 0) {
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 1) {
            return perla_dbi_fetch(av->elements[0]);
        }
    }
    if (strcmp(method, "fetchall_arrayref") == 0) {
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 1) {
            return perla_dbi_fetchall_arrayref(av->elements[0], args);
        }
    }
    if (strcmp(method, "finish") == 0) {
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 1) {
            return perla_dbi_finish(av->elements[0]);
        }
    }
    if (strcmp(method, "fetchrow_hashref") == 0) {
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 1) {
            return perla_dbi_fetchrow_hashref(av->elements[0]);
        }
    }
    if (strcmp(method, "fetchrow_array") == 0) {
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 1) {
            return perla_dbi_fetchrow_array(av->elements[0]);
        }
    }
    if (strcmp(method, "disconnect") == 0) {
        StradaArray *av = args ? strada_deref_array(args) : NULL;
        if (av && av->size >= 1) {
            perla_dbi_disconnect(av->elements[0]);
            return STRADA_MAKE_TAGGED_INT(1);
        }
    }
    } /* end if (__perla_is_dbi_obj) */

    /* ORM ResultSet interception: search/all/first → SQL via DBI */
    if (strcmp(method, "search") == 0 || strcmp(method, "all") == 0 || strcmp(method, "first") == 0) {
        const char *bless_pkg = perla_blessed(obj);
        if (bless_pkg && strstr(bless_pkg, "ResultSet")) {
            /* For first(): delegate to ->all and return [0] instead of the
             * compiled `sub first { $_[0]->reset->next }` chain. The
             * compiled `next` walks _construct_results which doesn't run
             * cleanly under perla — `->all` works, `->next` returns undef.
             * Without this, every DBIC `->first` (including bizowie's
             * `network_db('site_mapping')->search(...)->first`) returned
             * undef even though the row existed and `->all` saw it. */
            if (strcmp(method, "first") == 0) {
                PerlGlob *ag = perla_method_resolve(bless_pkg, "all");
                if (ag && ag->slots[PERLA_SLOT_CODE]) {
                    char *afn = strada_to_str(ag->slots[PERLA_SLOT_CODE]);
                    void *afp = dlsym(RTLD_DEFAULT, afn);
                    free(afn);
                    if (afp) {
                        /* Force list context: compiled `all` switches return
                         * shape based on __perla_want_list. Without forcing,
                         * it returns the count (scalar context). */
                        extern int __perla_want_list;
                        int saved_wl = __perla_want_list;
                        __perla_want_list = 1;
                        StradaValue *rv = ((StradaValue*(*)(StradaValue*))afp)(args);
                        __perla_want_list = saved_wl;
                        if (rv && !STRADA_IS_TAGGED_INT(rv) && rv->type == STRADA_ARRAY) {
                            StradaArray *rav = rv->value.av;
                            if (rav && rav->size > 0) {
                                StradaValue *first_elem = rav->elements[rav->head];
                                if (first_elem) strada_incref(first_elem);
                                strada_decref(rv);
                                return first_elem ? first_elem : strada_new_undef();
                            }
                        }
                        if (rv) strada_decref(rv);
                        return strada_new_undef();
                    }
                }
                /* No compiled `all` either — fall through to undef */
                return strada_new_undef();
            }
            /* These are ORM result-set queries — delegate to the compiled Perl method if it exists,
               otherwise return the object (search) or undef (all/first) to avoid crashing on SUPER:: */
            PerlGlob *g = perla_method_resolve(bless_pkg, method);
            if (g && g->slots[PERLA_SLOT_CODE]) {
                char *fn_name = strada_to_str(g->slots[PERLA_SLOT_CODE]);
                void *fn_ptr = dlsym(RTLD_DEFAULT, fn_name);
                free(fn_name);
                if (fn_ptr) {
                    return ((StradaValue*(*)(StradaValue*))fn_ptr)(args);
                }
            }
            /* search returns self (chainable), all/first return empty */
            if (strcmp(method, "search") == 0) return obj;
            return strada_new_undef();
        }
    }

    /* IO::File->new($filename, $mode) and IO::Handle->new — return a
     * STRADA_FILEHANDLE so the IO::Handle-style method dispatch below
     * (print/getline/etc.) can fire. Without these, `IO::File->new(...)`
     * fell through to the SUPER-chain walk and died with "Can't locate
     * object method 'new' via SUPER of 'IO::File'". */
    if (obj && !STRADA_IS_TAGGED_INT(obj) && obj->type == STRADA_STR && obj->value.pv) {
        const char *cn = obj->value.pv;
        /* IO::Socket::INET->new(...) — native TCP-client shim (the .pm builds
         * on core socket()/connect() which perla lacks). Returns a blessed
         * STRADA_FILEHANDLE; the filehandle dispatch below handles its methods. */
        if ((strcmp(cn, "IO::Socket::INET") == 0 || strcmp(cn, "IO::Socket") == 0
             || strcmp(cn, "IO::Socket::INET6") == 0 || strcmp(cn, "IO::Socket::IP") == 0)
            && strcmp(method, "new") == 0) {
            extern StradaValue *perla_io_socket_inet_new(StradaValue *);
            return perla_io_socket_inet_new(args);
        }
        if (strcmp(cn, "IO::Socket::SSL") == 0 && strcmp(method, "new") == 0) {
            return perla_io_socket_ssl_new(args);
        }
        if (strcmp(cn, "IO::File") == 0 || strcmp(cn, "IO::Handle") == 0) {
            if (strcmp(method, "new") == 0) {
                StradaArray *na = args ? strada_deref_array(args) : NULL;
                /* args = [class, filename?, mode?] — class is args[0]. */
                if (na && na->size >= 3) {
                    char *fn = strada_to_str(na->elements[na->head + 1]);
                    char *md = strada_to_str(na->elements[na->head + 2]);
                    StradaValue *sv = strada_open(fn ? fn : "", md ? md : "<");
                    if (fn) free(fn);
                    if (md) free(md);
                    /* strada_open returns STRADA_UNDEF on failure — match
                     * IO::File::new which returns undef in that case. */
                    return sv;
                }
                if (na && na->size == 2) {
                    /* Single-arg form: IO::File->new($filename) — default
                     * to read mode. */
                    char *fn = strada_to_str(na->elements[na->head + 1]);
                    StradaValue *sv = strada_open(fn ? fn : "", "<");
                    if (fn) free(fn);
                    return sv;
                }
                /* No-arg form: IO::File->new — return an unopened handle.
                 * We model it as STRADA_FILEHANDLE with fh=NULL; subsequent
                 * ->open($file, $mode) installs the libc handle. */
                return strada_new_filehandle(NULL);
            }
        }
        /* Math::BigInt->new(...) — native arbitrary-precision constructor.
         * Instance methods and operator overloads resolve via the stash slots
         * registered in perla_bigint_register; only the class constructor
         * needs intercepting here (the string-invocant fall-through would
         * otherwise lazy-load the system .pm and hang). */
        if (strcmp(cn, "Math::BigInt") == 0 && strcmp(method, "new") == 0) {
            return perla_bi_new(args);
        }
    }

    /* Built-in IO::Handle-style method dispatch for STRADA_FILEHANDLE
     * invocants. Perl auto-blesses opened handles into IO::Handle so
     * `$fh->print(...)`, `$fh->close`, etc. work; perla's filehandles
     * are not blessed, so dispatch a small set of methods directly to
     * the runtime helpers. */
    if (obj && !STRADA_IS_TAGGED_INT(obj) && obj->type == STRADA_FILEHANDLE) {
        StradaArray *fha = args ? strada_deref_array(args) : NULL;
        if (strcmp(method, "print") == 0) {
            if (fha) {
                for (size_t i = 1; i < fha->size; i++) {
                    strada_print_fh(fha->elements[fha->head + i], obj);
                }
            }
            return STRADA_MAKE_TAGGED_INT(1);
        }
        if (strcmp(method, "say") == 0) {
            if (fha) {
                for (size_t i = 1; i < fha->size; i++) {
                    strada_print_fh(fha->elements[fha->head + i], obj);
                }
            }
            StradaValue *nl = strada_new_str("\n");
            strada_print_fh(nl, obj);
            strada_decref(nl);
            return STRADA_MAKE_TAGGED_INT(1);
        }
        if (strcmp(method, "printf") == 0) {
            if (fha && fha->size > 1) {
                /* Build a StradaValue* array of [fmt, args...] then call
                 * strada_sprintf_sv_arr to get the formatted string. */
                StradaValue *fmt = fha->elements[fha->head + 1];
                int ac = (int)(fha->size - 2);
                StradaValue *result;
                if (ac == 0) {
                    result = strada_sprintf_sv(fmt, 0);
                } else {
                    /* Re-pack args[2..] into a fresh array for sprintf_sv_arr. */
                    StradaValue *pa = strada_new_array();
                    StradaArray *pav = strada_deref_array(pa);
                    for (size_t i = 2; i < fha->size; i++) {
                        StradaValue *e = fha->elements[fha->head + i];
                        strada_incref(e);
                        strada_array_push_take(pav, e);
                    }
                    result = strada_sprintf_sv_arr(fmt, pa);
                    strada_decref(pa);
                }
                strada_print_fh(result, obj);
                strada_decref(result);
            }
            return STRADA_MAKE_TAGGED_INT(1);
        }
        if (strcmp(method, "close") == 0) {
            strada_close(obj);
            return STRADA_MAKE_TAGGED_INT(1);
        }
        if (strcmp(method, "eof") == 0) {
            return strada_eof(obj);
        }
        if (strcmp(method, "fileno") == 0) {
            return strada_fileno(obj);
        }
        /* IO::Socket::INET server/socket methods. */
        if (strcmp(method, "accept") == 0) {
            extern StradaValue *perla_io_socket_accept(StradaValue *);
            return perla_io_socket_accept(obj);
        }
        if (strcmp(method, "sockport") == 0) {
            extern StradaValue *perla_io_socket_port(StradaValue *, int);
            return perla_io_socket_port(obj, 0);
        }
        if (strcmp(method, "peerport") == 0) {
            extern StradaValue *perla_io_socket_port(StradaValue *, int);
            return perla_io_socket_port(obj, 1);
        }
        if (strcmp(method, "connected") == 0) {
            extern StradaValue *perla_io_socket_port(StradaValue *, int);
            StradaValue *pp = perla_io_socket_port(obj, 1);
            int ok = pp && !STRADA_IS_TAGGED_INT(pp) ? 0 : (pp && STRADA_TAGGED_INT_VAL(pp) > 0);
            if (pp) strada_decref(pp);
            return ok ? STRADA_MAKE_TAGGED_INT(1) : strada_new_undef();
        }
        /* Datagram I/O — $sock->send(MSG [, FLAGS [, TO]]) and
         * $sock->recv(BUF, LEN [, FLAGS]). Used by UDP sockets; recv fills
         * BUF in place (method @_ args alias the caller's variables) and
         * returns the sender's packed sockaddr. */
        if (strcmp(method, "send") == 0 && obj->value.fh) {
            if (!fha || fha->size < 2) return STRADA_MAKE_TAGGED_INT(0);
            int fd = fileno(obj->value.fh);
            StradaValue *msgv = fha->elements[fha->head + 1];
            const char *mp; size_t mlen; char *heap = NULL;
            if (msgv && !STRADA_IS_TAGGED_INT(msgv) && msgv->type == STRADA_STR && msgv->value.pv) {
                mp = msgv->value.pv; mlen = STRADA_STR_BYTELEN(msgv);
            } else {
                heap = strada_to_str(msgv);
                mp = heap ? heap : ""; mlen = heap ? strlen(heap) : 0;
            }
            int flags = fha->size >= 3 ? (int)strada_to_int(fha->elements[fha->head + 2]) : 0;
            ssize_t r;
            if (fha->size >= 4) {
                /* send(SOCKET, MSG, FLAGS, TO) — TO is a packed sockaddr. */
                StradaValue *to = fha->elements[fha->head + 3];
                if (to && !STRADA_IS_TAGGED_INT(to) && to->type == STRADA_STR && to->value.pv) {
                    r = sendto(fd, mp, mlen, flags,
                               (struct sockaddr *)to->value.pv, (socklen_t)STRADA_STR_BYTELEN(to));
                } else {
                    r = send(fd, mp, mlen, flags);
                }
            } else {
                r = send(fd, mp, mlen, flags);
            }
            if (heap) free(heap);
            return STRADA_MAKE_TAGGED_INT(r < 0 ? 0 : (int64_t)r);
        }
        if (strcmp(method, "recv") == 0 && obj->value.fh) {
            if (!fha || fha->size < 3) return strada_new_undef();
            int fd = fileno(obj->value.fh);
            size_t len = (size_t)strada_to_int(fha->elements[fha->head + 2]);
            int flags = fha->size >= 4 ? (int)strada_to_int(fha->elements[fha->head + 3]) : 0;
            char *buf = malloc(len > 0 ? len : 1);
            if (!buf) return strada_new_undef();
            struct sockaddr_storage from;
            socklen_t fl = sizeof(from);
            memset(&from, 0, sizeof(from));
            ssize_t r = recvfrom(fd, buf, len, flags, (struct sockaddr *)&from, &fl);
            StradaValue *data = strada_new_str_len(buf, r < 0 ? 0 : (size_t)r);
            free(buf);
            extern void strada_overwrite_in_place(StradaValue *, StradaValue *);
            strada_overwrite_in_place(fha->elements[fha->head + 1], data);
            strada_decref(data);
            if (r < 0) return strada_new_str("");
            return strada_new_str_len((const char *)&from, fl);
        }
        if (strcmp(method, "autoflush") == 0) {
            if (obj->type == STRADA_FILEHANDLE && obj->value.fh) {
                setvbuf(obj->value.fh, NULL, _IONBF, 0);
            }
            return STRADA_MAKE_TAGGED_INT(1);
        }
        if (strcmp(method, "flush") == 0) {
            if (obj->type == STRADA_FILEHANDLE && obj->value.fh) {
                fflush(obj->value.fh);
            }
            return STRADA_MAKE_TAGGED_INT(1);
        }
        if (strcmp(method, "getline") == 0) {
            return strada_read_line(obj);
        }
        if (strcmp(method, "getlines") == 0) {
            StradaValue *arr = strada_new_array();
            StradaArray *av2 = strada_deref_array(arr);
            while (1) {
                StradaValue *line = strada_read_line(obj);
                if (!line || STRADA_IS_TAGGED_INT(line) || line->type == STRADA_UNDEF) {
                    if (line) strada_decref(line);
                    break;
                }
                strada_array_push_take(av2, line);
            }
            return arr;
        }
        if (strcmp(method, "read") == 0) {
            /* $fh->read($buf, $len) — perla's read is built around the
             * buffer-by-reference idiom that doesn't translate cleanly
             * to method form. Stub returns 0 (EOF). */
            return STRADA_MAKE_TAGGED_INT(0);
        }
        if (strcmp(method, "seek") == 0) {
            if (obj->value.fh && fha && fha->size >= 3) {
                long pos = (long)strada_to_int(fha->elements[fha->head + 1]);
                int whence = (int)strada_to_int(fha->elements[fha->head + 2]);
                int r = fseek(obj->value.fh, pos, whence);
                return STRADA_MAKE_TAGGED_INT(r == 0 ? 1 : 0);
            }
            return STRADA_MAKE_TAGGED_INT(0);
        }
        if (strcmp(method, "tell") == 0) {
            if (obj->value.fh) {
                return STRADA_MAKE_TAGGED_INT((int64_t)ftell(obj->value.fh));
            }
            return STRADA_MAKE_TAGGED_INT(-1);
        }
        if (strcmp(method, "binmode") == 0) {
            /* perla strings are already byte-oriented; binmode is a no-op. */
            return STRADA_MAKE_TAGGED_INT(1);
        }
        if (strcmp(method, "open") == 0) {
            /* $fh->open($file, $mode) — open an unopened handle (typically
             * created via IO::File->new with no args). If the handle is
             * already open, close first. */
            if (fha && fha->size >= 2) {
                if (obj->value.fh) { fclose(obj->value.fh); obj->value.fh = NULL; }
                char *fn = strada_to_str(fha->elements[fha->head + 1]);
                const char *md = "<";
                char *mds = NULL;
                if (fha->size >= 3) {
                    mds = strada_to_str(fha->elements[fha->head + 2]);
                    if (mds) md = mds;
                }
                StradaValue *opened = strada_open(fn ? fn : "", md);
                if (fn) free(fn);
                if (mds) free(mds);
                if (opened && !STRADA_IS_TAGGED_INT(opened) && opened->type == STRADA_FILEHANDLE) {
                    obj->value.fh = opened->value.fh;
                    opened->value.fh = NULL;   /* prevent close on decref */
                    strada_decref(opened);
                    return STRADA_MAKE_TAGGED_INT(1);
                }
                if (opened) strada_decref(opened);
                /* 2-arg form: open($filename) where the filename string
                 * contains the mode prefix, e.g. "< /tmp/foo". */
                if (fha->size == 2) {
                    char *fb = strada_to_str(fha->elements[fha->head + 1]);
                    if (fb) {
                        char *p = fb;
                        const char *m = "<";
                        if (*p == '<' || *p == '>' || *p == '+') {
                            char buf[4] = {0};
                            int bi = 0;
                            while (*p && (*p == '<' || *p == '>' || *p == '+') && bi < 3) {
                                buf[bi++] = *p++;
                            }
                            buf[bi] = '\0';
                            /* skip whitespace after mode */
                            while (*p == ' ' || *p == '\t') p++;
                            static char mode_buf[4];
                            strncpy(mode_buf, buf, 4);
                            m = mode_buf;
                        }
                        StradaValue *o2 = strada_open(p, m);
                        free(fb);
                        if (o2 && !STRADA_IS_TAGGED_INT(o2) && o2->type == STRADA_FILEHANDLE) {
                            obj->value.fh = o2->value.fh;
                            o2->value.fh = NULL;
                            strada_decref(o2);
                            return STRADA_MAKE_TAGGED_INT(1);
                        }
                        if (o2) strada_decref(o2);
                    }
                }
            }
            return STRADA_MAKE_TAGGED_INT(0);
        }
        if (strcmp(method, "blocking") == 0) {
            /* Switching blocking mode at runtime — not supported, but
             * returning 1 (was-blocking) keeps callers happy. */
            return STRADA_MAKE_TAGGED_INT(1);
        }
        if (strcmp(method, "opened") == 0) {
            return STRADA_MAKE_TAGGED_INT(obj->value.fh ? 1 : 0);
        }
        if (strcmp(method, "ungetc") == 0) {
            if (obj->value.fh && fha && fha->size >= 2) {
                int c = (int)strada_to_int(fha->elements[fha->head + 1]);
                int r = ungetc(c, obj->value.fh);
                return STRADA_MAKE_TAGGED_INT(r == EOF ? -1 : r);
            }
            return STRADA_MAKE_TAGGED_INT(-1);
        }
        /* Anything else on a filehandle still trips the unblessed-ref
         * error below. Most user code only reaches for the methods
         * handled here. */
    }

    /* Get class name: either blessed ref or string class name */
    const char *pkg = perla_blessed(obj);
    char *pkg_alloc = NULL;
    if (!pkg) {
        /* Maybe it's a string class name (e.g., "Child"->new()) — but
         * first check if it's actually a bareword that names a sub in
         * the calling package or a globally-known sub. Perl resolves
         * `BAREWORD->method` by trying sub first, then class. Without
         * this, code like `sub Dumper { DumperObject->Values([@_])->Dump }`
         * (Data::Dumper::Concise) tried to look up `Values` in package
         * "DumperObject" and died. */
        if (!STRADA_IS_TAGGED_INT(obj) && obj->type == STRADA_STR && obj->value.pv) {
            const char *bareword = obj->value.pv;
            /* Heuristic: only attempt the sub-resolve when the string
             * looks like a single bareword (no `::`, no whitespace) so
             * we don't accidentally call a sub for a real class name
             * passed as a string. */
            int looks_like_bareword = 1;
            for (const char *p = bareword; *p; p++) {
                char c = *p;
                if (!((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z')
                      || (c >= '0' && c <= '9') || c == '_')) {
                    looks_like_bareword = 0; break;
                }
            }
            if (looks_like_bareword && bareword[0]) {
                /* Try the calling package first, then main, then anywhere. */
                StradaValue *sub_val = NULL;
                const char *caller_pkg = (perla_call_depth >= 1)
                    ? perla_call_stack[perla_call_depth - 1].package : NULL;
                if (caller_pkg && caller_pkg[0]) {
                    sub_val = perla_code_get(caller_pkg, bareword);
                }
                if (!sub_val) {
                    sub_val = perla_code_get("main", bareword);
                }
                if (sub_val) {
                    /* Call the sub with no args, use return value as invocant
                     * for the method dispatch. Caller passed args list with
                     * just the bareword as obj — drop it, the method dispatch
                     * below rebuilds args around the new obj. */
                    StradaValue *empty_args = strada_new_array();
                    StradaValue *new_obj = perla_call_code(sub_val, empty_args);
                    strada_decref(empty_args);
                    if (new_obj) {
                        /* Re-dispatch on the resolved invocant. The args
                         * passed in still reference the old "DumperObject"
                         * string in slot 0 — replace it. */
                        StradaArray *aa = args ? strada_deref_array(args) : NULL;
                        if (aa && aa->size >= 1) {
                            StradaValue *old_first = aa->elements[aa->head];
                            strada_incref(new_obj);
                            aa->elements[aa->head] = new_obj;
                            if (old_first) strada_decref(old_first);
                        }
                        StradaValue *r = perla_method_dispatch(new_obj, method, args);
                        strada_decref(new_obj);
                        return r;
                    }
                }
            }
            pkg_alloc = obj->value.pv;
            pkg = pkg_alloc;
        } else {
            /* Unblessed invocant: a real ref (HASH/ARRAY/REF/CODE) that
             * isn't blessed into any package. Perl dies with
             * "Can't call method "X" on unblessed reference". Match Perl
             * by default so `eval { $href->method }` sets $@; gated by
             * the same PERLA_UNDEF_METHOD_SILENT opt-out as the
             * undef-method case for CPAN init paths that depend on
             * silent-undef-return. */
            if (getenv("PERLA_UNDEF_METHOD_TRACE")) {
                int t = (obj && !STRADA_IS_TAGGED_INT(obj)) ? obj->type : -1;
                const char *caller_pkg = (perla_call_depth >= 1)
                    ? (perla_call_stack[perla_call_depth - 1].package ?: "?") : "?";
                const char *caller_sub = (perla_call_depth >= 1)
                    ? (perla_call_stack[perla_call_depth - 1].subname ?: "?") : "?";
                fprintf(stderr, "[undef-method] method=%s obj_type=%d in %s::%s\n",
                        method, t, caller_pkg, caller_sub);
            }
            if (getenv("PERLA_UNDEF_METHOD_SILENT")) {
                return strada_new_undef();
            }
            char ubuf[256];
            snprintf(ubuf, sizeof(ubuf),
                     "Can't call method \"%s\" on unblessed reference", method);
            strada_throw(ubuf);
            return strada_new_undef();
        }
    }

    /* Native File::Spec: Unix path semantics only. Module's Perl source
     * uses a chain of component classes Perla doesn't handle yet. */
    if (strcmp(pkg, "File::Spec") == 0 || strcmp(pkg, "File::Spec::Unix") == 0) {
        StradaArray *fsa = args ? strada_deref_array(args) : NULL;
        if (strcmp(method, "file_name_is_absolute") == 0) {
            if (fsa && fsa->size >= 2) {
                char *p = strada_to_str(fsa->elements[fsa->head + 1]);
                int abs = (p && p[0] == '/') ? 1 : 0;
                free(p);
                return STRADA_MAKE_TAGGED_INT(abs);
            }
            return STRADA_MAKE_TAGGED_INT(0);
        }
        if (strcmp(method, "catfile") == 0 || strcmp(method, "catdir") == 0
            || strcmp(method, "catpath") == 0) {
            /* Join args[1..] with '/', collapsing doubled separators. */
            size_t start = 1;
            size_t n = fsa ? fsa->size : 0;
            size_t cap = 64;
            char *buf = (char*)malloc(cap);
            size_t len = 0;
            buf[0] = '\0';
            for (size_t i = start; i < n; i++) {
                char *p = strada_to_str(fsa->elements[fsa->head + i]);
                if (!p) continue;
                size_t plen = strlen(p);
                /* Skip empty components except the first (leading /) */
                if (plen == 0) { free(p); continue; }
                size_t need = len + plen + 2;
                if (need > cap) { cap = need * 2; buf = (char*)realloc(buf, cap); }
                if (len > 0 && buf[len - 1] != '/' && p[0] != '/') {
                    buf[len++] = '/';
                }
                /* Avoid doubling slash */
                size_t src = 0;
                if (len > 0 && buf[len - 1] == '/' && p[0] == '/') src = 1;
                memcpy(buf + len, p + src, plen - src);
                len += plen - src;
                buf[len] = '\0';
                free(p);
            }
            StradaValue *r = strada_new_str(buf);
            free(buf);
            return r;
        }
        if (strcmp(method, "splitdir") == 0) {
            StradaValue *out = strada_new_array();
            if (fsa && fsa->size >= 2) {
                char *p = strada_to_str(fsa->elements[fsa->head + 1]);
                if (p) {
                    const char *s = p;
                    const char *tok = s;
                    for (; *s; s++) {
                        if (*s == '/') {
                            size_t len = s - tok;
                            char *part = (char*)malloc(len + 1);
                            memcpy(part, tok, len);
                            part[len] = '\0';
                            strada_array_push_take(strada_deref_array(out), strada_new_str(part));
                            free(part);
                            tok = s + 1;
                        }
                    }
                    strada_array_push_take(strada_deref_array(out), strada_new_str(tok));
                    free(p);
                }
            }
            return out;
        }
        if (strcmp(method, "canonpath") == 0) {
            /* Collapse runs of `/`, strip trailing `/` (unless path is
             * just `/`), and collapse `/./` to `/`. Matches
             * File::Spec::Unix behavior closely enough for the common
             * idioms. Doesn't resolve `..` (intentional — File::Spec
             * doesn't either, since `a/../b` may differ from `b` when
             * `a` is a symlink). */
            if (fsa && fsa->size >= 2) {
                char *raw = strada_to_str(fsa->elements[fsa->head + 1]);
                if (!raw) return strada_new_str("");
                size_t n = strlen(raw);
                char *out = malloc(n + 1);
                size_t oi = 0;
                int last_slash = 0;
                for (size_t i = 0; i < n; i++) {
                    char c = raw[i];
                    if (c == '/') {
                        if (last_slash) continue;  /* collapse */
                        last_slash = 1;
                        out[oi++] = '/';
                    } else {
                        last_slash = 0;
                        out[oi++] = c;
                    }
                }
                out[oi] = '\0';
                /* Second pass: collapse `/./` to `/` and trailing `/.`
                 * to `/`. Operating on the already-slash-deduped string
                 * means we don't need to re-handle multi-slash here. */
                {
                    size_t ri = 0, wi = 0;
                    while (ri < oi) {
                        if (out[ri] == '/' && ri + 1 < oi && out[ri + 1] == '.' &&
                            (ri + 2 == oi || out[ri + 2] == '/')) {
                            /* skip the "/." — leave the next char (either
                             * '/' or end-of-string) to continue normally */
                            ri += 2;
                        } else {
                            out[wi++] = out[ri++];
                        }
                    }
                    oi = wi;
                    out[oi] = '\0';
                }
                /* Strip leading `./` (after the slash-dedup pass this
                 * is the only place a leading `./` could remain). */
                if (oi >= 2 && out[0] == '.' && out[1] == '/') {
                    memmove(out, out + 2, oi - 2);
                    oi -= 2;
                    out[oi] = '\0';
                }
                /* Strip trailing '/' unless the whole result is "/" or empty */
                if (oi > 1 && out[oi - 1] == '/') {
                    oi--;
                    out[oi] = '\0';
                }
                if (oi == 0) {
                    free(out);
                    free(raw);
                    return strada_new_str(".");  /* Perl returns "." for empty */
                }
                free(raw);
                StradaValue *r = strada_new_str(out);
                free(out);
                return r;
            }
            return strada_new_str("");
        }
        if (strcmp(method, "rootdir") == 0) return strada_new_str("/");
        if (strcmp(method, "curdir") == 0) return strada_new_str(".");
        if (strcmp(method, "updir") == 0) return strada_new_str("..");
        if (strcmp(method, "tmpdir") == 0) {
            /* Match Perl's File::Spec::Unix::tmpdir: prefer $TMPDIR, fall
             * back to /tmp. Without this, perla's no-method path landed
             * here returning undef, so File::Temp::tempfile() and other
             * "default location" callers got cwd via implicit cast and
             * tried to create files relative to it. */
            const char *t = getenv("TMPDIR");
            if (t && t[0]) return strada_new_str(t);
            return strada_new_str("/tmp");
        }
        if (strcmp(method, "devnull") == 0) return strada_new_str("/dev/null");
        if (strcmp(method, "path") == 0) {
            /* PATH split on ':'. Returns array (not array ref). */
            const char *p = getenv("PATH");
            StradaValue *out = strada_new_array();
            if (p) {
                const char *tok = p;
                for (const char *s = p; ; s++) {
                    if (*s == ':' || *s == '\0') {
                        size_t l = (size_t)(s - tok);
                        char *part = (char*)malloc(l + 1);
                        memcpy(part, tok, l);
                        part[l] = '\0';
                        strada_array_push_take(strada_deref_array(out), strada_new_str(part));
                        free(part);
                        if (!*s) break;
                        tok = s + 1;
                    }
                }
            }
            return out;
        }
    }

    /* Look up method in class hierarchy */
    PerlGlob *g = perla_method_resolve(pkg, method);
    if (g && g->slots[PERLA_SLOT_CODE]) {
        if (getenv("PERLA_METHOD_DEBUG") && strcmp(method, "import") == 0) {
            StradaValue *slot = g->slots[PERLA_SLOT_CODE];
            const char *kind = "?";
            if (slot && !STRADA_IS_TAGGED_INT(slot)) {
                if (slot->type == STRADA_CPOINTER) kind = "cpointer";
                else if (slot->type == STRADA_CLOSURE) kind = "closure";
                else if (slot->type == STRADA_STR) kind = slot->value.pv ? slot->value.pv : "str";
            }
            fprintf(stderr, "[dispatch] %s->%s resolved to %s\n", pkg, method, kind);
        }
        return perla_call_code(g->slots[PERLA_SLOT_CODE], args);
    }

    /* Fallback: Class::C3::Componentised::load_components.
     *
     * Real CPAN Class::C3::Componentised:
     *   sub load_components {
     *     my $class = shift;
     *     $class->_load_components(
     *       map { /^\+(.*)$/ ? $1 : join('::', $class->component_base_class, $_) }
     *           grep { !/^#/ } @_
     *     );
     *   }
     *   sub _load_components { require each; inject_base(class, @comps); }
     *
     * The Perl source fails to parse under Perla (`*{"${class}::$_"}{CODE}`
     * glob-slot peek at line 141). Without a working load_components,
     * DBIx::Class::Core never pulls in InflateColumn / Row / PK / etc., so
     * every Abe::DB::* model reports "Can't locate object method
     * inflate_column via package …". Emulate the component-loading
     * behavior at dispatch time. */
    if (strcmp(method, "load_components") == 0) {
        StradaArray *la = args ? strada_deref_array(args) : NULL;
        /* args[0] is the invocant (class). Components start at index 1. */
        if (la && la->size >= 2) {
            /* Determine component_base_class: call method on invocant if it
             * has one, else default to the class name itself (DBIx::Class
             * style: DBIx::Class overrides component_base_class to return
             * 'DBIx::Class', and its children inherit that). */
            const char *base = pkg;
            char *base_alloc = NULL;
            PerlGlob *cbg = perla_method_resolve(pkg, "component_base_class");
            if (cbg && cbg->slots[PERLA_SLOT_CODE]) {
                StradaValue *cba = strada_new_array();
                strada_array_push(strada_deref_array(cba), obj);
                StradaValue *cbr = perla_call_code(cbg->slots[PERLA_SLOT_CODE], cba);
                strada_decref(cba);
                if (cbr && !STRADA_IS_TAGGED_INT(cbr) && cbr->type == STRADA_STR && cbr->value.pv && cbr->value.pv[0]) {
                    base_alloc = strdup(cbr->value.pv);
                    base = base_alloc;
                }
                strada_decref(cbr);
            }
            for (size_t i = 1; i < la->size; i++) {
                StradaValue *cv = la->elements[la->head + i];
                if (!cv) continue;
                char *cn = strada_to_str(cv);
                if (!cn || !cn[0]) { free(cn); continue; }
                if (cn[0] == '#') { free(cn); continue; }
                char *full = NULL;
                if (cn[0] == '+') {
                    full = strdup(cn + 1);
                } else {
                    size_t need = strlen(base) + 2 + strlen(cn) + 1;
                    full = (char*)malloc(need);
                    snprintf(full, need, "%s::%s", base, cn);
                }
                /* require the component (no-op if stash already populated) */
                StradaValue *mod_sv = strada_new_str(full);
                perla_require_module(mod_sv);
                strada_decref(mod_sv);
                /* inject as parent of the invocant class */
                perla_isa_push(pkg, full);
                free(full);
                free(cn);
            }
            if (base_alloc) free(base_alloc);
            if (pkg_alloc) { /* keep pkg_alloc logic intact */ }
            return strada_new_undef();
        }
    }

    /* DBIx::Class::ResultSourceProxy: install proxy methods.
     * The CPAN source uses Sub::Quote (`quote_sub`) to dynamically
     * install a list of source-proxy methods at module load time.
     * perla doesn't run the quote_sub installer, so the methods never
     * appear. They're all the same shape:
     *     shift->result_source_instance->METHOD(@_)
     * — proxy the call through to the class's ResultSource. */
    {
        static const char *proxy_methods[] = {
            "source_info", "result_class", "resultset_class",
            "resultset_attributes", "columns", "has_column",
            "remove_column", "remove_columns", "column_info",
            "columns_info", "column_info_from_storage",
            "set_primary_key", "primary_columns", "sequence",
            "add_unique_constraint", "add_unique_constraints",
            "unique_constraints", "unique_constraint_names",
            "unique_constraint_columns", "relationships",
            "relationship_info", "has_relationship",
            NULL
        };
        for (int pi = 0; proxy_methods[pi]; pi++) {
            if (strcmp(method, proxy_methods[pi]) != 0) continue;
            /* $class->result_source_instance — class-data accessor */
            PerlGlob *rsi_g = perla_method_resolve(pkg, "result_source_instance");
            if (!rsi_g || !rsi_g->slots[PERLA_SLOT_CODE]) break;
            StradaValue *rsi_args = strada_new_array();
            strada_array_push(rsi_args->value.av, obj);
            StradaValue *source = perla_call_code(rsi_g->slots[PERLA_SLOT_CODE], rsi_args);
            strada_decref(rsi_args);
            if (!source || STRADA_IS_TAGGED_INT(source) || source->type == STRADA_UNDEF) {
                if (source) strada_decref(source);
                break;
            }
            /* Build new args: (source, @rest_of_original_args). */
            StradaValue *new_args = strada_new_array();
            StradaArray *nav = new_args->value.av;
            strada_array_push(nav, source);
            if (args) {
                StradaArray *oav = strada_deref_array(args);
                if (oav) {
                    for (size_t i = 1; i < oav->size; i++) {
                        StradaValue *v = oav->elements[oav->head + i];
                        if (v) strada_incref(v);
                        strada_array_push_take(nav, v);
                    }
                }
            }
            StradaValue *r = perla_method_dispatch(source, method, new_args);
            strada_decref(source);
            strada_decref(new_args);
            return r;
        }
    }

    /* Not found: try AUTOLOAD */
    StradaValue *result = perla_try_autoload(pkg, method, obj, args);
    if (result) return result;

    /* Silent no-op stubs for DBIx::Class::* register-and-forget methods.
     * Real CPAN DBIx::Class has a deep component chain (Class::C3::Componentised
     * + MRO::Compat + Sub::Quote + Sub::Defer + namespace::clean) that Perla's
     * parser can't handle yet. DBIx::Class-based models call these at init
     * time expecting them to be inherited from DBIx::Class::Core — stubbing
     * as truthy no-ops so registration completes silently without breaking
     * the program.
     *
     * Keep this list tight: only methods we know are register-and-forget. */
    /* Only stub the methods that have NO real implementation reachable
     * via @ISA — for the rest let DBIC's actual code run. Stubbing
     * `table` / `mk_classdata` etc. blocks DBIC's source registration,
     * which then makes `$schema->resultset()` return undef downstream. */
    if (strcmp(method, "set_inc_loaded") == 0
        || strcmp(method, "_skip_namespace_frames") == 0) {
        return STRADA_MAKE_TAGGED_INT(1);
    }

    /* Generic `new` fallback: return a blessed empty hash ref. Without
     * this, `JSON->new`, `Devel::StackTrace->new`, etc. return undef,
     * and the caller's `$obj->method` chain dereferences NULL and
     * segfaults. Blessing the fallback lets subsequent method dispatch
     * hit our soft not-found path instead of crashing. */
    if (strcmp(method, "new") == 0) {
        StradaValue *h = strada_new_hash();
        StradaValue *r = strada_ref_create(h);
        perla_bless(r, pkg);
        strada_decref(h);
        return r;
    }


    /* Suppress errors for:
     * - Moose::Exception and internal MOP classes (not real packages)
     * - `overload::OVERLOAD` dispatch on internal types (YAML::Tag etc.)
     * - import / unimport on packages without a registered stash.
     *   In Perl these are soft calls (`use Module` skips ->import if
     *   Module has no import method). Modules like Date::Calc wrap
     *   `Date::Calc::XS->import(...)` in eval { } expecting it to die
     *   gracefully when XS isn't available; our fprintf bypasses the
     *   eval and floods stderr with noise. Silently no-op instead.
     */
    int suppress = 0;
    if (strncmp(pkg, "Moose::Exception::", 18) == 0) suppress = 1;
    else if (strncmp(pkg, "Moose::Meta::Object::", 21) == 0) suppress = 1;
    else if (strcmp(method, "overload::OVERLOAD") == 0) suppress = 1;
    else if (strcmp(method, "import") == 0 || strcmp(method, "unimport") == 0) {
        /* Perl's `use Module` semantics: if Module has no import method, do
         * nothing silently. Many modules also wrap Module->import(...) in
         * eval { } expecting soft failure. We can't die() cleanly here
         * (not all callers have a try/eval frame), so suppress unconditionally. */
        suppress = 1;
    }
    /* JSON.pm probes for an XS backend via `JSON::Backend::XS->init($v)`;
     * the missing-method failure is exactly the signal it uses to fall
     * back to JSON::PP. Same shape for ::Choose and other modules that
     * conditionally try XS subclasses. */
    else if (strncmp(pkg, "JSON::Backend::", 15) == 0 && strcmp(method, "init") == 0) {
        suppress = 1;
    }
    /* `meta` is Moose's class-introspection accessor. Plenty of CPAN
     * code does `eval { $obj->meta }` to probe for Moose-ness — the
     * miss is the signal that the class isn't Moose, not an error. */
    else if (strcmp(method, "meta") == 0) {
        suppress = 1;
    }
    /* DBIC relationship-helper methods unreachable via @ISA — typically
     * because the target class's @ISA chain didn't link through to
     * DBIx::Class::Relationship::Helpers::* (component chain not fully
     * wired at the time of the call, or the call site is dead code
     * such as an aspirational reference in references=>{...}). Failing
     * silently here matches what bizowie/CPAN code expects: each loud
     * "Can't locate" warn cascades through Bootstrap.pm's $SIG{__DIE__}
     * stack walker, dramatically slowing down model init. Methods
     * return undef as Perl would. */
    else if (strcmp(method, "belongs_to") == 0
             || strcmp(method, "has_many") == 0
             || strcmp(method, "has_one") == 0
             || strcmp(method, "might_have") == 0
             || strcmp(method, "many_to_many") == 0
             || strcmp(method, "add_relationship") == 0
             || strcmp(method, "add_relationship_accessor") == 0) {
        suppress = 1;
    }
    if (!suppress) {
        /* Perl's canonical behavior for missing methods on a real
         * package: die with "Can't locate object method ...". `eval`
         * catches this and puts the message in $@; without an eval the
         * program terminates. Suppressed cases above return undef so
         * legitimate probe patterns (Moose `meta`, JSON XS backend
         * probe, DBIC relationship helpers, `import`/`unimport`) keep
         * working. Env-gated opt-out (PERLA_METHOD_NOT_FOUND_UNDEF=1)
         * restores the old silent-undef-return for code that depends on
         * it. */
        char buf[1024];
        const char *caller_file = "-";
        int caller_line = 0;
        if (perla_call_depth >= 1) {
            caller_file = perla_call_stack[perla_call_depth - 1].file ?: "-";
            /* perla_pending_call_line is the line of the call site
             * the codegen set right before dispatch; the frame's own
             * .line is where THIS frame started, which is wrong for
             * "at FILE line N" diagnostics. Prefer the pending value. */
            if (perla_pending_call_line > 0) {
                caller_line = perla_pending_call_line;
            } else {
                caller_line = perla_call_stack[perla_call_depth - 1].line;
            }
        }
        snprintf(buf, sizeof(buf),
                 "Can't locate object method \"%s\" via package \"%s\" at %s line %d.\n",
                 method, pkg, caller_file, caller_line);
        if (getenv("PERLA_METHOD_NOT_FOUND_UNDEF")) {
            fprintf(stderr, "%s", buf);
            if (getenv("PERLA_UNDEF_METHOD_TRACE")) {
                const char *caller_pkg = (perla_call_depth >= 1)
                    ? (perla_call_stack[perla_call_depth - 1].package ?: "?") : "?";
                const char *caller_sub = (perla_call_depth >= 1)
                    ? (perla_call_stack[perla_call_depth - 1].subname ?: "?") : "?";
                fprintf(stderr, "  in %s::%s\n", caller_pkg, caller_sub);
            }
            return strada_new_undef();
        }
        strada_throw(buf);
    }
    return strada_new_undef();
}

/* $obj->next::method(@args) — dispatch to the *next* package in the
 * MRO that has the *currently-executing* method name.  Routed via
 * perla_method_dispatch when method is literally "next::method" or
 * "maybe::next::method".  The "maybe" variant returns undef silently
 * when no next method exists; the bare form warns.
 *
 * Linearisation here is depth-first @ISA (Perl's default MRO). C3
 * would be more correct for diamond hierarchies but DFS handles the
 * common DBIx::Class case (single inheritance chain). */
StradaValue *perla_next_method_dispatch(StradaValue *obj, StradaValue *args, int maybe) {
    if (perla_call_depth < 1) {
        if (!maybe) fprintf(stderr, "Can't call next::method (no active frame)\n");
        return strada_new_undef();
    }
    const char *cur_pkg = perla_call_stack[perla_call_depth - 1].package;
    const char *cur_method = perla_call_stack[perla_call_depth - 1].subname;
    if (!cur_pkg || !cur_method) {
        if (!maybe) fprintf(stderr, "Can't call next::method (no method context)\n");
        return strada_new_undef();
    }
    const char *obj_pkg = perla_blessed(obj);
    if (!obj_pkg) {
        if (obj && !STRADA_IS_TAGGED_INT(obj) && obj->type == STRADA_STR && obj->value.pv) {
            obj_pkg = obj->value.pv;
        } else {
            obj_pkg = cur_pkg;
        }
    }

    /* next::method ALWAYS uses C3 linearization regardless of the
     * originating package's declared MRO — that's what perl's
     * `next::method` does (see perldoc mro). The package's
     * mro_c3 flag only affects regular method dispatch order, not
     * next::method. Without this, `D->greet` with default-DFS classes
     * in a diamond gave `D>B>A` instead of perl's `D>B>C>A` because
     * we walked obj_stash->isa in DFS order and missed the C3 sibling
     * pickup. Falls back to DFS only if C3 linearisation fails
     * (inconsistent inheritance). */
    enum { MAX_MRO = 64 };
    char *seen[MAX_MRO];
    int seen_n = 0;
    int use_c3 = 1;
    {
        StradaValue *lin_sv = strada_new_array();
        StradaArray *lin_av = strada_deref_array(lin_sv);
        if (perla_mro_c3_linearize(obj_pkg, lin_av) == 0) {
            for (size_t i = 0; i < lin_av->size && seen_n < MAX_MRO; i++) {
                char *p = strada_to_str(lin_av->elements[lin_av->head + i]);
                if (p && p[0]) seen[seen_n++] = p;
                else if (p) free(p);
            }
            strada_decref(lin_sv);
        } else {
            strada_decref(lin_sv);
            use_c3 = 0;  /* C3 failed → fall back to DFS */
        }
    }
    if (!use_c3) {
        char *worklist[MAX_MRO];
        int worklist_n = 0;
        worklist[worklist_n++] = strdup(obj_pkg);
        while (worklist_n > 0) {
            char *cur = worklist[--worklist_n];
            int dup = 0;
            for (int i = 0; i < seen_n; i++) {
                if (strcmp(seen[i], cur) == 0) { dup = 1; break; }
            }
            if (dup) { free(cur); continue; }
            if (seen_n >= MAX_MRO) { free(cur); break; }
            seen[seen_n++] = cur;
            PerlStash *st = perla_stash_get(cur);
            if (st && st->isa && st->isa->value.av) {
                StradaArray *isa = st->isa->value.av;
                /* Push parents in reverse so first parent is processed first.
                 * Use head offset (deque ring-buffer). */
                for (size_t i = isa->size; i-- > 0; ) {
                    if (worklist_n >= MAX_MRO) break;
                    char *p = strada_to_str(isa->elements[isa->head + i]);
                    if (p && p[0]) worklist[worklist_n++] = p;
                    else if (p) free(p);
                }
            }
        }
        for (int i = 0; i < worklist_n; i++) free(worklist[i]);
    }

    int idx = -1;
    for (int i = 0; i < seen_n; i++) {
        if (strcmp(seen[i], cur_pkg) == 0) { idx = i; break; }
    }

    StradaValue *result = NULL;
    if (idx >= 0) {
        for (int i = idx + 1; i < seen_n; i++) {
            PerlGlob *g = perla_method_resolve(seen[i], cur_method);
            if (g && g->slots[PERLA_SLOT_CODE]) {
                result = perla_call_code(g->slots[PERLA_SLOT_CODE], args);
                break;
            }
        }
    }

    for (int i = 0; i < seen_n; i++) free(seen[i]);

    if (!result) {
        if (!maybe) {
            fprintf(stderr, "Can't locate next::method for \"%s\" via \"%s\"\n",
                    cur_method, cur_pkg);
        }
        return strada_new_undef();
    }
    return result;
}

StradaValue *perla_super_dispatch(StradaValue *obj, const char *current_pkg, const char *method, StradaValue *args) {
    if (!current_pkg || !method) return strada_new_undef();

    /* Walk @ISA of current_pkg to find the parent, then resolve from there.
     * When @ISA is empty, every class still inherits from UNIVERSAL — Perl
     * treats `$self->SUPER::can(...)` etc. as resolving against UNIVERSAL
     * after exhausting explicit parents. HTTP::Message's own
     * `sub can { ... $self->SUPER::can($method) ... }` was breaking here:
     * HTTP::Message has no explicit @ISA, perla returned undef without
     * trying UNIVERSAL, and LWP's caller saw `$req->can('headers')` come
     * back false → croaked with "You need a request object, not a
     * HTTP::Request object". */
    PerlStash *stash = perla_stash_get(current_pkg);
    if (!stash || !stash->isa) {
        if (strcmp(current_pkg, "UNIVERSAL") != 0) {
            PerlGlob *ug = perla_method_resolve("UNIVERSAL", method);
            if (ug && ug->slots[PERLA_SLOT_CODE]) {
                return perla_call_code(ug->slots[PERLA_SLOT_CODE], args);
            }
        }
        return strada_new_undef();
    }

    StradaArray *isa = stash->isa->value.av;
    if (!isa) return strada_new_undef();

    /* Try each parent in @ISA order — use head offset (deque). */
    for (size_t i = 0; i < isa->size; i++) {
        StradaValue *parent_sv = isa->elements[isa->head + i];
        if (!parent_sv) continue;
        char *parent = strada_to_str(parent_sv);
        PerlGlob *g = perla_method_resolve(parent, method);
        free(parent);
        if (g && g->slots[PERLA_SLOT_CODE]) {
            return perla_call_code(g->slots[PERLA_SLOT_CODE], args);
        }
    }

    /* Exhausted @ISA — fall through to UNIVERSAL (can/isa/DOES). */
    if (strcmp(current_pkg, "UNIVERSAL") != 0) {
        PerlGlob *ug = perla_method_resolve("UNIVERSAL", method);
        if (ug && ug->slots[PERLA_SLOT_CODE]) {
            return perla_call_code(ug->slots[PERLA_SLOT_CODE], args);
        }
    }

    fprintf(stderr, "Can't locate object method \"%s\" via SUPER of \"%s\"\n", method, current_pkg);
    return strada_new_undef();
}

/* ===== Custom Sort ===== */

static void *g_sort_cmp_fn = NULL;

static int perla_sort_qsort_cmp(const void *a, const void *b) {
    StradaValue *va = *(StradaValue**)a;
    StradaValue *vb = *(StradaValue**)b;
    perla_cmp_func fn = (perla_cmp_func)g_sort_cmp_fn;

    /* Reuse a single 2-element args array across comparisons instead of
     * mallocing one per comparison. The elements are borrowed (no incref) —
     * va/vb live in the array being sorted, which outlives the sort. The
     * comparator reads them at entry, so a nested sort inside the block is
     * still safe. Not reused recursively, but g_sort_cmp_fn already makes
     * this path non-reentrant per comparator. */
    static StradaValue *g_sort_args = NULL;
    if (!g_sort_args) {
        g_sort_args = strada_new_array();
        strada_array_push_take(g_sort_args->value.av, strada_new_undef());
        strada_array_push_take(g_sort_args->value.av, strada_new_undef());
    }
    StradaArray *aa = g_sort_args->value.av;
    aa->elements[aa->head + 0] = va;
    aa->elements[aa->head + 1] = vb;

    StradaValue *result = fn(g_sort_args);
    int cmp = result ? (int)strada_to_num(result) : 0;
    /* spaceship/cmp yield immortal tagged ints; a heap result is owned. */
    if (result && !STRADA_IS_TAGGED_INT(result)) strada_decref(result);
    return cmp;
}

/* Native sort fast path for the canonical comparators the codegen detects:
 * `{ $a <=> $b }` (0), `{ $b <=> $a }` (1), `{ $a cmp $b }` (2),
 * `{ $b cmp $a }` (3). These avoid a per-comparison Perl call entirely. */
static int perla_cmp_num_asc(const void *a, const void *b) {
    double da = strada_to_num(*(StradaValue * const *)a);
    double db = strada_to_num(*(StradaValue * const *)b);
    return (da > db) - (da < db);
}
static int perla_cmp_num_desc(const void *a, const void *b) { return perla_cmp_num_asc(b, a); }
static int perla_cmp_str_asc(const void *a, const void *b) {
    char *sa = strada_to_str(*(StradaValue * const *)a);
    char *sb = strada_to_str(*(StradaValue * const *)b);
    int r = strcmp(sa ? sa : "", sb ? sb : "");
    if (sa) free(sa); if (sb) free(sb);
    return r;
}
static int perla_cmp_str_desc(const void *a, const void *b) { return perla_cmp_str_asc(b, a); }
StradaValue* perla_sort_native(StradaValue *arr, int mode) {
    if (!arr || STRADA_IS_TAGGED_INT(arr)) return arr;
    StradaArray *av = NULL;
    if (arr->type == STRADA_ARRAY) av = arr->value.av;
    else if (arr->type == STRADA_REF && arr->value.rv && arr->value.rv->type == STRADA_ARRAY)
        av = arr->value.rv->value.av;
    if (!av) return strada_new_array();
    StradaValue *result = strada_new_array();
    for (size_t i = 0; i < av->size; i++) {
        StradaValue *e = av->elements[av->head + i];
        if (e) strada_incref(e);
        strada_array_push_take(result->value.av, e);
    }
    if (result->value.av->size > 1) {
        int (*cmp)(const void *, const void *) =
            mode == 1 ? perla_cmp_num_desc :
            mode == 2 ? perla_cmp_str_asc  :
            mode == 3 ? perla_cmp_str_desc : perla_cmp_num_asc;
        qsort(result->value.av->elements + result->value.av->head,
              result->value.av->size, sizeof(StradaValue*), cmp);
    }
    return result;
}

StradaValue* perla_sort_custom(StradaValue *arr, void *cmp_fn) {
    if (!arr || STRADA_IS_TAGGED_INT(arr)) return arr;

    StradaArray *av = NULL;
    if (arr->type == STRADA_ARRAY) av = arr->value.av;
    else if (arr->type == STRADA_REF && arr->value.rv && arr->value.rv->type == STRADA_ARRAY)
        av = arr->value.rv->value.av;
    if (!av || av->size == 0) return arr;

    /* Copy array for sorting */
    StradaValue *result = strada_new_array();
    for (size_t i = 0; i < av->size; i++) {
        strada_array_push(result->value.av, av->elements[av->head + i]);
    }

    /* Sort using qsort with the custom comparator */
    g_sort_cmp_fn = cmp_fn;
    qsort(result->value.av->elements + result->value.av->head,
          result->value.av->size,
          sizeof(StradaValue*),
          perla_sort_qsort_cmp);

    return result;
}

/* ===== Special Variables ===== */

/* Perl special variables mapped to glob names in main:: */
static struct { const char *perl_name; const char *glob_name; } special_vars[] = {
    { "$_",  "_" },
    { "$!",  "!" },        /* errno */
    { "$@",  "@" },        /* eval error */
    { "$/",  "/" },        /* input record separator */
    { "$\\", "\\" },       /* output record separator */
    { "$,",  "," },        /* output field separator */
    { "$\"", "\"" },       /* list separator */
    { "$;",  ";" },        /* subscript separator */
    { "$&",  "&" },        /* match string */
    { "$`",  "`" },        /* prematch */
    { "$'",  "'" },        /* postmatch */
    { "$+",  "+" },        /* last bracket match */
    { "$0",  "0" },        /* program name */
    { "$$",  "$" },        /* PID */
    { NULL, NULL }
};

void perla_init_special_vars(void) {
    if (!g_main_stash) return;

    /* $/ = "\n" (default input record separator) */
    PerlGlob *g = perla_glob_get_or_create(g_main_stash, "/");
    g->slots[PERLA_SLOT_SCALAR] = strada_new_str("\n");

    /* $\ = undef (no output record separator by default) */

    /* $, = undef (no output field separator by default) */

    /* $" = " " (default list separator) */
    g = perla_glob_get_or_create(g_main_stash, "\"");
    g->slots[PERLA_SLOT_SCALAR] = strada_new_str(" ");

    /* $; = "\x1c" (subscript separator) */
    g = perla_glob_get_or_create(g_main_stash, ";");
    g->slots[PERLA_SLOT_SCALAR] = strada_new_str("\x1c");

    /* $0 = program name (set later by main) */

    /* $$ = PID */
    g = perla_glob_get_or_create(g_main_stash, "$");
    g->slots[PERLA_SLOT_SCALAR] = strada_new_int(getpid());
}

StradaValue *perla_special_get(const char *name) {
    /* Look up in main:: stash */
    return perla_scalar_get("main", name);
}

void perla_special_set(const char *name, StradaValue *val) {
    perla_scalar_set("main", name, val);
}

/* ===== Dynamic Glob Assignment ===== */

/* *{"Pkg::name"} = value — assign to a glob using a runtime string name */
StradaValue *perla_glob_assign_dynamic_pkg(StradaValue *name_sv, StradaValue *val, const char *default_pkg) {
    if (!name_sv || STRADA_IS_TAGGED_INT(name_sv) || !val) return val;

    char *fullname = strada_to_str(name_sv);
    if (!fullname || !fullname[0]) { free(fullname); return val; }

    /* Split "Pkg::name" into pkg and name */
    char *last_sep = NULL;
    for (char *p = fullname; *p; p++) {
        if (p[0] == ':' && p[1] == ':') last_sep = p;
    }

    const char *pkg = (default_pkg && default_pkg[0]) ? default_pkg : "main";
    char *name = fullname;
    char *pkg_buf = NULL;
    if (last_sep) {
        pkg_buf = strndup(fullname, last_sep - fullname);
        pkg = pkg_buf;
        name = last_sep + 2;
    }

    PerlGlob *glob = perla_glob_get_or_create(perla_stash_get_or_create(pkg), name);
    perla_glob_assign(glob, val);

    if (pkg_buf) free(pkg_buf);
    free(fullname);
    return val;
}

StradaValue *perla_glob_assign_dynamic(StradaValue *name_sv, StradaValue *val) {
    return perla_glob_assign_dynamic_pkg(name_sv, val, "main");
}

/* ===== eval STRING runtime ===== */

/* Global: path to perla binary (set at startup) */
static char g_perla_path[1024] = "";
static char g_strada_dir[1024] = "";
static int g_eval_counter = 0;

void perla_eval_set_paths(const char *perla_path, const char *strada_dir) {
    if (perla_path) strncpy(g_perla_path, perla_path, sizeof(g_perla_path) - 1);
    if (strada_dir) strncpy(g_strada_dir, strada_dir, sizeof(g_strada_dir) - 1);
}

/* ===== @INC-like search paths for runtime `require` =====
 *
 * Populated from perla.conf's lib_path at program start via
 * perla_require_set_paths. perla_require_module iterates this list
 * when it has no pm_path yet. The defaults (used if nothing was ever
 * set) reflect a standard Perl install layout; they're NOT
 * distribution-specific — callers should set the real paths via
 * perla.conf instead of relying on these. */
char **g_require_paths = NULL;
size_t g_require_path_count = 0;
static int g_require_paths_set = 0;

static void perla_require_paths_free(void) {
    if (!g_require_paths) return;
    for (size_t i = 0; i < g_require_path_count; i++) free(g_require_paths[i]);
    free(g_require_paths);
    g_require_paths = NULL;
    g_require_path_count = 0;
}

/* Read a perla.conf file and return its lib_path value (malloc'd), or NULL.
 * Caller frees. */
static char *perla_conf_read_lib_path(const char *path) {
    FILE *f = fopen(path, "r");
    if (!f) return NULL;
    char line[2048];
    char *result = NULL;
    while (fgets(line, sizeof(line), f)) {
        char *p = line;
        while (*p == ' ' || *p == '\t') p++;
        if (*p == '#' || *p == '\n' || *p == '\0') continue;
        if (strncmp(p, "lib_path", 8) == 0) {
            p += 8;
            while (*p == ' ' || *p == '\t' || *p == '=') p++;
            size_t len = strlen(p);
            while (len > 0 && (p[len-1] == '\n' || p[len-1] == '\r' || p[len-1] == ' ' || p[len-1] == '\t')) len--;
            p[len] = '\0';
            if (len > 0) result = strdup(p);
            break;
        }
    }
    fclose(f);
    return result;
}

/* Append paths from $HOME/.perla/perla.conf and /etc/perla.conf to
 * g_require_paths (if not already present). Called from
 * perla_require_set_paths so the baked compile-time paths are augmented
 * with user- and system-wide runtime overrides without bloating compile. */
static void perla_require_merge_conf_paths(void) {
    char conf_paths[3][1024];
    int n_conf = 0;
    const char *home = getenv("HOME");
    if (home && home[0]) {
        snprintf(conf_paths[n_conf], sizeof(conf_paths[0]),
                 "%s/.perla/perla.conf", home);
        n_conf++;
    }
    snprintf(conf_paths[n_conf++], sizeof(conf_paths[0]), "/etc/perla.conf");
    const char *prefix = getenv("PERLA_PREFIX");
    if (prefix && prefix[0] && n_conf < 3) {
        snprintf(conf_paths[n_conf], sizeof(conf_paths[0]),
                 "%s/etc/perla.conf", prefix);
        n_conf++;
    }
    for (int ci = 0; ci < n_conf; ci++) {
        char *val = perla_conf_read_lib_path(conf_paths[ci]);
        if (!val) continue;
        /* Split on ':' and append each to g_require_paths if not duplicate */
        const char *s = val;
        while (*s) {
            const char *e = strchr(s, ':');
            size_t len = e ? (size_t)(e - s) : strlen(s);
            if (len > 0) {
                int dup_found = 0;
                for (size_t i = 0; i < g_require_path_count; i++) {
                    if (strlen(g_require_paths[i]) == len &&
                        strncmp(g_require_paths[i], s, len) == 0) {
                        dup_found = 1;
                        break;
                    }
                }
                if (!dup_found) {
                    g_require_paths = (char**)realloc(g_require_paths,
                        (g_require_path_count + 1) * sizeof(char*));
                    g_require_paths[g_require_path_count] = strndup(s, len);
                    g_require_path_count++;
                }
            }
            if (!e) break;
            s = e + 1;
        }
        free(val);
    }
}

/* Add a single path to g_require_paths (checked for duplicates). */
static void perla_require_push_path_raw(const char *path, size_t len) {
    if (len == 0) return;
    for (size_t i = 0; i < g_require_path_count; i++) {
        if (strlen(g_require_paths[i]) == len &&
            strncmp(g_require_paths[i], path, len) == 0) {
            return;  /* dup */
        }
    }
    g_require_paths = (char**)realloc(g_require_paths,
        (g_require_path_count + 1) * sizeof(char*));
    g_require_paths[g_require_path_count++] = strndup(path, len);
}

/* Add a path plus its archlib siblings (if they exist) — mirrors Perl's
 * automatic @INC expansion where `use lib "/foo"` also promotes
 * /foo/$archname into @INC so XS-style modules living under
 * /foo/x86_64-linux/Module/Name.pm are found. Without this,
 * `require Date::Calc::XS` fails to locate
 * /opt/bzperl/lib/site_perl/5.42.0/x86_64-linux/Date/Calc/XS.pm even
 * though /opt/bzperl/lib/site_perl/5.42.0 is on the path. */
static void perla_require_push_path_with_archlibs(const char *path, size_t len) {
    perla_require_push_path_raw(path, len);
    /* Known archname suffixes on this box. Kept short and explicit rather
     * than shelling out to `perl -V` at startup — those are the two
     * layouts actually present in /opt/bzperl and /usr/lib/perl5. */
    static const char *archnames[] = {
        "x86_64-linux",
        "x86_64-linux-gnu-thread-multi",
        NULL
    };
    char buf[2048];
    for (int i = 0; archnames[i]; i++) {
        if (len + 1 + strlen(archnames[i]) + 1 > sizeof(buf)) continue;
        memcpy(buf, path, len);
        buf[len] = '/';
        strcpy(buf + len + 1, archnames[i]);
        struct stat st;
        if (stat(buf, &st) == 0 && S_ISDIR(st.st_mode)) {
            perla_require_push_path_raw(buf, strlen(buf));
        }
    }
}

void perla_require_set_paths(const char *colon_paths) {
    perla_require_paths_free();
    g_require_paths_set = 1;
    if (colon_paths && colon_paths[0]) {
        const char *s = colon_paths;
        while (*s) {
            const char *e = strchr(s, ':');
            size_t len = e ? (size_t)(e - s) : strlen(s);
            if (len > 0) {
                perla_require_push_path_with_archlibs(s, len);
            }
            if (!e) break;
            s = e + 1;
        }
    }
    /* After installing the baked (compile-time) paths, also merge in any
     * lib_path entries from ~/.perla/perla.conf and /etc/perla.conf. This
     * lets users add runtime-only search paths (e.g. /opt/bzperl/lib/...)
     * without bloating compile time by putting source trees on the
     * compile-time search path. */
    perla_require_merge_conf_paths();
}

/* Install a sensible default if nothing was set explicitly.
 * Called lazily from perla_require_module so a program that doesn't
 * ever call perla_require_set_paths still has something to search. */
void perla_require_ensure_paths(void) {
    if (g_require_paths_set) return;
    g_require_paths_set = 1;
    /* Try: PERLA_LIB env, then /etc/perla.conf's lib_path, then
     * perl -V @INC (if available via PERLA_PERL). Final fallback is
     * the empty list — `require` then only searches PERL5LIB + "lib"
     * + ".". Keeping this simple so bzperl-specific paths stop being
     * baked into the binary. */
    const char *env = getenv("PERLA_LIB");
    if (env && env[0]) { perla_require_set_paths(env); return; }
    /* /etc/perla.conf — read lib_path line if present */
    FILE *f = fopen("/etc/perla.conf", "r");
    if (f) {
        char line[2048];
        while (fgets(line, sizeof(line), f)) {
            char *p = line;
            while (*p == ' ' || *p == '\t') p++;
            if (*p == '#' || *p == '\n' || *p == '\0') continue;
            if (strncmp(p, "lib_path", 8) == 0) {
                p += 8;
                while (*p == ' ' || *p == '\t' || *p == '=') p++;
                size_t len = strlen(p);
                while (len > 0 && (p[len-1] == '\n' || p[len-1] == '\r' || p[len-1] == ' ' || p[len-1] == '\t')) len--;
                p[len] = '\0';
                if (len > 0) { fclose(f); perla_require_set_paths(p); return; }
            }
        }
        fclose(f);
    }
    /* No explicit config — leave paths empty. */
}

/* Set by perla_eval_string_with_args before invoking the eval body, so
 * the eval'd code's $_[N] sees the calling sub's @_. Read once and
 * cleared by the body invocation in perla_eval_string. Single-threaded
 * eval STRING is fine; if perla ever grows MT eval STRING this needs
 * thread-locality. */
StradaValue *perla_eval_caller_args = NULL;

StradaValue *perla_eval_string_with_args(StradaValue *code_sv, const char *current_pkg, StradaValue *caller_args) {
    perla_eval_caller_args = caller_args;
    return perla_eval_string(code_sv, current_pkg);
}

/* eval STRING in Perl shares the calling sub's lexicals — code inside
 * reads/writes the same `my $x` the caller declared. perla compiles
 * the eval body in a separate .pm.so so it can't close over them; we
 * pass a captures hashref of current values. The body's wrapper sub
 * unpacks each capture into a my-shadow at entry and writes back at
 * exit. Codegen at the eval call site mirrors the writeback by
 * pulling caps->{name} back into v_name after this returns. */
StradaValue *perla_eval_caps_pending = NULL;

StradaValue *perla_get_eval_caps(StradaValue *args) {
    (void)args;
    if (perla_eval_caps_pending) {
        StradaValue *r = perla_eval_caps_pending;
        strada_incref(r);
        return strada_new_ref_take(r, '%');
    }
    return strada_new_ref_take(strada_new_hash(), '%');
}

StradaValue *perla_eval_string_with_lexicals(StradaValue *code_sv, const char *current_pkg,
                                             StradaValue *caller_args, StradaValue *caps) {
    perla_eval_caller_args = caller_args;
    perla_eval_caps_pending = caps;
    StradaValue *r = perla_eval_string(code_sv, current_pkg);
    perla_eval_caps_pending = NULL;
    return r;
}

/* Returns 1 if the eval code needs a trailing ; appended before being
 * wrapped in `do { ... }`. Real Perl allows the last statement in a block
 * to omit its terminator, but perla's parser doesn't, so an eval body
 * like `no Foo()` (no trailing ;) leaves the inner do-block parser hitting
 * `}` unexpectedly. We append a ; unless the code already ends with one
 * of `;`, `}`, `{`, or just whitespace. Trailing `}` from a block stmt
 * (sub def, if/while/for block, etc.) is its own legal terminator. */
static int perla_eval_code_needs_semi(const char *code) {
    if (!code) return 0;
    size_t n = strlen(code);
    while (n > 0 && (code[n-1] == ' ' || code[n-1] == '\t'
                  || code[n-1] == '\n' || code[n-1] == '\r')) n--;
    if (n == 0) return 0;
    char c = code[n-1];
    if (c == ';' || c == '}' || c == '{') return 0;
    return 1;
}

StradaValue *perla_eval_string(StradaValue *code_sv, const char *current_pkg) {
    if (!code_sv || STRADA_IS_TAGGED_INT(code_sv)) {
        return strada_new_undef();
    }

    char *code = strada_to_str(code_sv);
    if (!code || !code[0]) {
        free(code);
        return strada_new_undef();
    }
    if (perla_debug_mode()) {
        char preview[80];
        snprintf(preview, sizeof(preview), "%.76s", code);
        fprintf(stderr, "[eval] pkg=%s code=%s%s\n", current_pkg, preview, strlen(code) > 76 ? "..." : "");
    }

    /* Fast path: `package X; use Y;` or `package X; use Y (@list)` —
     * a common idiom in module loaders like aliased.pm and Module::Load.
     * Each call would otherwise fork `perla -M` to compile a tiny .pm
     * just to trigger a perla_require_module on Y. With cyclic uses
     * (use aliased 'Sibling' inside Pkg whose .pm uses Sibling which
     * uses Pkg), the fork chain recurses indefinitely and never
     * terminates during a cold-cache rebuild. Short-circuit here:
     * detect the pattern, call perla_require_module directly, and
     * return immediately. The package context is informational only —
     * the runtime require sets up the stash and import path the same
     * way the eval-via-fork would. */
    {
        const char *p = code;
        while (*p == ' ' || *p == '\t' || *p == '\n') p++;
        if (strncmp(p, "package ", 8) == 0) {
            p += 8;
            while (*p == ' ' || *p == '\t') p++;
            const char *pkg_start = p;
            while (*p && *p != ' ' && *p != '\t' && *p != ';' && *p != '\n') p++;
            const char *pkg_end = p;
            while (*p == ' ' || *p == '\t') p++;
            if (*p == ';') {
                p++;
                while (*p == ' ' || *p == '\t' || *p == '\n') p++;
                if (strncmp(p, "use ", 4) == 0) {
                    p += 4;
                    while (*p == ' ' || *p == '\t') p++;
                    const char *mod_start = p;
                    while (*p && *p != ' ' && *p != '\t' && *p != ';' && *p != '(' && *p != '\n') p++;
                    const char *mod_end = p;
                    /* Skip optional rest of statement; accept anything
                     * up to the trailing `;` plus optional whitespace. */
                    while (*p && *p != '\n') p++;
                    while (*p == ' ' || *p == '\t' || *p == '\n') p++;
                    if (!*p && pkg_end > pkg_start && mod_end > mod_start) {
                        size_t mod_len = (size_t)(mod_end - mod_start);
                        if (mod_len < 256) {
                            char mod_buf[256];
                            memcpy(mod_buf, mod_start, mod_len);
                            mod_buf[mod_len] = 0;
                            if (perla_debug_mode()) fprintf(stderr, "[eval] fast-path require %s\n", mod_buf);
                            StradaValue *mod_sv = strada_new_str(mod_buf);
                            StradaValue *r = perla_require_module(mod_sv);
                            strada_decref(mod_sv);
                            extern StradaValue *perla_eval_error;
                            if (perla_eval_error) strada_decref(perla_eval_error);
                            perla_eval_error = strada_new_str("");
                            strada_incref(perla_eval_error);
                            free(code);
                            return r ? r : strada_new_str("1");
                        }
                    }
                }
            }
        }
    }

    /* Generate unique temp file names */
    int eval_id = __sync_add_and_fetch(&g_eval_counter, 1);
    pid_t pid = getpid();
    char pm_path[256], so_path[256];
    snprintf(pm_path, sizeof(pm_path), "/tmp/perla_eval_%d_%d.pm", (int)pid, eval_id);
    snprintf(so_path, sizeof(so_path), "/tmp/perla_eval_%d_%d.pm.so", (int)pid, eval_id);

    /* Write the eval code to a temp .pm file */
    const char *pkg = current_pkg ? current_pkg : "main";
    FILE *f = fopen(pm_path, "w");
    if (!f) {
        /* Set $@ */
        extern StradaValue *perla_eval_error;
        if (perla_eval_error) strada_decref(perla_eval_error);
        perla_eval_error = strada_new_str("eval: cannot write temp file");
        strada_incref(perla_eval_error);
        free(code);
        return strada_new_undef();
    }
    /* Wrap the user's code in a sub so we can both (a) make `return` work
     * inside the eval and (b) capture the last-expression value to return
     * to the caller. The sub name is unique per eval invocation and we'll
     * dlsym + call it below. When perla_eval_caps_pending is set, also
     * emit a prelude/postlude that shares lexicals with the caller. */
    fprintf(f, "package %s;\n", pkg);
    fprintf(f, "sub __perla_eval_body_%d_%d {\n", (int)pid, eval_id);
    if (perla_eval_caps_pending) {
        StradaHash *cap_hv = strada_deref_hash(perla_eval_caps_pending);
        StradaArray *keys = cap_hv ? strada_hash_keys(cap_hv) : NULL;
        size_t nk = keys ? keys->size : 0;
        if (nk > 0) {
            fprintf(f, "  my $__caps = main::perla_get_eval_caps();\n");
            for (size_t i = 0; i < nk; i++) {
                StradaValue *kv = keys->elements[keys->head + i];
                char *kn = strada_to_str(kv);
                if (!kn || !kn[0]) { free(kn); continue; }
                fprintf(f, "  my $%s = $__caps->{%s};\n", kn, kn);
                free(kn);
            }
            /* Capture user code's value with context-matching do-block:
             * outer scalar context → my $ = do {...}, outer list →
             * my @ = do {...}. Without this branching, `my $x = eval
             * "ctx()"` (which uses with-lexicals path because of any
             * captured my-vars) evaluates ctx() in list context. */
            fprintf(f, "  if (wantarray) {\n");
            fprintf(f, "    my @__perla_eval_rv = do {\n");
            fprintf(f, "%s%s\n", code, perla_eval_code_needs_semi(code) ? ";" : "");
            fprintf(f, "    };\n");
            for (size_t i = 0; i < nk; i++) {
                StradaValue *kv = keys->elements[keys->head + i];
                char *kn = strada_to_str(kv);
                if (!kn || !kn[0]) { free(kn); continue; }
                fprintf(f, "    $__caps->{%s} = $%s;\n", kn, kn);
                free(kn);
            }
            fprintf(f, "    return @__perla_eval_rv;\n");
            fprintf(f, "  } else {\n");
            fprintf(f, "    my $__perla_eval_rv = do {\n");
            fprintf(f, "%s%s\n", code, perla_eval_code_needs_semi(code) ? ";" : "");
            fprintf(f, "    };\n");
            for (size_t i = 0; i < nk; i++) {
                StradaValue *kv = keys->elements[keys->head + i];
                char *kn = strada_to_str(kv);
                if (!kn || !kn[0]) { free(kn); continue; }
                fprintf(f, "    $__caps->{%s} = $%s;\n", kn, kn);
                free(kn);
            }
            fprintf(f, "    return $__perla_eval_rv;\n");
            fprintf(f, "  }\n");
        } else {
            fprintf(f, "%s%s\n", code, perla_eval_code_needs_semi(code) ? ";" : "");
        }
        if (keys) strada_free_array(keys);
    } else {
        /* Wrap user code in `do { ... }`. The context of the do-block
         * comes from its LHS — using \`my @ = do {...}\` forces list
         * context, which is wrong when the caller wants scalar (e.g.
         * \`my \$x = eval "ctx()"\` should evaluate ctx() in scalar
         * context). Use a wantarray-conditional to give the user code
         * the right context, mirroring the wrapper's outer wantarray. */
        fprintf(f, "  if (wantarray) {\n");
        fprintf(f, "    my @__perla_eval_rv = do {\n");
        fprintf(f, "%s%s\n", code, perla_eval_code_needs_semi(code) ? ";" : "");
        fprintf(f, "    };\n");
        fprintf(f, "    return @__perla_eval_rv;\n");
        fprintf(f, "  } else {\n");
        fprintf(f, "    my $__perla_eval_rv = do {\n");
        fprintf(f, "%s%s\n", code, perla_eval_code_needs_semi(code) ? ";" : "");
        fprintf(f, "    };\n");
        fprintf(f, "    return $__perla_eval_rv;\n");
        fprintf(f, "  }\n");
    }
    fprintf(f, "}\n");
    fprintf(f, "1;\n");
    fclose(f);

    /* Compile with perla -M */
    /* Check if perla binary exists before trying to fork */
    if (perla_debug_mode()) fprintf(stderr, "[eval] g_perla_path=%s g_strada_dir=%s\n", g_perla_path, g_strada_dir);
    if (g_perla_path[0]) {
        FILE *test = fopen(g_perla_path, "r");
        if (!test) {
            /* Perla binary not found — set error and return */
            extern StradaValue *perla_eval_error;
            if (perla_eval_error) strada_decref(perla_eval_error);
            perla_eval_error = strada_new_str("eval: perla binary not found");
            strada_incref(perla_eval_error);
            unlink(pm_path);
            free(code);
            if (perla_debug_mode()) fprintf(stderr, "[eval] EARLY: perla binary not found at %s\n", g_perla_path);
            return strada_new_undef();
        }
        fclose(test);
    }

    char cmd[4096];
    /* eval STRING dlopens the .pm.so produced by `perla -M`. We only
     * need the .pm.so (not the .pm.o), so PERLA_BUILD_PM_SO_ONLY=1
     * skips the redundant gcc -c step — about half the cost.
     * Default to gcc (not tcc). tcc is ~10x faster but has known
     * correctness gaps (see project_perla_tcc_dclone_bug): tcc-compiled
     * .pm.so can silently misbehave on edge cases gcc handles
     * correctly. The -O0 speed flags added to perla's _cc_opt_flags
     * make gcc fast enough for eval-STRING use without sacrificing
     * correctness. Users who explicitly want tcc can set
     * PERLA_EVAL_CC=tcc. */
    const char *eval_cc = getenv("PERLA_EVAL_CC");
    /* No tcc-by-default probe — gcc is implicit when eval_cc is empty
     * (perla.strada falls through to "gcc" when PERLA_EVAL_CC unset). */
    char eval_cc_env[128] = "";
    if (eval_cc && eval_cc[0]) {
        snprintf(eval_cc_env, sizeof(eval_cc_env), "PERLA_EVAL_CC=%s ", eval_cc);
    }
    /* Propagate the runtime's @INC (g_require_paths) to the child as
     * PERLA_LIB so `perla -M` can find dependencies that the eval body
     * `use`s. Without this, eval STRING'd `use JSON::backportPP` from
     * /opt/bzperl/lib couldn't locate the module — child probed only
     * default ~/perl5 paths and failed silently, leaving JSON::PP
     * methods (allow_nonref, etc.) unregistered. */
    extern char **g_require_paths;
    extern size_t g_require_path_count;
    char eval_lib_env[16384] = "";
    if (g_require_paths && g_require_path_count > 0) {
        /* Build the colon-joined path list once. */
        char paths[8192] = "";
        size_t ppos = 0;
        for (size_t i = 0; i < g_require_path_count && ppos < sizeof(paths) - 2; i++) {
            const char *p = g_require_paths[i];
            if (!p) continue;
            if (ppos > 0 && ppos < sizeof(paths) - 1) paths[ppos++] = ':';
            size_t plen = strlen(p);
            if (ppos + plen >= sizeof(paths) - 2) break;
            memcpy(paths + ppos, p, plen);
            ppos += plen;
        }
        paths[ppos] = 0;
        /* Pass both PERLA_LIB (for the child's runtime require paths)
         * and PERLA5LIB (consumed by perla.strada's _build_lib_paths
         * so the compile-time parser can find .pm sources). */
        snprintf(eval_lib_env, sizeof(eval_lib_env),
                 "PERLA_LIB=%s PERLA5LIB=%s ", paths, paths);
    }
    /* REPL/eval shared-pad mode: propagate PERLA_REPL_PAD to the child compile
     * so the eval body's package/our scalars are aliased to the process-shared
     * stash slots (and thus persist across eval-body .so loads). */
    const char *pad_on = getenv("PERLA_REPL_PAD");
    const char *eval_pad_env = (pad_on && pad_on[0] == '1') ? "PERLA_REPL_PAD=1 " : "";
    if (g_perla_path[0] && g_strada_dir[0]) {
        snprintf(cmd, sizeof(cmd), "%s%sSTRADA_DIR=%s PERLA_BUILD_PM_SO_ONLY=1 %s%s -M %s 2>&1",
                 eval_pad_env, eval_lib_env, g_strada_dir, eval_cc_env, g_perla_path, pm_path);
    } else if (g_perla_path[0]) {
        snprintf(cmd, sizeof(cmd), "%s%sPERLA_BUILD_PM_SO_ONLY=1 %s%s -M %s 2>&1", eval_pad_env, eval_lib_env, eval_cc_env, g_perla_path, pm_path);
    } else {
        /* Perla not available — return error */
        extern StradaValue *perla_eval_error;
        if (perla_eval_error) strada_decref(perla_eval_error);
        perla_eval_error = strada_new_str("eval: perla not in PATH");
        strada_incref(perla_eval_error);
        unlink(pm_path);
        free(code);
        return strada_new_undef();
    }

    if (perla_debug_mode()) fprintf(stderr, "[eval] cmd=%s\n", cmd);
    FILE *proc = popen(cmd, "r");
    if (proc) {
        char buf[1024];
        /* Read output (for error messages) */
        char errbuf[4096] = "";
        while (fgets(buf, sizeof(buf), proc)) {
            strncat(errbuf, buf, sizeof(errbuf) - strlen(errbuf) - 1);
        }
        int status = pclose(proc);
        if (perla_debug_mode()) fprintf(stderr, "[eval] pclose status=%d errbuf=%s\n", status, errbuf);
        /* `perla -M` currently returns exit status 0 even when its parser
         * reports `[parse error]` / "syntax error". Match Perl 5's eval
         * STRING semantics by sniffing errbuf for parse-error markers and
         * treating those as compile failures regardless of process status.
         * This is what sets `$@` for `eval "for(;)"` and friends. */
        int parse_failed = 0;
        if (errbuf[0]) {
            if (strstr(errbuf, "[parse error]") ||
                strstr(errbuf, "syntax error") ||
                strstr(errbuf, "Compilation failed"))
                parse_failed = 1;
        }
        if (status != 0 || parse_failed) {
            /* Compilation failed - set $@. Strip noisy "Compiled X.so"
             * status lines (perla -M still emits these when the parser
             * actually generated a .so despite a parse error elsewhere) —
             * they're tooling chatter, not the user-visible error. */
            char *strip = errbuf;
            if (parse_failed) {
                char *p = errbuf;
                char *out = errbuf;
                while (*p) {
                    char *line_end = strchr(p, '\n');
                    size_t line_len = line_end ? (size_t)(line_end - p) : strlen(p);
                    if (line_len < 9 || strncmp(p, "Compiled ", 9) != 0) {
                        if (out != p) memmove(out, p, line_len + (line_end ? 1 : 0));
                        out += line_len + (line_end ? 1 : 0);
                    }
                    if (!line_end) break;
                    p = line_end + 1;
                }
                *out = '\0';
            }
            extern StradaValue *perla_eval_error;
            if (perla_eval_error) strada_decref(perla_eval_error);
            perla_eval_error = strada_new_str(strip[0] ? strip : "eval: compilation failed");
            strada_incref(perla_eval_error);
            unlink(pm_path);
            free(code);
            return strada_new_undef();
        }
    }

    free(code);

    /* dlopen the .so */
    void *handle = dlopen(so_path, RTLD_NOW | RTLD_GLOBAL);
    if (!handle) {
        extern StradaValue *perla_eval_error;
        if (perla_eval_error) strada_decref(perla_eval_error);
        char errmsg[512];
        snprintf(errmsg, sizeof(errmsg), "eval: dlopen failed: %s", dlerror());
        perla_eval_error = strada_new_str(errmsg);
        strada_incref(perla_eval_error);
        unlink(pm_path);
        return strada_new_undef();
    }

    /* Find and call the init function */
    /* Init name: perla_mod_init_<pkg with :: -> _>_perla_eval_PID_ID */
    /* Actually, the -M flag derives the name from the file path */
    /* For /tmp/perla_eval_PID_ID.pm, the module name is perla_eval_PID_ID */
    char init_name[256];
    snprintf(init_name, sizeof(init_name), "perla_mod_init_perla_eval_%d_%d", (int)pid, eval_id);

    void (*init_fn)(void) = (void(*)(void))dlsym(handle, init_name);
    if (perla_debug_mode()) fprintf(stderr, "[eval] init_fn %s %s\n", init_name, init_fn ? "FOUND" : "NOT FOUND");
    if (init_fn) {
        init_fn();
    }

    /* Find and call the wrapped eval body sub. Its symbol is
     * perla_sub_<pkg_underscored>_<body_name>. The body name matches what
     * we wrote to the .pm above. */
    char body_name[512];
    size_t bn_pos = 0;
    const char *pn = pkg;
    bn_pos += snprintf(body_name + bn_pos, sizeof(body_name) - bn_pos, "perla_sub_");
    while (*pn && bn_pos + 1 < sizeof(body_name)) {
        if (pn[0] == ':' && pn[1] == ':') { body_name[bn_pos++] = '_'; pn += 2; }
        else { body_name[bn_pos++] = *pn++; }
    }
    snprintf(body_name + bn_pos, sizeof(body_name) - bn_pos,
             "___perla_eval_body_%d_%d", (int)pid, eval_id);

    StradaValue *(*body_fn)(StradaValue*) = (StradaValue*(*)(StradaValue*))dlsym(handle, body_name);
    if (perla_debug_mode()) fprintf(stderr, "[eval] body_fn %s %s\n", body_name, body_fn ? "FOUND" : "NOT FOUND");
    StradaValue *result = NULL;
    if (body_fn) {
        /* eval STRING in Perl shares the calling sub's @_ — the eval'd
         * code reads $_[N] and sees the args of whoever called us.
         * Sub::Quote relies on this: _clean_eval(\$code, \%captures) is
         * called as a sub, and the eval'd $code reads $_[1] = \%captures
         * to pull captured lexicals into scope. perla_eval_caller_args
         * is set by perla_eval_string_with_args (called from codegen
         * with the active sub's perla_at_) and consumed once here. */
        extern StradaValue *perla_eval_caller_args;
        StradaValue *args_to_pass = perla_eval_caller_args;
        int created_empty = 0;
        if (!args_to_pass) {
            args_to_pass = strada_new_array();
            created_empty = 1;
        }
        result = body_fn(args_to_pass);
        if (created_empty) strada_decref(args_to_pass);
        perla_eval_caller_args = NULL;
    }

    /* Clear $@ on success */
    extern StradaValue *perla_eval_error;
    if (perla_eval_error) strada_decref(perla_eval_error);
    perla_eval_error = strada_new_str("");
    strada_incref(perla_eval_error);

    /* Clean up temp files (keep .so loaded) */
    if (!getenv("PERLA_EVAL_KEEP")) {
        unlink(pm_path);
        char o_path[256], deps_path[256];
        snprintf(o_path, sizeof(o_path), "/tmp/perla_eval_%d_%d.pm.o", (int)pid, eval_id);
        snprintf(deps_path, sizeof(deps_path), "/tmp/perla_eval_%d_%d.pm.deps", (int)pid, eval_id);
        unlink(o_path);
        unlink(deps_path);
    }
    /* Note: .so stays loaded via dlopen so symbols registered by its init
     * remain valid. Reclaimed on process exit. */

    return result ? result : strada_new_undef();
}

/* ===== Runtime require ===== */

/* ===== Call Stack ===== */
PerlaCallFrame perla_call_stack[PERLA_CALL_STACK_SIZE];
int perla_call_depth = 0;
int perla_real_call_depth = 0;
/* OFF by default — matches perl's "warnings off without `use warnings`"
 * for the `recursion` category. Env-gated so users who want it can opt
 * in with PERLA_WARN_RECURSION=1. Lazy-init on first perla_call_push
 * (no static constructor needed). */
int perla_warn_recursion_enabled = -1;

/* Emit Perl's "Deep recursion" warning. Format mirrors Perl 5:
 *   Deep recursion on anonymous subroutine at FILE line N.
 *   Deep recursion on subroutine "PKG::NAME" at FILE line N.
 * Perla codegen names anon subs "__perla_anon_N" (or "__ANON__"
 * in some paths) — both fold to Perl's "anonymous" wording. */
void perla_emit_deep_recursion_warning(const char *pkg, const char *sub, const char *file, int line) {
    if (!sub) sub = "(unknown)";
    if (!file) file = "(eval)";
    int is_anon =
        (strcmp(sub, "__ANON__") == 0) ||
        (strncmp(sub, "__perla_anon_", 13) == 0);
    if (is_anon) {
        fprintf(stderr, "Deep recursion on anonymous subroutine at %s line %d.\n", file, line);
    } else {
        const char *p = pkg ? pkg : "main";
        fprintf(stderr, "Deep recursion on subroutine \"%s::%s\" at %s line %d.\n", p, sub, file, line);
    }
}

/* ===== File-test stat cache =====
 * Holds the last path that flowed through `-e $path` (and friends). The
 * `_X _` token in YAML::Tiny/File::Spec/IO::Socket::SSL reuses this. */
char perla_last_stat_path[4096] = {0};
void perla_remember_stat_path(const char *path) {
    if (!path) { perla_last_stat_path[0] = 0; return; }
    size_t n = strlen(path);
    if (n >= sizeof(perla_last_stat_path)) n = sizeof(perla_last_stat_path) - 1;
    memcpy(perla_last_stat_path, path, n);
    perla_last_stat_path[n] = 0;
}

/* Override for perla_exporter_import's caller-package lookup. Codegen
 * for `use Module qw(...)` sets this to the inlining-context package
 * before dispatching `Module->import(...)`, then clears it after.
 * Without this, exporter_import walks call_stack and falls back to
 * "main" when the only frame is the .pm.so mod_init context's "Module"
 * (from_pkg) entry. */
const char *perla_use_caller_pkg = NULL;

/* ===== Fake PL_defgv =====
 * XS modules read $_ via GvSV(PL_defgv). Wire the storage to point at
 * perla's actual $_ (perla_dollar_underscore) so XS code sees the same
 * variable perla code does. */
extern StradaValue *perla_dollar_underscore;

typedef struct PerlaFakeGV { StradaValue **sv_ptr; } PerlaFakeGV;
PerlaFakeGV perla_defgv_storage = { &perla_dollar_underscore };

StradaValue *perla_caller(int level) {
    /* Perl: caller(N) returns the frame for the sub N levels up
     * (caller(0) = current sub; subroutine field is current sub's
     * name; file/line are where THAT sub was invoked from).
     * Old code used depth-2-level which read the CALLER's frame
     * (off by one) — broke `caller(0)[3]` returning the callee. */
    int idx = perla_call_depth - 1 - level;
    if (getenv("PERLA_CALLER_TRACE")) {
        const char *sn = (idx >= 0 && idx < perla_call_depth && perla_call_stack[idx].subname)
            ? perla_call_stack[idx].subname : "(null)";
        const char *pk = (idx >= 0 && idx < perla_call_depth && perla_call_stack[idx].package)
            ? perla_call_stack[idx].package : "(null)";
        fprintf(stderr, "[perla_caller] level=%d depth=%d idx=%d frame.subname=%s frame.pkg=%s ucp='%s'\n",
                level, perla_call_depth, idx, sn, pk,
                perla_use_caller_pkg ? perla_use_caller_pkg : "(null)");
    }
    /* Special case: caller(0) at the BOTTOM of a use-dispatch call chain.
     * Codegen for `use Module` forces perla_call_depth=0 and sets
     * perla_use_caller_pkg before dispatching Module->import. So inside
     * import (whatever its name — installed as `import`, an anonymous
     * sub assigned to the import slot, etc.), depth=1 and idx=0 points
     * to the import frame's own package (e.g. Drogo::Dispatch). Real
     * Perl returns the caller's package (= the `use`r), which lives
     * outside any frame because `use` runs at file scope.
     *
     * Detection: level==0 (asking about immediate caller) AND idx==0
     * (we're in the bottom frame, no caller frame exists) AND
     * perla_use_caller_pkg is set (we're inside a use-dispatch chain).
     *
     * Surfaced via bizowie e_min.pl: Drogo::Dispatch::import's
     * `my $caller = $params{class} || caller;` returned Drogo::Dispatch
     * itself and wiped @Drogo::Dispatch::ISA instead of setting
     * @Abe::App::ISA. Also YAML::Mo's `my($P,%e,%o)=caller.'::';`
     * (anonymous import sub installed via *{$M.import} = sub {...})
     * returned YAML::Mo:: and YAML.pm's `has` accessor declarations
     * never installed. */
    if (level == 0 && idx == 0 && perla_call_depth >= 1
        && perla_use_caller_pkg && perla_use_caller_pkg[0]) {
        PerlaCallFrame *f0 = &perla_call_stack[0];
        extern int __perla_want_list;
        if (!__perla_want_list) {
            return strada_new_str(perla_use_caller_pkg);
        }
        StradaValue *arr = strada_new_array();
        StradaArray *av = strada_deref_array(arr);
        strada_array_push_take(av, strada_new_str(perla_use_caller_pkg));
        strada_array_push_take(av, strada_new_str(f0->file ? f0->file : "(eval)"));
        strada_array_push_take(av, STRADA_MAKE_TAGGED_INT((int64_t)f0->line));
        return arr;
    }
    if (idx < 0 || idx >= perla_call_depth) {
        /* Fallback: when called from inside a sub dispatched via
         * perla_method_dispatch from a module init (which doesn't push
         * a call frame), idx goes negative and we'd return undef. Use
         * perla_use_caller_pkg if codegen set it to the consuming
         * module's package. Drogo::Dispatch::import hits this path:
         * `my $caller = $params{class} || caller;` runs caller()
         * with no caller frame, gets undef, and silently fails to
         * inject @ISA. */
        if (level == 0 && perla_use_caller_pkg && perla_use_caller_pkg[0]) {
            return strada_new_str(perla_use_caller_pkg);
        }
        /* Perl: caller(N) returns the empty list in list context (and
         * undef in scalar context) when the call stack isn't N deep.
         * Without checking want_list here, list-context callers got a
         * 1-element array containing undef instead of an empty list,
         * so `my @c = caller(3); scalar @c` returned 1 instead of 0. */
        extern int __perla_want_list;
        if (__perla_want_list) {
            return strada_new_array();
        }
        return strada_new_undef();
    }
    PerlaCallFrame *f = &perla_call_stack[idx];
    /* Perl: caller() called from the file's top level (outside any sub
     * or eval) returns the empty list. perla pushes a synthetic main
     * pseudo-frame at startup with subname="(main)"; without this
     * check, caller() at top level returned ("main", file, line) and
     * scripts that branch on `caller` to detect "running directly"
     * (e.g. `__PACKAGE__->main(@ARGV) unless caller;`) misfired. */
    if (idx == 0 && f->subname && strcmp(f->subname, "(main)") == 0) {
        extern int __perla_want_list;
        if (__perla_want_list) return strada_new_array();
        return strada_new_undef();
    }
    /* Perl semantics: caller(N) returns the caller's PACKAGE plus the
     * file/line where the current sub was INVOKED. perla_call_push
     * stores both halves on `f`: f->line is the call-site line (from
     * perla_pending_call_line), but f->package is the called sub's
     * own package — caller's package lives on frame[idx-1] (or "main"
     * when no frame below exists for a top-of-script invocation). */
    PerlaCallFrame *caller_frame = (idx > 0) ? &perla_call_stack[idx - 1] : NULL;
    const char *caller_pkg = caller_frame && caller_frame->package
        ? caller_frame->package
        : "main";
    const char *caller_file = f->file ? f->file : "(eval)";
    int caller_line = f->line;
    extern int __perla_want_list;
    /* Scalar context: return just the caller's package name. */
    if (!__perla_want_list) {
        return strada_new_str(caller_pkg);
    }
    /* List context: return (package, filename, line[, subname, hasargs, wantarray]).
     * Minimum 3-element tuple matches the common destructure pattern. */
    StradaValue *arr = strada_new_array();
    StradaArray *av = strada_deref_array(arr);
    strada_array_push_take(av, strada_new_str(caller_pkg));
    strada_array_push_take(av, strada_new_str(caller_file));
    strada_array_push_take(av, STRADA_MAKE_TAGGED_INT((int64_t)caller_line));
    /* Extended fields — subname is "Pkg::sub" for the CURRENT frame f,
     * hasargs / wantarray we don't track yet; pass placeholders so
     * destructures with more vars don't blow up. */
    if (f->subname && f->subname[0]) {
        /* Anonymous subs use "__ANON__" in Perl's caller output, not
         * perla's internal "__perla_anon_N" placeholder. Fold the
         * internal name to Perl's convention so caller(0)[3] matches
         * `main::__ANON__` for bare `sub { ... }` calls. */
        const char *sn = f->subname;
        char qname[512];
        if (strncmp(sn, "__perla_anon_", 13) == 0) {
            snprintf(qname, sizeof(qname), "%s::__ANON__",
                     f->package ? f->package : "main");
        } else {
            snprintf(qname, sizeof(qname), "%s::%s",
                     f->package ? f->package : "main", sn);
        }
        strada_array_push_take(av, strada_new_str(qname));
    } else {
        strada_array_push_take(av, strada_new_str(""));
    }
    strada_array_push_take(av, STRADA_MAKE_TAGGED_INT(1));  /* hasargs */
    strada_array_push_take(av, strada_new_undef());          /* wantarray */
    /* Perl's caller returns up to 11 elements when called with arg:
     * package, filename, line, subroutine, hasargs, wantarray,
     * evaltext, is_require, hints, bitmask, hinthash. We don't track
     * the eval/hints state; emit placeholders so code that unpacks
     * scalar @c == 11 (or higher-index access like $c[7]) works. */
    strada_array_push_take(av, strada_new_undef());          /* evaltext */
    strada_array_push_take(av, strada_new_undef());          /* is_require */
    strada_array_push_take(av, STRADA_MAKE_TAGGED_INT(0));   /* hints */
    strada_array_push_take(av, strada_new_str(""));          /* bitmask */
    strada_array_push_take(av, strada_new_undef());          /* hinthash */
    return arr;
}

/* Built-in: Package::Stash::new — create a stash wrapper object */
StradaValue *perla_package_stash_new(StradaValue *args) {
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    if (!av || strada_array_length(av) < 2) return strada_new_undef();
    StradaValue *pkg_name = strada_array_get(av, 1);
    char *pkg = strada_to_str(pkg_name);
    /* Ensure the stash exists */
    perla_stash_get_or_create(pkg);
    /* Return a blessed hashref with the package name */
    StradaValue *h = strada_new_hash();
    strada_hash_set(h->value.hv, "package", pkg_name);
    StradaValue *obj = perla_bless(strada_ref_create_take(h), "Package::Stash");
    free(pkg);
    return obj;
}

/* Built-in: Package::Stash::name — return package name */
StradaValue *perla_package_stash_name(StradaValue *args) {
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    if (!av || strada_array_length(av) < 1) return strada_new_undef();
    StradaValue *self = strada_array_get(av, 0);
    if (!self || STRADA_IS_TAGGED_INT(self)) return strada_new_undef();
    /* Deref if needed */
    if (self->type == STRADA_REF && self->value.rv) self = self->value.rv;
    if (self->type == STRADA_HASH) return strada_hv_fetch_owned(self, "package");
    return strada_new_undef();
}

/* Built-in: Package::Stash::add_symbol — install a symbol */
StradaValue *perla_package_stash_add_symbol(StradaValue *args) {
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    if (!av || strada_array_length(av) < 3) return strada_new_undef();
    StradaValue *self = strada_array_get(av, 0);
    StradaValue *name_sv = strada_array_get(av, 1);
    StradaValue *val = strada_array_get(av, 2);

    /* Get package name from self */
    if (!self || STRADA_IS_TAGGED_INT(self)) return strada_new_undef();
    if (self->type == STRADA_REF && self->value.rv) self = self->value.rv;
    char *pkg = strada_to_str(strada_hv_fetch_owned(self, "package"));
    char *sym = strada_to_str(name_sv);

    /* Strip sigil */
    char *name = sym;
    if (name[0] == '&' || name[0] == '$' || name[0] == '@' || name[0] == '%') name++;

    PerlGlob *glob = perla_glob_get_or_create(perla_stash_get_or_create(pkg), name);
    perla_glob_assign(glob, val);

    /* If it's a code ref, also register for method dispatch */
    if (sym[0] == '&') {
        /* Can't easily register a C function name, but the glob CODE slot is set */
    }

    free(sym);
    free(pkg);
    return val;
}

/* Built-in: Package::Stash::has_symbol */
StradaValue *perla_package_stash_has_symbol(StradaValue *args) {
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    if (!av || strada_array_length(av) < 2) return STRADA_MAKE_TAGGED_INT(0);
    StradaValue *self = strada_array_get(av, 0);
    StradaValue *name_sv = strada_array_get(av, 1);
    if (!self || STRADA_IS_TAGGED_INT(self)) return STRADA_MAKE_TAGGED_INT(0);
    if (self->type == STRADA_REF && self->value.rv) self = self->value.rv;
    char *pkg = strada_to_str(strada_hv_fetch_owned(self, "package"));
    char *sym = strada_to_str(name_sv);
    char *name = sym;
    if (name[0] == '&' || name[0] == '$' || name[0] == '@' || name[0] == '%') name++;
    PerlStash *stash = perla_stash_get(pkg);
    int result = 0;
    if (stash) {
        PerlGlob *g = perla_glob_get(stash, name);
        if (g) {
            int slot = PERLA_SLOT_SCALAR;
            if (sym[0] == '&') slot = PERLA_SLOT_CODE;
            else if (sym[0] == '@') slot = PERLA_SLOT_ARRAY;
            else if (sym[0] == '%') slot = PERLA_SLOT_HASH;
            result = (g->slots[slot] != NULL) ? 1 : 0;
        }
    }
    free(sym);
    free(pkg);
    return STRADA_MAKE_TAGGED_INT(result);
}

/* Built-in: Package::Stash::get_symbol */
StradaValue *perla_package_stash_get_symbol(StradaValue *args) {
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    if (!av || strada_array_length(av) < 2) return strada_new_undef();
    StradaValue *self = strada_array_get(av, 0);
    StradaValue *name_sv = strada_array_get(av, 1);
    if (!self || STRADA_IS_TAGGED_INT(self)) return strada_new_undef();
    if (self->type == STRADA_REF && self->value.rv) self = self->value.rv;
    char *pkg = strada_to_str(strada_hv_fetch_owned(self, "package"));
    char *sym = strada_to_str(name_sv);
    char *name = sym;
    if (name[0] == '&' || name[0] == '$' || name[0] == '@' || name[0] == '%') name++;
    PerlStash *stash = perla_stash_get(pkg);
    StradaValue *result = strada_new_undef();
    if (stash) {
        /* Special case: @ISA — return stash->isa (populated by perla_isa_push) */
        if (sym[0] == '@' && strcmp(name, "ISA") == 0) {
            if (stash->isa) result = stash->isa;
            free(sym);
            free(pkg);
            return result;
        }
        PerlGlob *g = perla_glob_get(stash, name);
        if (g) {
            int slot = PERLA_SLOT_SCALAR;
            if (sym[0] == '&') slot = PERLA_SLOT_CODE;
            else if (sym[0] == '@') slot = PERLA_SLOT_ARRAY;
            else if (sym[0] == '%') slot = PERLA_SLOT_HASH;
            if (g->slots[slot]) result = g->slots[slot];
        }
    }
    free(sym);
    free(pkg);
    return result;
}

/* Built-in: Package::Stash::list_all_symbols */
StradaValue *perla_package_stash_list_all_symbols(StradaValue *args) {
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    if (!av || strada_array_length(av) < 1) return strada_new_array();
    StradaValue *self = strada_array_get(av, 0);
    if (!self || STRADA_IS_TAGGED_INT(self)) return strada_new_array();
    if (self->type == STRADA_REF && self->value.rv) self = self->value.rv;
    char *pkg = strada_to_str(strada_hv_fetch_owned(self, "package"));

    /* Filter by type if specified */
    char *type_filter = NULL;
    if (strada_array_length(av) >= 2) {
        type_filter = strada_to_str(strada_array_get(av, 1));
    }

    PerlStash *stash = perla_stash_get(pkg);
    StradaValue *result = strada_new_array();
    if (stash) {
        for (int i = 0; i < stash->count; i++) {
            if (stash->keys[i] && stash->entries[i]) {
                int include = 1;
                if (type_filter) {
                    int slot = PERLA_SLOT_SCALAR;
                    if (strcmp(type_filter, "CODE") == 0) slot = PERLA_SLOT_CODE;
                    else if (strcmp(type_filter, "ARRAY") == 0) slot = PERLA_SLOT_ARRAY;
                    else if (strcmp(type_filter, "HASH") == 0) slot = PERLA_SLOT_HASH;
                    else if (strcmp(type_filter, "SCALAR") == 0) slot = PERLA_SLOT_SCALAR;
                    include = (stash->entries[i]->slots[slot] != NULL) ? 1 : 0;
                }
                if (include) {
                    strada_array_push(strada_deref_array(result), strada_new_str(stash->keys[i]));
                }
            }
        }
    }
    free(pkg);
    if (type_filter) free(type_filter);
    return result;
}

/* Built-in: Package::Stash::get_or_add_symbol — get or create a symbol */
StradaValue *perla_package_stash_get_or_add_symbol(StradaValue *args) {
    /* Same as get_symbol but creates if not found */
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    if (!av || strada_array_length(av) < 2) return strada_new_undef();
    StradaValue *self = strada_array_get(av, 0);
    StradaValue *name_sv = strada_array_get(av, 1);
    if (!self || STRADA_IS_TAGGED_INT(self)) return strada_new_undef();
    if (self->type == STRADA_REF && self->value.rv) self = self->value.rv;
    char *pkg = strada_to_str(strada_hv_fetch_owned(self, "package"));
    char *sym = strada_to_str(name_sv);
    char *name = sym;
    int slot = PERLA_SLOT_SCALAR;
    if (name[0] == '&') { slot = PERLA_SLOT_CODE; name++; }
    else if (name[0] == '@') { slot = PERLA_SLOT_ARRAY; name++; }
    else if (name[0] == '%') { slot = PERLA_SLOT_HASH; name++; }
    else if (name[0] == '$') { slot = PERLA_SLOT_SCALAR; name++; }

    PerlStash *stash = perla_stash_get_or_create(pkg);

    /* Special case: @ISA — use the stash's ISA array (populated by perla_isa_push) */
    if (slot == PERLA_SLOT_ARRAY && strcmp(name, "ISA") == 0) {
        if (!stash->isa) stash->isa = strada_new_array();
        free(sym);
        free(pkg);
        return strada_ref_create(stash->isa);
    }

    PerlGlob *g = perla_glob_get_or_create(stash, name);
    StradaValue *result = g->slots[slot];
    if (!result) {
        /* Create default value for the slot type */
        if (slot == PERLA_SLOT_ARRAY) result = strada_new_array();
        else if (slot == PERLA_SLOT_HASH) result = strada_new_hash();
        else result = strada_new_undef();
        g->slots[slot] = result;
        strada_incref_impl(result);
    }
    free(sym);
    free(pkg);
    return strada_ref_create(result);
}

/* Built-in: Package::Stash::remove_symbol */
StradaValue *perla_package_stash_remove_symbol(StradaValue *args) {
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    if (!av || strada_array_length(av) < 2) return strada_new_undef();
    StradaValue *self = strada_array_get(av, 0);
    StradaValue *name_sv = strada_array_get(av, 1);
    if (!self || STRADA_IS_TAGGED_INT(self)) return strada_new_undef();
    if (self->type == STRADA_REF && self->value.rv) self = self->value.rv;
    char *pkg = strada_to_str(strada_hv_fetch_owned(self, "package"));
    char *sym = strada_to_str(name_sv);
    char *name = sym;
    if (name[0] == '&' || name[0] == '$' || name[0] == '@' || name[0] == '%') name++;
    PerlStash *stash = perla_stash_get(pkg);
    if (stash) {
        PerlGlob *g = perla_glob_get(stash, name);
        if (g) {
            int slot = PERLA_SLOT_SCALAR;
            if (sym[0] == '&') slot = PERLA_SLOT_CODE;
            else if (sym[0] == '@') slot = PERLA_SLOT_ARRAY;
            else if (sym[0] == '%') slot = PERLA_SLOT_HASH;
            if (g->slots[slot]) {
                strada_decref(g->slots[slot]);
                g->slots[slot] = NULL;
            }
        }
    }
    free(sym);
    free(pkg);
    return strada_new_undef();
}

/* `use overload '""' => sub { ... }, 'fallback' => 1` — install overload
 * subs on the *caller's* package. Real Perl's overload.pm import does:
 *
 *   sub import {
 *     my $package = caller();
 *     shift;
 *     $package->overload::OVERLOAD(@_);
 *   }
 *
 * which installs subs in the caller's stash under names "(" + op (e.g.
 * `(""`, `(0+`, `(bool`). We register this as `overload::import` so the
 * `use overload` codegen path lands here.
 *
 * The caller's package is taken from the call stack — when `use overload`
 * runs at module init time, the top frame's package is the loading
 * module's package (set by perla_mod_init via perla_call_stack[..].package).
 */
/* Binary overload dispatcher — used by codegen for \`+\`/\`-\`/\`*\`
 * (and other binary ops once wired up). Checks each operand for a
 * blessed package; if the package has an installed overload sub for
 * \`op\` (stored under "(" + op via perla_overload_import), invokes
 * it with \`(self, other, swapped)\` args. Returns the result, or NULL
 * if neither side has an overload (caller falls back to default
 * numeric arithmetic). */
/* Try a single overload slot — return the result of calling the
 * user sub, or NULL if no overload registered for this op. */
/* If `cv` is a STRADA_STR method-name (e.g. `use overload '-' =>
 * 'subtract'` or `'-' => 'sub'`), resolve it in `pkg`'s stash and
 * return the underlying callable. Otherwise return cv unchanged.
 * Needed because perla_call_code's string-name resolution falls back
 * to the *caller's* package, but the overload was registered in the
 * object's package — so a string method-name that exists only in that
 * package wouldn't resolve. Also lets us reach subs whose name is a
 * reserved word (e.g. `sub sub { ... }` → C symbol perla_sub_Pkg_sub
 * which dlsym misses because "sub" alone isn't a fn). */
static StradaValue *perla_overload_resolve_method(StradaValue *cv, const char *pkg) {
    if (!cv || STRADA_IS_TAGGED_INT(cv)) return cv;
    if (cv->type != STRADA_STR) return cv;
    if (!pkg || !pkg[0]) return cv;
    const char *name = cv->value.pv;
    if (!name || !name[0]) return cv;
    /* If the string looks like Pkg::name (qualified), let perla_call_code's
     * existing qualified-name path handle it. */
    if (strstr(name, "::")) return cv;
    StradaValue *resolved = perla_code_get(pkg, name);
    if (resolved && !STRADA_IS_TAGGED_INT(resolved)) return resolved;
    return cv;
}

static StradaValue *perla_overload_call_one(StradaValue *left, StradaValue *right, const char *op) {
    if (!op || !op[0]) return NULL;
    char slot[32];
    snprintf(slot, sizeof(slot), "(%s", op);
    /* Try left operand first */
    if (left && !STRADA_IS_TAGGED_INT(left) && left->type == STRADA_REF) {
        const char *pkg = perla_blessed(left);
        if (pkg) {
            PerlGlob *g = perla_method_resolve(pkg, slot);
            if (g && g->slots[PERLA_SLOT_CODE]) {
                StradaValue *cv = perla_overload_resolve_method(g->slots[PERLA_SLOT_CODE], pkg);
                StradaValue *a = strada_new_array();
                StradaArray *aav = strada_deref_array(a);
                strada_incref(left); strada_array_push_take(aav, left);
                if (right) { strada_incref(right); strada_array_push_take(aav, right); }
                else { strada_array_push_take(aav, strada_new_undef()); }
                strada_array_push_take(aav, STRADA_MAKE_TAGGED_INT(0)); /* not swapped */
                StradaValue *r = perla_call_code(cv, a);
                strada_decref(a);
                return r;
            }
        }
    }
    /* Try right operand (swapped) */
    if (right && !STRADA_IS_TAGGED_INT(right) && right->type == STRADA_REF) {
        const char *pkg = perla_blessed(right);
        if (pkg) {
            PerlGlob *g = perla_method_resolve(pkg, slot);
            if (g && g->slots[PERLA_SLOT_CODE]) {
                StradaValue *cv = perla_overload_resolve_method(g->slots[PERLA_SLOT_CODE], pkg);
                StradaValue *a = strada_new_array();
                StradaArray *aav = strada_deref_array(a);
                strada_incref(right); strada_array_push_take(aav, right);
                if (left) { strada_incref(left); strada_array_push_take(aav, left); }
                else { strada_array_push_take(aav, strada_new_undef()); }
                strada_array_push_take(aav, STRADA_MAKE_TAGGED_INT(1)); /* swapped */
                StradaValue *r = perla_call_code(cv, a);
                strada_decref(a);
                return r;
            }
        }
    }
    return NULL;
}

/* Recursion guard for `%{}`/`@{}`/`&{}` overloads.
 *
 * Perl's behavior: when the user writes `'%{}' => sub { $_[0]->{h} }`,
 * the `$_[0]->{h}` access inside the sub *must not* re-dispatch through
 * the same overload — otherwise infinite recursion. Perl detects this
 * and uses the underlying hash for accesses that originate inside the
 * overload sub.
 *
 * We approximate this with a small fixed-size stack of (obj, slot) pairs
 * currently being dereffed. perla_overload_deref skips the lookup when
 * the same pair is on the stack. */
#define PERLA_OVERLOAD_DEREF_STACK_MAX 32
static __thread StradaValue *perla_overload_deref_stack[PERLA_OVERLOAD_DEREF_STACK_MAX];
static __thread const char *perla_overload_deref_slot_stack[PERLA_OVERLOAD_DEREF_STACK_MAX];
static __thread int perla_overload_deref_depth = 0;

/* Resolve `@{}` / `%{}` / `&{}` deref overloads. Given a blessed ref
 * and a slot suffix ("@{}", "%{}", "&{}"), invoke the registered
 * overload sub (0-arity here — the operand sits at $_[0]) and return
 * its result. NULL means "no overload, use default behavior". */
StradaValue *perla_overload_deref(StradaValue *sv, const char *slot_suffix) {
    if (!sv || STRADA_IS_TAGGED_INT(sv) || sv->type != STRADA_REF) return NULL;
    /* Recursion guard: if we're already dereffing this object with this
     * slot, fall through to default behavior. */
    for (int i = 0; i < perla_overload_deref_depth; i++) {
        if (perla_overload_deref_stack[i] == sv &&
            strcmp(perla_overload_deref_slot_stack[i], slot_suffix) == 0) {
            return NULL;
        }
    }
    const char *pkg = perla_blessed(sv);
    if (!pkg) return NULL;
    char slot[32];
    snprintf(slot, sizeof(slot), "(%s", slot_suffix);
    PerlGlob *g = perla_method_resolve(pkg, slot);
    if (!g || !g->slots[PERLA_SLOT_CODE]) return NULL;
    StradaValue *cv = g->slots[PERLA_SLOT_CODE];
    if (perla_overload_deref_depth >= PERLA_OVERLOAD_DEREF_STACK_MAX) return NULL;
    perla_overload_deref_stack[perla_overload_deref_depth] = sv;
    perla_overload_deref_slot_stack[perla_overload_deref_depth] = slot_suffix;
    perla_overload_deref_depth++;
    StradaValue *a = strada_new_array();
    StradaArray *aav = strada_deref_array(a);
    strada_incref(sv); strada_array_push_take(aav, sv);
    strada_array_push_take(aav, strada_new_undef());
    strada_array_push_take(aav, STRADA_MAKE_TAGGED_INT(0)); /* not swapped */
    StradaValue *r = perla_call_code(cv, a);
    strada_decref(a);
    perla_overload_deref_depth--;
    return r;
}

StradaValue *perla_overload_binary(StradaValue *left, StradaValue *right, const char *op) {
    if (!op || !op[0]) return NULL;
    StradaValue *r = perla_overload_call_one(left, right, op);
    if (r) return r;
    /* Perl fallback: when a numeric/string comparison operator has no
     * direct overload, fall back to `<=>` / `cmp` and convert the
     * result. CPAN modules conventionally overload only `<=>` (or
     * `cmp`) and rely on the derived ops. */
    int is_num_cmp = (strcmp(op, "<") == 0 || strcmp(op, ">") == 0 ||
                      strcmp(op, "<=") == 0 || strcmp(op, ">=") == 0 ||
                      strcmp(op, "==") == 0 || strcmp(op, "!=") == 0);
    int is_str_cmp = (strcmp(op, "lt") == 0 || strcmp(op, "gt") == 0 ||
                      strcmp(op, "le") == 0 || strcmp(op, "ge") == 0 ||
                      strcmp(op, "eq") == 0 || strcmp(op, "ne") == 0);
    if (is_num_cmp) {
        StradaValue *cmp = perla_overload_call_one(left, right, "<=>");
        if (cmp) {
            int c = (int)strada_to_int(cmp);
            strada_decref(cmp);
            int b = 0;
            if (op[0] == '<' && op[1] == '\0') b = (c < 0);
            else if (op[0] == '>' && op[1] == '\0') b = (c > 0);
            else if (op[0] == '<' && op[1] == '=') b = (c <= 0);
            else if (op[0] == '>' && op[1] == '=') b = (c >= 0);
            else if (op[0] == '=' && op[1] == '=') b = (c == 0);
            else if (op[0] == '!' && op[1] == '=') b = (c != 0);
            return STRADA_MAKE_TAGGED_INT(b);
        }
    } else if (is_str_cmp) {
        StradaValue *cmp = perla_overload_call_one(left, right, "cmp");
        if (cmp) {
            int c = (int)strada_to_int(cmp);
            strada_decref(cmp);
            int b = 0;
            if (op[0] == 'l' && op[1] == 't') b = (c < 0);
            else if (op[0] == 'g' && op[1] == 't') b = (c > 0);
            else if (op[0] == 'l' && op[1] == 'e') b = (c <= 0);
            else if (op[0] == 'g' && op[1] == 'e') b = (c >= 0);
            else if (op[0] == 'e' && op[1] == 'q') b = (c == 0);
            else if (op[0] == 'n' && op[1] == 'e') b = (c != 0);
            return STRADA_MAKE_TAGGED_INT(b);
        }
    }
    /* `nomethod` catch-all: when no direct overload is registered
     * and no comparison fallback applies, look up `(nomethod` on
     * each operand's package. The user's sub is called with
     * (self, other, swap, op-name) — one extra arg beyond the
     * regular binary signature. */
    for (int side = 0; side < 2; side++) {
        StradaValue *self = side == 0 ? left : right;
        StradaValue *other = side == 0 ? right : left;
        if (!self || STRADA_IS_TAGGED_INT(self) || self->type != STRADA_REF) continue;
        const char *pkg = perla_blessed(self);
        if (!pkg) continue;
        PerlGlob *g = perla_method_resolve(pkg, "(nomethod");
        if (!g || !g->slots[PERLA_SLOT_CODE]) continue;
        StradaValue *cv = g->slots[PERLA_SLOT_CODE];
        StradaValue *a = strada_new_array();
        StradaArray *aav = strada_deref_array(a);
        strada_incref(self); strada_array_push_take(aav, self);
        if (other) { strada_incref(other); strada_array_push_take(aav, other); }
        else { strada_array_push_take(aav, strada_new_undef()); }
        strada_array_push_take(aav, STRADA_MAKE_TAGGED_INT(side));
        strada_array_push_take(aav, strada_new_str(op));
        StradaValue *rv = perla_call_code(cv, a);
        strada_decref(a);
        return rv;
    }
    return NULL;
}

StradaValue *perla_overload_import(StradaValue *args) {
    if (!args) return strada_new_undef();
    StradaArray *av = strada_deref_array(args);
    if (!av || av->size < 1) return strada_new_undef();

    /* Caller's package — the module being loaded. The codegen sets
     * perla_use_caller_pkg before calling overload->import in module
     * init (where the call stack has no caller frame), so prefer it
     * over the call_stack walk. */
    const char *caller_pkg = NULL;
    if (perla_use_caller_pkg && perla_use_caller_pkg[0]) {
        caller_pkg = perla_use_caller_pkg;
    } else if (perla_call_depth >= 1) {
        caller_pkg = perla_call_stack[perla_call_depth - 1].package;
    }
    if (!caller_pkg || !caller_pkg[0]) caller_pkg = "main";
    if (getenv("PERLA_OVERLOAD_TRACE")) {
        fprintf(stderr, "[perla_overload_import] caller_pkg='%s', av->size=%zu\n", caller_pkg, av->size);
    }

    /* Skip args[0] = "overload" class name (shifted off by the import sub). */
    for (size_t i = 1; i + 1 < av->size; i += 2) {
        StradaValue *op_sv  = av->elements[av->head + i];
        StradaValue *val_sv = av->elements[av->head + i + 1];
        if (!op_sv) continue;
        char *op = strada_to_str(op_sv);
        if (!op) continue;

        if (strcmp(op, "fallback") == 0) {
            /* Stored as a scalar slot under "()" — Perl's convention. */
            if (val_sv) strada_incref(val_sv);
            perla_scalar_set(caller_pkg, "()", val_sv ? val_sv : strada_new_undef());
        } else {
            char slot_name[64];
            snprintf(slot_name, sizeof(slot_name), "(%s", op);
            if (val_sv) strada_incref(val_sv);
            perla_code_set(caller_pkg, slot_name, val_sv ? val_sv : strada_new_undef());
        }
        free(op);
    }
    return STRADA_MAKE_TAGGED_INT(1);
}

/* perla_overload_stringify — invoked by strada_to_str via the hook for
 * blessed STRADA_REF values. Looks up the package's `(""` sub, falling
 * through @ISA, and calls it with ($self, undef, 0) per Perl's overload
 * calling convention. Returns a strdup'd string or NULL if no overload
 * is installed for this package. */
/* Common helper: invoke an overload sub with ($self, undef, 0) and
 * return its result (caller owns ref). Returns NULL if the package has
 * no installed sub for `op_name` (one of "(\"\"", "(0+", "(bool", etc.).
 * Has a thread-local recursion guard so a buggy overload sub that
 * re-invokes the same op doesn't infinite-loop. */
static StradaValue *perla_overload_call(StradaValue *sv, const char *op_name) {
    if (!sv || STRADA_IS_TAGGED_INT(sv)) return NULL;
    const char *pkg = perla_blessed(sv);
    if (!pkg) return NULL;

    PerlGlob *g = perla_method_resolve(pkg, op_name);
    if (!g || !g->slots[PERLA_SLOT_CODE]) return NULL;

    static __thread int in_overload = 0;
    if (in_overload > 4) return NULL;
    in_overload++;

    StradaValue *args = strada_new_array();
    StradaArray *aav = strada_deref_array(args);
    strada_incref(sv);
    strada_array_push_take(aav, sv);
    strada_array_push_take(aav, strada_new_undef());
    strada_array_push_take(aav, STRADA_MAKE_TAGGED_INT(0));

    StradaValue *cv = g->slots[PERLA_SLOT_CODE];
    StradaValue *result;
    /* If the overload value is a Perl method name (string, not a C
     * function pointer or symbol), dispatch as a method on the package
     * rather than dlsym'ing it. `use overload '""' => 'stringify'`
     * stores the literal string "stringify" — perla_call_code's STRADA_STR
     * path tries dlsym(RTLD_DEFAULT, "stringify") which doesn't resolve
     * to perla_sub_<Pkg>_stringify, so the call returns undef. */
    if (cv && !STRADA_IS_TAGGED_INT(cv) && cv->type == STRADA_STR
        && cv->value.pv && cv->value.pv[0]
        && strncmp(cv->value.pv, "perla_sub_", 10) != 0) {
        result = perla_method_dispatch(sv, cv->value.pv, args);
    } else {
        result = perla_call_code(cv, args);
    }
    strada_decref(args);
    in_overload--;

    if (!result) return NULL;
    /* Avoid identity-loop. */
    if (result == sv) { strada_decref(result); return NULL; }
    return result;
}

/* Numeric overload: returns 1 + sets *out if `(0+` is installed, else 0. */
int perla_overload_numeric(StradaValue *sv, double *out) {
    StradaValue *r = perla_overload_call(sv, "(0+");
    if (!r) return 0;
    if (out) *out = strada_to_num(r);
    strada_decref(r);
    return 1;
}

/* Boolean overload: returns -1 (no overload), 0 (false), 1 (true).
 * Falls back to numeric if `(bool` not installed but `(0+` is — matches
 * Perl's overload-fallback semantics. */
int perla_overload_bool(StradaValue *sv) {
    StradaValue *r = perla_overload_call(sv, "(bool");
    if (!r) {
        /* Try numeric fallback. */
        r = perla_overload_call(sv, "(0+");
        if (!r) return -1;
    }
    int b = strada_to_bool(r) ? 1 : 0;
    strada_decref(r);
    return b;
}

char *perla_overload_stringify(StradaValue *sv) {
    if (!sv || STRADA_IS_TAGGED_INT(sv)) return NULL;
    const char *pkg = perla_blessed(sv);
    if (!pkg) return NULL;

    PerlGlob *g = perla_method_resolve(pkg, "(\"\"");
    if (getenv("PERLA_OVERLOAD_TRACE")) {
        StradaValue *cv = g ? g->slots[PERLA_SLOT_CODE] : NULL;
        fprintf(stderr, "[perla_overload_stringify] pkg='%s', g=%p, code=%p",
                pkg, (void*)g, (void*)cv);
        if (cv && !STRADA_IS_TAGGED_INT(cv)) {
            fprintf(stderr, " type=%d", cv->type);
            if (cv->type == STRADA_STR && cv->value.pv) {
                fprintf(stderr, " str='%s'", cv->value.pv);
            }
        }
        fprintf(stderr, "\n");
    }
    if (!g || !g->slots[PERLA_SLOT_CODE]) return NULL;

    /* Recursion guard — if the overload itself stringifies the same SV
     * (e.g. `sub { "[" . shift . "]" }` where the concat would re-enter),
     * we'd loop. A thread-local depth counter caps the chain. */
    static __thread int in_overload = 0;
    if (in_overload > 4) return NULL;
    in_overload++;

    StradaValue *args = strada_new_array();
    StradaArray *aav = strada_deref_array(args);
    strada_incref(sv);
    strada_array_push_take(aav, sv);
    strada_array_push_take(aav, strada_new_undef());
    strada_array_push_take(aav, STRADA_MAKE_TAGGED_INT(0));

    StradaValue *cv = g->slots[PERLA_SLOT_CODE];
    StradaValue *result;
    /* See perla_overload_call: dispatch method-name strings via
     * perla_method_dispatch, not perla_call_code's dlsym path. */
    if (cv && !STRADA_IS_TAGGED_INT(cv) && cv->type == STRADA_STR
        && cv->value.pv && cv->value.pv[0]
        && strncmp(cv->value.pv, "perla_sub_", 10) != 0) {
        result = perla_method_dispatch(sv, cv->value.pv, args);
    } else {
        result = perla_call_code(cv, args);
    }
    strada_decref(args);
    in_overload--;

    if (!result) return NULL;
    /* Avoid infinite recursion: if the overload returned the same blessed
     * REF (perhaps because the user wrote `'""' => sub { $self }` by
     * mistake), don't re-recurse — fall through to default formatting. */
    if (result == sv) {
        strada_decref(result);
        return NULL;
    }
    char *s = NULL;
    if (!STRADA_IS_TAGGED_INT(result) && result->type == STRADA_STR && result->value.pv) {
        s = strdup(result->value.pv);
    } else {
        s = strada_to_str(result);
    }
    strada_decref(result);
    return s;
}

/* Built-in: Package::Stash::namespace — return the stash hash */
StradaValue *perla_package_stash_namespace(StradaValue *args) {
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    if (!av || strada_array_length(av) < 1) return strada_new_hash();
    StradaValue *self = strada_array_get(av, 0);
    if (!self || STRADA_IS_TAGGED_INT(self)) return strada_new_hash();
    if (self->type == STRADA_REF && self->value.rv) self = self->value.rv;
    char *pkg = strada_to_str(strada_hv_fetch_owned(self, "package"));
    PerlStash *stash = perla_stash_get_or_create(pkg);
    /* Return the stash as a hash */
    StradaValue *result = strada_new_hash();
    if (stash) {
        for (int i = 0; i < stash->count; i++) {
            if (stash->keys[i] && stash->entries[i]) {
                /* Store the glob as a value (simplified: store code slot if available) */
                StradaValue *val = stash->entries[i]->slots[PERLA_SLOT_CODE];
                if (!val) val = stash->entries[i]->slots[PERLA_SLOT_SCALAR];
                if (!val) val = strada_new_undef();
                strada_hash_set(result->value.hv, stash->keys[i], val);
            }
        }
    }
    free(pkg);
    return result;
}

/* Generic MOP hash-key accessor: returns $self->{key}
 * The key is stored in a closure-like pattern using a static table */
typedef struct { const char *key; } MopAccessorCtx;

static StradaValue *perla_mop_hash_accessor(StradaValue *args, const char *key) {
    StradaArray *av = args ? strada_deref_array(args) : NULL;
    if (!av || strada_array_length(av) < 1) return strada_new_undef();
    StradaValue *self = strada_array_get(av, 0);
    if (!self || STRADA_IS_TAGGED_INT(self)) return strada_new_undef();
    StradaValue *target = self;
    if (self->type == STRADA_REF && self->value.rv && !STRADA_IS_TAGGED_INT(self->value.rv)) {
        target = self->value.rv;
    }
    if (target->type == STRADA_HASH) {
        StradaValue *val = strada_hv_fetch_owned(target, key);
        return val ? val : strada_new_undef();
    }
    return strada_new_undef();
}

/* name accessor: returns $self->{'package'} */
static StradaValue *perla_mop_name(StradaValue *args) {
    return perla_mop_hash_accessor(args, "package");
}

/* We need individual C functions for each accessor key (can't use closures in C func ptrs) */
#define MOP_ACCESSOR(cname, key) \
    static StradaValue *perla_mop_##cname(StradaValue *args) { return perla_mop_hash_accessor(args, key); }

